// ============================================================================
// RPC Server
// ============================================================================

/// JSON-RPC server configuration.
pub const RpcConfig = struct {
    bind_address: []const u8 = "127.0.0.1",
    port: u16 = 8332,
    auth_token: ?[]const u8 = null, // Base64-encoded "user:pass"
    cookie_token: ?[]const u8 = null, // Base64-encoded "__cookie__:<hex>" from .cookie file
    max_request_size: usize = 1 << 24, // 16 MB (needed for submitblock with large blocks)
    /// Absolute path to the node's data directory. Used by RPCs that read or
    /// write auxiliary files (mempool.dat, etc) in the datadir without
    /// touching the chainstate. Empty string disables those RPCs.
    datadir: []const u8 = "",
    /// Optional path to a PEM-encoded X.509 certificate for HTTPS termination.
    /// Both `tls_cert_path` and `tls_key_path` must be set together; supplying
    /// only one is a startup error.  When unset (the default), the RPC server
    /// binds plain HTTP for backward compatibility with existing operators.
    ///
    /// See `validateTlsConfig` for the full deferral rationale: Zig 0.13's
    /// standard library ships `std.crypto.tls.Client` but no server-side TLS
    /// implementation.  Supplying these flags today fails fast with a clear
    /// `TlsServerUnavailable` error instead of silently downgrading to HTTP.
    tls_cert_path: ?[]const u8 = null,
    /// Optional path to the PEM-encoded private key matching `tls_cert_path`.
    /// See the field comment on `tls_cert_path` for the deferral rationale.
    tls_key_path: ?[]const u8 = null,
};

/// RPC Server error set.
pub const RpcError = error{
    ParseError,
    InvalidRequest,
    MethodNotFound,
    InvalidParams,
    InternalError,
    OutOfMemory,
    Unauthorized,
    ConnectionError,
    /// Returned when `tls_cert_path` is set without `tls_key_path` (or vice
    /// versa).  Operators must supply both PEM paths together.
    TlsCertWithoutKey,
    TlsKeyWithoutCert,
    /// Returned when both TLS paths are supplied but server-side TLS is not
    /// available in this build.  See `validateTlsConfig` for the rationale
    /// (Zig 0.13 stdlib has no `std.crypto.tls.Server`; a future drop-in
    /// will wire BearSSL, OpenSSL, or a Zig 0.14+ server primitive).
    TlsServerUnavailable,
};

// ============================================================================
// HTTPS / TLS termination — DEFERRED, flag plumbing only (W119 + FIX-64)
// ----------------------------------------------------------------------------
// BIP-78 PayJoin REQUIRES the receiver endpoint to be either HTTPS or a Tor
// .onion address (W119 BUG-3 + G3).  Bitcoin Core terminates HTTPS itself via
// libevent + OpenSSL (see bitcoin-core/src/httpserver.cpp); clearbit's RPC
// server in this file currently binds plain TCP only.
//
// Plumbing the flags now (without implementing the actual handshake) catches
// two production foot-guns ahead of the eventual real implementation:
//
//   1. Operators who set --rpc-tls-cert / --rpc-tls-key today would otherwise
//      silently get plain HTTP — a privacy / security regression they would
//      not notice until a packet capture surfaces.  The plumbing in
//      `validateTlsConfig` fails fast with a clear error instead.
//
//   2. The eventual implementation can drop in behind these stable config
//      fields and a single switch on `RpcServer.tlsAvailable()` — no API
//      churn for callers (main.zig already passes the paths through
//      `RpcConfig`, and any future `RpcServerCore` / `TlsRpcServer` split
//      can be made internal).
//
// We deliberately do NOT add `TlsRpcServer`, `TlsPayjoinServer`, or
// `TlsClient` declarations: W119/G3 + W119/G24 audit-gate tests assert
// the absence of those names as a way to track this exact gap.  Adding
// stub decls would silently pass those gates without delivering working
// TLS, which is precisely the regression the audit is guarding against.
//
// Blockers (precise):
//   - Zig 0.13.0 `lib/std/crypto/tls/` contains only `Client.zig`.  There is
//     no `Server.zig`; `std.crypto.tls` exposes record-layer + handshake
//     constants and a client-only `init` flow.  See
//     /usr/local/zig-linux-x86_64-0.13.0/lib/std/crypto/tls.zig:40
//     (`pub const Client = @import("tls/Client.zig");` — the only @import).
//   - Adding BearSSL or OpenSSL bumps clearbit's C-dep surface (currently
//     rocksdb + secp256k1 + minisketch + optional shani).  That's a build
//     decision a maintainer should ratify, not silently bolt on.
//   - A pure-Zig third-party server (e.g. `zig-bearssl`, `zig-tls13-server`)
//     would also be a dep decision.  The ecosystem is still pre-1.0 and
//     each candidate has different licensing + supply-chain trade-offs.
//
// Tracking: W119 audit (commit 6c0fe8f) BUG-3 + BUG-23, this commit closes
// the flag-plumbing slice only.  Future audit/fix wave WILL replace the
// `TlsServerUnavailable` return with a real handshake.
// ============================================================================

/// Validate that `tls_cert_path` and `tls_key_path` are consistent and that
/// the build can honor them.  Called from `RpcServer.start` before bind so
/// mistyped paths surface immediately, not after the listening socket is up.
///
/// Returns `void` (HTTP is OK) when both fields are null.  Returns an error
/// in three cases:
///   - `TlsCertWithoutKey` / `TlsKeyWithoutCert` — partial config
///   - `TlsServerUnavailable` — both set, but the build does not include a
///     TLS server implementation (current state — see deferral block above)
pub fn validateTlsConfig(cfg: RpcConfig) RpcError!void {
    const has_cert = cfg.tls_cert_path != null;
    const has_key = cfg.tls_key_path != null;
    if (!has_cert and !has_key) return; // HTTP (default)
    if (has_cert and !has_key) return RpcError.TlsCertWithoutKey;
    if (!has_cert and has_key) return RpcError.TlsKeyWithoutCert;
    // Both set.  Today: deferral.  Future: drop in the real handshake here
    // and return void after parsing/validating the PEM files.
    return RpcError.TlsServerUnavailable;
}

/// Whether this build can terminate HTTPS for RPC.  Always false on Zig
/// 0.13 stdlib (no server-side TLS); the eventual real implementation
/// flips this to true and `validateTlsConfig` starts honoring the paths.
pub fn tlsAvailable() bool {
    return false;
}

// ============================================================================
// BIP-78 PayJoin receiver — foundation (FIX-65, plain HTTP only)
// ----------------------------------------------------------------------------
// FIX-65 ships the receiver-side surface that the W119 audit (`tests_w119_
// payjoin.zig`) lists at G1, G4-G9, G16, G17, G21: the `POST /payjoin` route,
// the BIP-78 query parser, the four mandated JSON error codes, the v=1
// version pin, and an Original-PSBT → Proposal-PSBT round-trip helper.
//
// Transport: PLAIN HTTP ONLY.  BIP-78 §"Receiver's transport security"
// requires HTTPS or a .onion endpoint, but FIX-64 deferred server-side TLS
// (Zig 0.13 stdlib has no `std.crypto.tls.Server`, only `Client`).  This
// route is reachable plaintext on the same port the JSON-RPC server uses;
// operators MUST front it with nginx / Caddy / Tor for production exposure.
// This is the same posture Bitcoin Core itself takes: Core's libevent HTTP
// server speaks plain HTTP, and operators terminate TLS upstream.  Adding
// a stub `TlsPayjoinServer` decl would silently mute the W119/G3 + G24
// audit assertions without delivering working TLS, which is exactly the
// regression those gates were designed to surface — so we keep the absence
// signal intact and document the deferral here instead.
//
// What this block ships (receiver-side foundation):
//   - `PAYJOIN_VERSION = 1` — the only supported BIP-78 version
//   - `PayjoinError` enum + the 4 BIP-78 JSON-error code constants
//   - `PayjoinQuery` + `parsePayjoinQuery` — the URL-query parser for the
//     5 BIP-78 optional parameters
//   - `PayjoinHandler` namespace holding `processOriginalPsbt` (the
//     round-trip primitive: deserialize → validate → add receiver input →
//     sign → serialize) and `formatErrorJson` (4-error renderer)
//   - `RpcServer.handlePayjoinRequest` — the HTTP-side dispatcher that
//     reads the body, parses the query, runs the round-trip, and writes
//     `text/plain` (base64 PSBT) on success or `application/json` BIP-78
//     errors on failure
//
// Deferred to a later fix wave (W119 audit-tracked):
//   - G2 sender HTTP client + G10-G15 sender anti-snoop validators
//     (this fix is RECEIVER-ONLY, matching the FIX-65 scope memo)
//   - G3 HTTPS / G24 TLS client / G25 Tor Hidden Service publisher
//     (blocked on Zig 0.13 stdlib gap — same as FIX-64)
//   - G18 receiver TTL store / G19 UTXO lock / G20 fingerprint-aware
//     coin selection / G30 replay protection (Implementation Suggestions
//     in BIP-78; receiver fundamentals first)
//   - G26 `getpayjoinrequest` / G27 `sendpayjoinrequest` RPCs (BTCPay
//     Server reference shape, layered on top of this foundation)
// ============================================================================

/// BIP-78 protocol version.  The only value the receiver accepts on the
/// `v=` query parameter.  Any other value triggers `PAYJOIN_ERR_VERSION_
/// UNSUPPORTED` per BIP-78 §"Version negotiation".
pub const PAYJOIN_VERSION: u32 = 1;

/// BIP-78 well-known error codes (the four strings the receiver returns in
/// the JSON `errorCode` field).  Cross-impl wire compatibility with
/// BTCPayServer.Payjoin matters here — the strings must match verbatim.
pub const PAYJOIN_ERR_UNAVAILABLE: []const u8 = "unavailable";
pub const PAYJOIN_ERR_NOT_ENOUGH_MONEY: []const u8 = "not-enough-money";
pub const PAYJOIN_ERR_VERSION_UNSUPPORTED: []const u8 = "version-unsupported";
pub const PAYJOIN_ERR_ORIGINAL_REJECTED: []const u8 = "original-psbt-rejected";

/// Error set used internally by the PayJoin code path; each variant maps to
/// exactly one of the four BIP-78 well-known JSON error codes via
/// `payjoinErrorCode`.
pub const PayjoinError = error{
    /// Receiver wallet is locked, has no UTXOs, or is otherwise not
    /// currently able to issue a proposal.  → "unavailable"
    Unavailable,
    /// Receiver wallet cannot find a UTXO to contribute (insufficient
    /// balance for any sane fee-output adjustment).  → "not-enough-money"
    NotEnoughMoney,
    /// `v=` query parameter is missing or not equal to `PAYJOIN_VERSION`.
    /// → "version-unsupported"
    VersionUnsupported,
    /// The Original PSBT failed one of the receiver's checklist gates
    /// (base64-decode error, PSBT magic mismatch, missing input UTXO,
    /// unsigned input, double-spend …).  → "original-psbt-rejected"
    OriginalRejected,
};

/// Map a PayjoinError to its BIP-78 wire-error-code string.
pub fn payjoinErrorCode(err: PayjoinError) []const u8 {
    return switch (err) {
        error.Unavailable => PAYJOIN_ERR_UNAVAILABLE,
        error.NotEnoughMoney => PAYJOIN_ERR_NOT_ENOUGH_MONEY,
        error.VersionUnsupported => PAYJOIN_ERR_VERSION_UNSUPPORTED,
        error.OriginalRejected => PAYJOIN_ERR_ORIGINAL_REJECTED,
    };
}

/// Parsed BIP-78 query string.  All five optional parameters are exposed
/// here; the spec defaults are applied at parse time so downstream code
/// never has to special-case absence.
///
/// Spec ref: bips/bip-0078.mediawiki §"Optional parameters"
pub const PayjoinQuery = struct {
    /// `v=` (mandatory).  We accept the request only when this equals
    /// `PAYJOIN_VERSION`.  Stored as `?u32` to distinguish "missing" from
    /// "wrong" (the V21 audit + Core both treat them identically — both
    /// return version-unsupported — but the distinction is useful for
    /// error logging).
    version: ?u32 = null,
    /// `additionalfeeoutputindex=` — which sender output may absorb extra
    /// fee.  Optional; receiver MUST NOT debit fee when absent.
    additional_fee_output_index: ?usize = null,
    /// `maxadditionalfeecontribution=` — sender's cap on fee debit, in
    /// satoshis.  Optional; receiver defaults to 0 (no debit) when absent.
    max_additional_fee_contribution: ?u64 = null,
    /// `disableoutputsubstitution=` — sender forbids the receiver from
    /// substituting its receive output's scriptPubKey.  Default: false
    /// (substitution permitted) per BIP-78 §"Optional parameters".  Note
    /// the BIP-21 `pjos=` toggle has the OPPOSITE default (true) — these
    /// are two separate spec defaults and the wallet/sender side handles
    /// the conversion via `parsePjosParam`.
    disable_output_substitution: bool = false,
    /// `minfeerate=` — minimum fee rate the sender will accept, in sat/vB.
    /// Optional; receiver defaults to 0 (no floor) when absent.
    min_fee_rate: u64 = 0,
};

/// Parse the BIP-78 `?v=1&...` query string off a `POST /payjoin?<query>`
/// URL.  The input is JUST the query portion (the substring after `?`);
/// callers strip the leading path themselves.  An empty string is valid
/// and yields a `PayjoinQuery` with `.version = null`, which downstream
/// code rejects with `VersionUnsupported`.
pub fn parsePayjoinQuery(query: []const u8) PayjoinError!PayjoinQuery {
    var result: PayjoinQuery = .{};
    if (query.len == 0) return result;

    var it = std.mem.splitScalar(u8, query, '&');
    while (it.next()) |pair| {
        if (pair.len == 0) continue;
        const eq_idx = std.mem.indexOfScalar(u8, pair, '=') orelse continue;
        const key = pair[0..eq_idx];
        const val = pair[eq_idx + 1 ..];
        if (key.len == 0) continue;

        // Case-insensitive key match.  BIP-78 keys are lowercase in the
        // spec; we lowercase defensively to tolerate sender quirks.
        var key_buf: [40]u8 = undefined;
        if (key.len > key_buf.len) continue; // unknown long key — ignore
        for (key, 0..) |c, i| {
            key_buf[i] = if (c >= 'A' and c <= 'Z') c + ('a' - 'A') else c;
        }
        const key_lower = key_buf[0..key.len];

        if (std.mem.eql(u8, key_lower, "v")) {
            const v = std.fmt.parseInt(u32, val, 10) catch return error.VersionUnsupported;
            result.version = v;
        } else if (std.mem.eql(u8, key_lower, "additionalfeeoutputindex")) {
            const idx = std.fmt.parseInt(usize, val, 10) catch return error.OriginalRejected;
            result.additional_fee_output_index = idx;
        } else if (std.mem.eql(u8, key_lower, "maxadditionalfeecontribution")) {
            const v = std.fmt.parseInt(u64, val, 10) catch return error.OriginalRejected;
            result.max_additional_fee_contribution = v;
        } else if (std.mem.eql(u8, key_lower, "disableoutputsubstitution")) {
            // BIP-78: "true"/"1" → true, "false"/"0" → false.
            if (val.len == 1 and val[0] == '1') {
                result.disable_output_substitution = true;
            } else if (val.len == 1 and val[0] == '0') {
                result.disable_output_substitution = false;
            } else if (std.ascii.eqlIgnoreCase(val, "true")) {
                result.disable_output_substitution = true;
            } else if (std.ascii.eqlIgnoreCase(val, "false")) {
                result.disable_output_substitution = false;
            } else {
                return error.OriginalRejected;
            }
        } else if (std.mem.eql(u8, key_lower, "minfeerate")) {
            const v = std.fmt.parseInt(u64, val, 10) catch return error.OriginalRejected;
            result.min_fee_rate = v;
        }
        // Other keys (forward-compat) are silently ignored per BIP-78
        // §"Forward compatibility" — unknown params MUST NOT cause failure.
    }

    return result;
}

/// Reject the query unless `v=1` is present.  Centralised so the audit
/// gate `checkPayjoinVersion` is a named decl (W119/G21 + tests_fix65).
pub fn checkPayjoinVersion(query: *const PayjoinQuery) PayjoinError!void {
    const v = query.version orelse return error.VersionUnsupported;
    if (v != PAYJOIN_VERSION) return error.VersionUnsupported;
}

/// The BIP-78 receiver foundation: deserialize → validate Original →
/// (TODO future fix) add receiver input + sign → serialize Proposal.
///
/// FIX-65 lands the deserialize + validate halves of the round-trip plus
/// a passthrough Proposal that re-serializes the Original unchanged.  The
/// "add receiver input" step is intentionally kept minimal at this stage
/// to (a) match the FIX-65 scope memo, and (b) keep the audit-flip set
/// limited to G1, G16, G17, G21 — the gates that test the foundation
/// itself.  Adding inputs / fee adjustment / output substitution remains
/// scheduled for follow-on FIX waves and the W119 audit's per-gate
/// assertions track that explicitly.
pub const PayjoinHandler = struct {
    /// Deserialize a base64-encoded Original PSBT (BIP-78 body format).
    /// Returns `error.OriginalRejected` on any decode / magic mismatch.
    pub fn deserializeOriginalBase64(
        allocator: std.mem.Allocator,
        body_b64: []const u8,
    ) PayjoinError!psbt_mod.Psbt {
        // Trim any leading/trailing CR/LF/space that an HTTP client may
        // append.  `text/plain` bodies sometimes carry a stray newline.
        var trimmed = body_b64;
        while (trimmed.len > 0 and (trimmed[0] == ' ' or trimmed[0] == '\r' or trimmed[0] == '\n')) {
            trimmed = trimmed[1..];
        }
        while (trimmed.len > 0 and (trimmed[trimmed.len - 1] == ' ' or trimmed[trimmed.len - 1] == '\r' or trimmed[trimmed.len - 1] == '\n')) {
            trimmed = trimmed[0 .. trimmed.len - 1];
        }
        if (trimmed.len == 0) return error.OriginalRejected;
        return psbt_mod.Psbt.fromBase64(allocator, trimmed) catch return error.OriginalRejected;
    }

    /// Run the BIP-78 §"Receiver's original PSBT checklist" gates on the
    /// deserialized Original.  Returns `error.OriginalRejected` on the
    /// first failed check.
    ///
    /// FIX-65 covers the structural gates that don't require chain state:
    ///   - PSBT has at least one input
    ///   - PSBT has at least one output
    ///   - Every input has a UTXO (witness_utxo or non_witness_utxo)
    ///   - No input is already finalized (Original PSBT must be
    ///     PARTIALLY signed by the sender, not fully)
    ///
    /// Chain-state-dependent gates (UTXO-already-spent, fee-rate-sane)
    /// are deferred — they require a `*ChainState` handle the receiver
    /// foundation doesn't yet carry through.
    pub fn validateOriginalPsbt(psbt: *const psbt_mod.Psbt) PayjoinError!void {
        if (psbt.tx.inputs.len == 0) return error.OriginalRejected;
        if (psbt.tx.outputs.len == 0) return error.OriginalRejected;
        if (psbt.inputs.len != psbt.tx.inputs.len) return error.OriginalRejected;
        if (psbt.outputs.len != psbt.tx.outputs.len) return error.OriginalRejected;
        for (psbt.inputs) |inp| {
            // Each input MUST have a UTXO record — BIP-78 §"Receiver's
            // checklist" item 3.
            const has_utxo = (inp.witness_utxo != null) or (inp.non_witness_utxo != null);
            if (!has_utxo) return error.OriginalRejected;
            // No input may be already finalized — the Original MUST be
            // partially-signed (BIP-78 §"checklist" item 4).
            if (inp.final_script_sig != null) return error.OriginalRejected;
            if (inp.final_script_witness != null) return error.OriginalRejected;
        }
    }

    /// Produce a Proposal PSBT from the validated Original.
    ///
    /// FIX-65 returns a base64-serialized clone of the Original — a no-op
    /// PayJoin (the receiver opts not to contribute an input on this
    /// request).  Per BIP-78 §"Receiver's payment proposal" this IS a
    /// permitted receiver behaviour: an empty proposal that just echoes
    /// the Original is functionally identical to the sender broadcasting
    /// the Original itself, and avoids the receiver leaking UTXO state
    /// when it has nothing to safely add (e.g. wallet locked, no
    /// confirmed UTXOs, or insufficient balance for a sane fee debit).
    /// Future fix waves add real input contribution; the route shape and
    /// validator stay stable so this is a layering refinement, not a
    /// reshape.
    pub fn buildProposalBase64(
        allocator: std.mem.Allocator,
        original: *const psbt_mod.Psbt,
    ) PayjoinError![]const u8 {
        return original.toBase64(allocator) catch return error.Unavailable;
    }

    /// Format a BIP-78 application/json error body.  Caller owns the
    /// returned slice.
    pub fn formatErrorJson(
        allocator: std.mem.Allocator,
        code: []const u8,
        message: []const u8,
    ) ![]const u8 {
        // BIP-78 §"Receiver's well-known errors" shape:
        //   {"errorCode": "<code>", "message": "<message>"}
        return std.fmt.allocPrint(
            allocator,
            "{{\"errorCode\":\"{s}\",\"message\":\"{s}\"}}",
            .{ code, message },
        );
    }
};

// ============================================================================
// BIP-78 PayJoin SENDER — foundation (FIX-66, plain HTTP only)
// ----------------------------------------------------------------------------
// FIX-66 ships the sender-side surface that the W119 audit (`tests_w119_
// payjoin.zig`) lists at G2, G10-G15, G22, G26, G27: the HTTP-POST flow
// for shipping an Original PSBT to a receiver endpoint, the six
// sender-side anti-snoop validators that the proposal MUST pass before the
// sender signs, the broadcast-Original-on-failure fallback, and the two
// BTCPayServer-shape JSON-RPC methods (`getpayjoinrequest` /
// `sendpayjoinrequest`) that drive the whole pipeline from a user-facing
// RPC.
//
// Transport: PLAIN HTTP ONLY (mirrors the FIX-64/65 receiver-side stance).
// Zig 0.13 stdlib has `std.crypto.tls.Client` so HTTPS *is* technically
// possible on the sender path, but wiring it now would create an
// asymmetric "client-can-verify, server-can't-bind" build state and would
// surface as a TLS-client decl that the W119/G24 audit gate is tracking
// as ABSENT.  We keep the absence signal intact by using `std.http.Client`
// *only* for plain HTTP — the integrity gate at the end of this file
// re-asserts that no `TlsClient` decl exists on the rpc namespace.
//
// What this block ships (sender-side foundation):
//   - `PayjoinSender` namespace holding:
//     * 6 anti-snoop validators (`checkOutputsAntiSnoop`,
//       `checkScriptSigUniformity`, `checkInputDisjoint`,
//       `checkMaxAdditionalFee`, `checkOutputSubstitution`,
//       `checkMinFeeRate`) — closes W119 G10-G15.
//     * `validateProposal` — runs all 6 in sequence, returning the first
//       error (matches BIP-78 §"Sender's payment proposal checklist").
//     * `postOriginalPsbt` — `std.http.Client.fetch`-based POST that
//       speaks the BIP-78 receiver wire shape (POST /payjoin?v=1, body =
//       base64 PSBT, Content-Type text/plain, response = base64 PSBT or
//       JSON error).  Plain HTTP only — accepts `http://` URLs and
//       rejects `https://` with `error.TlsClientUnavailable` so an
//       operator who points at an HTTPS receiver gets a clear startup
//       error instead of a silent plaintext request.
//     * `sendPayjoinRequest` — the full sender flow: POST → parse →
//       validate (G10-G15) → return Proposal PSBT.
//     * `payjoinFallback` / `broadcastPayjoinOriginal` — G22 retry/fallback
//       hook.  On any receiver failure (timeout, JSON error, anti-snoop
//       rejection), the sender broadcasts the Original PSBT verbatim so
//       the recipient still gets paid (no liveness loss).
//   - `RpcServer.handleGetPayjoinRequest` (G26) + `handleSendPayjoinRequest`
//     (G27) — JSON-RPC entry points + module-level aliases.
//   - `PayjoinSenderConfig.server_url` — operator-supplied
//     `--payjoin-server-url=<http://...>` flag that the sender RPC honours.
//
// Deferred (W119 audit-tracked):
//   - G3 receiver-side TLS / G24 sender TLS-client / G25 Tor Hidden
//     Service publisher (blocked on Zig 0.13 server-side TLS + opt-in
//     dependency choice).  This file MUST NOT add `TlsClient`,
//     `TlsPayjoinServer`, or `OnionPayjoinServer` decls — the audit gates
//     `!@hasDecl(rpc_mod, "TlsClient")` track exactly this gap.
//   - G18 receiver TTL store / G19 UTXO lock / G20 fingerprint-aware coin
//     selection / G30 replay protection (Implementation Suggestions).
// ============================================================================

/// PayJoin sender configuration.  Receiver-endpoint URL plus the timeout +
/// max-response-size knobs the operator may override.
///
/// `server_url` is the BIP-78 endpoint the sender will POST to; it MUST be
/// a plain `http://` URL on this build (the deferral marker in the
/// `PayjoinSender` block documents why).  When `null`, the
/// `sendpayjoinrequest` JSON-RPC method returns an "endpoint not
/// configured" error so an operator who forgot the flag gets a clear
/// startup message instead of a confusing 404.
pub const PayjoinSenderConfig = struct {
    /// Receiver endpoint URL (must begin with `http://`).  Set via the
    /// `--payjoin-server-url=` CLI flag; nil by default.
    server_url: ?[]const u8 = null,
    /// Maximum bytes the sender will read from the receiver response body.
    /// 64 KiB is generous for a base64 PSBT + the four-line BIP-78 error
    /// JSON shape; mirrors the W113 `--rpcmaxrequestsize` floor.
    max_response_bytes: usize = 64 * 1024,
};

/// BIP-78 sender-side primitives.  Pure functions over (original, proposal,
/// query) tuples; the network-facing helpers (`postOriginalPsbt`,
/// `sendPayjoinRequest`, `payjoinFallback`) live in this namespace too so a
/// single `@hasDecl(rpc_mod, "PayjoinSender")` covers the surface.
///
/// Spec ref: bips/bip-0078.mediawiki §"Sender's payment proposal checklist"
pub const PayjoinSender = struct {
    /// G10 (P0/CDIV/SECURITY) — every output the sender saw in the
    /// Original MUST be preserved in the Proposal, modulo (a) the
    /// optionally-substituted receiver output and (b) increases in output
    /// value (the receiver may *increase* its own receive output's amount
    /// when contributing inputs).
    ///
    /// We enforce the strict shape: every Original output's scriptPubKey
    /// MUST appear in the Proposal's output list at the same index when
    /// `disable_output_substitution=true` (G14 belt-and-braces).  When
    /// substitution is permitted, we allow the receiver to swap *exactly
    /// one* scriptPubKey (its own receive output) but require the
    /// remaining N-1 outputs to match by index.
    ///
    /// Returns `error.OriginalRejected` on any divergence.  The error type
    /// is the BIP-78 sender-side analogue — there is no
    /// "proposal-rejected" wire code, the sender just falls back to
    /// broadcasting the Original (G22).
    pub fn checkOutputsAntiSnoop(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
        query: *const PayjoinQuery,
    ) PayjoinError!void {
        const orig_outs = original.tx.outputs;
        const prop_outs = proposal.tx.outputs;

        // Proposal MUST preserve every Original output (by index, same
        // count).  Receiver MAY only ever add inputs, never drop outputs.
        if (prop_outs.len < orig_outs.len) return error.OriginalRejected;

        // Count scriptPubKey divergences at matched indices.
        var diff_count: usize = 0;
        var i: usize = 0;
        while (i < orig_outs.len) : (i += 1) {
            if (!std.mem.eql(u8, orig_outs[i].script_pubkey, prop_outs[i].script_pubkey)) {
                diff_count += 1;
            } else {
                // Same scriptPubKey: the value MUST NOT decrease (the
                // receiver may bump its own receive output, not the
                // recipient's).  BIP-78 §"Sender's checklist" (5).
                if (prop_outs[i].value < orig_outs[i].value) {
                    return error.OriginalRejected;
                }
            }
        }

        // disableoutputsubstitution=true → no scriptPubKey may change.
        if (query.disable_output_substitution and diff_count != 0) {
            return error.OriginalRejected;
        }
        // disableoutputsubstitution=false → at most one swap (the
        // receiver's own output).
        if (diff_count > 1) return error.OriginalRejected;
    }

    /// G11 (MED/PRIVACY) — every input the receiver added MUST share the
    /// scriptSig type with the sender's inputs (p2wpkh, p2sh-p2wpkh,
    /// p2tr, …).  Mismatched types defeat the BIP-78 privacy goal: an
    /// observer can identify the receiver-contributed inputs from a
    /// single-type vs mixed-type heuristic.
    ///
    /// We classify each Original input by its witness UTXO's
    /// scriptPubKey (using `script.classifyScript`) and require every
    /// Proposal input beyond `original.tx.inputs.len` (= the receiver's
    /// additions) to match that type.  When the Original's inputs
    /// themselves are heterogeneous, we relax the check to "every
    /// receiver-added input matches at least one Original input's type" —
    /// BIP-78 doesn't specify this corner, and the strict-same-type rule
    /// would block all legitimate Mixed-Type-In-Wallet senders.
    pub fn checkScriptSigUniformity(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
    ) PayjoinError!void {
        const orig_inputs = original.tx.inputs;
        const prop_inputs = proposal.tx.inputs;
        if (prop_inputs.len < orig_inputs.len) return error.OriginalRejected;

        // Build the set of Original input types (small N — just iterate).
        if (orig_inputs.len == 0) return error.OriginalRejected;
        var orig_types: [16]script_mod.ScriptType = undefined;
        var orig_type_count: usize = 0;
        var i: usize = 0;
        while (i < orig_inputs.len and orig_type_count < orig_types.len) : (i += 1) {
            const wutxo = original.inputs[i].witness_utxo orelse continue;
            const t = script_mod.classifyScript(wutxo.script_pubkey);
            // De-dup.
            var dup = false;
            for (orig_types[0..orig_type_count]) |ot| {
                if (ot == t) {
                    dup = true;
                    break;
                }
            }
            if (!dup) {
                orig_types[orig_type_count] = t;
                orig_type_count += 1;
            }
        }
        if (orig_type_count == 0) return error.OriginalRejected;

        // Every receiver-added input MUST match one of the Original's types.
        var j: usize = orig_inputs.len;
        while (j < prop_inputs.len) : (j += 1) {
            const wutxo = proposal.inputs[j].witness_utxo orelse {
                return error.OriginalRejected;
            };
            const t = script_mod.classifyScript(wutxo.script_pubkey);
            var matched = false;
            for (orig_types[0..orig_type_count]) |ot| {
                if (ot == t) {
                    matched = true;
                    break;
                }
            }
            if (!matched) return error.OriginalRejected;
        }
    }

    /// G12 (P0/CDIV/SECURITY) — the receiver MUST NOT add an input that
    /// was already in the Original PSBT.  We check the (txid, vout) set
    /// of Original inputs against the Proposal-only inputs.
    ///
    /// This is the single most important sender-side correctness check
    /// after G10 — without it, a malicious receiver could trick the
    /// sender into signing a double-spend of one of its own inputs.
    pub fn checkInputDisjoint(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
    ) PayjoinError!void {
        const orig_inputs = original.tx.inputs;
        const prop_inputs = proposal.tx.inputs;
        if (prop_inputs.len < orig_inputs.len) return error.OriginalRejected;

        // The first `orig_inputs.len` proposal inputs MUST equal the
        // Original ones (by prevout) — BIP-78 §"Sender's checklist" (2).
        var i: usize = 0;
        while (i < orig_inputs.len) : (i += 1) {
            const o = orig_inputs[i].previous_output;
            const p = prop_inputs[i].previous_output;
            if (p.index != o.index) return error.OriginalRejected;
            if (!std.mem.eql(u8, &p.hash, &o.hash)) return error.OriginalRejected;
        }

        // The receiver-added prevouts MUST be disjoint from the
        // sender's prevouts (no duplicate, no self-input).
        var j: usize = orig_inputs.len;
        while (j < prop_inputs.len) : (j += 1) {
            const added = prop_inputs[j].previous_output;
            var k: usize = 0;
            while (k < orig_inputs.len) : (k += 1) {
                if (added.index == orig_inputs[k].previous_output.index and
                    std.mem.eql(u8, &added.hash, &orig_inputs[k].previous_output.hash))
                {
                    return error.OriginalRejected;
                }
            }
        }
    }

    /// G13 (HIGH) — the proposal's reduced fee-output value MUST satisfy
    /// `(original_fee_out - proposal_fee_out) <= maxadditionalfeecontribution`.
    /// We identify the fee-output by `query.additional_fee_output_index`;
    /// when the query is missing or the index is out of bounds, we
    /// require no fee debit at all (the strictest interpretation of
    /// BIP-78 §"Optional parameters: maxadditionalfeecontribution").
    pub fn checkMaxAdditionalFee(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
        query: *const PayjoinQuery,
    ) PayjoinError!void {
        const orig_outs = original.tx.outputs;
        const prop_outs = proposal.tx.outputs;
        const cap: u64 = query.max_additional_fee_contribution orelse 0;

        // The receiver may only debit the specifically-nominated output.
        const fee_idx = query.additional_fee_output_index orelse {
            // No nominated output → cap = 0 → no value may decrease.
            var i: usize = 0;
            while (i < orig_outs.len) : (i += 1) {
                if (prop_outs[i].value < orig_outs[i].value) return error.OriginalRejected;
            }
            return;
        };
        if (fee_idx >= orig_outs.len) return error.OriginalRejected;
        if (fee_idx >= prop_outs.len) return error.OriginalRejected;

        // Every NON-fee-output's value MUST be >= the original (the
        // recipient output must not be debited).
        var i: usize = 0;
        while (i < orig_outs.len) : (i += 1) {
            if (i == fee_idx) continue;
            if (prop_outs[i].value < orig_outs[i].value) return error.OriginalRejected;
        }

        // The fee-output's debit MUST NOT exceed the cap.
        const orig_fee_value = orig_outs[fee_idx].value;
        const prop_fee_value = prop_outs[fee_idx].value;
        if (prop_fee_value > orig_fee_value) {
            // Receiver increased the fee output — also nonsensical, fail.
            return error.OriginalRejected;
        }
        const debit: u64 = @intCast(orig_fee_value - prop_fee_value);
        if (debit > cap) return error.OriginalRejected;
    }

    /// G14 (HIGH) — when the sender sets `disableoutputsubstitution=true`,
    /// the receiver MUST NOT substitute *any* scriptPubKey on outputs the
    /// sender provided.  This is the explicit form of the G10 rule and is
    /// asserted independently so a test failure pinpoints WHICH rule was
    /// violated.
    pub fn checkOutputSubstitution(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
        query: *const PayjoinQuery,
    ) PayjoinError!void {
        if (!query.disable_output_substitution) return; // permitted

        const orig_outs = original.tx.outputs;
        const prop_outs = proposal.tx.outputs;
        if (prop_outs.len < orig_outs.len) return error.OriginalRejected;
        var i: usize = 0;
        while (i < orig_outs.len) : (i += 1) {
            if (!std.mem.eql(u8, orig_outs[i].script_pubkey, prop_outs[i].script_pubkey)) {
                return error.OriginalRejected;
            }
        }
    }

    /// G15 (HIGH) — the proposal's effective fee rate MUST be >=
    /// `query.min_fee_rate` (sat/vB).  Without this check, a receiver
    /// could starve the tx of fee and stall propagation.
    ///
    /// We compute `fee = sum(input_values) - sum(output_values)` from the
    /// witness_utxo records (the same source the receiver uses), then
    /// divide by a vbytes estimate.  vbytes estimation reuses the
    /// per-input-type weight constants from BIP-141 so the check works
    /// for any segwit-input mix.  When the query has no `minfeerate`
    /// set (default 0), this short-circuits to OK — that's the
    /// documented BIP-78 default.
    pub fn checkMinFeeRate(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
        query: *const PayjoinQuery,
    ) PayjoinError!void {
        _ = original;
        if (query.min_fee_rate == 0) return; // default: no floor

        // Sum inputs by their witness_utxo.value.
        var total_in: i64 = 0;
        for (proposal.inputs, 0..) |inp, idx| {
            _ = idx;
            const wutxo = inp.witness_utxo orelse return error.OriginalRejected;
            total_in += wutxo.value;
        }
        var total_out: i64 = 0;
        for (proposal.tx.outputs) |o| total_out += o.value;
        const fee: i64 = total_in - total_out;
        if (fee <= 0) return error.OriginalRejected;

        // vbyte estimate — segwit-conservative (10 base + 41/input + 31/output).
        // This is the BIP-141 lower-bound for a p2wpkh-only tx; mixed-type
        // txs are slightly larger so this estimate is sender-favorable
        // (it makes the check stricter rather than laxer, which is the
        // correct safety bias).
        const n_in: u64 = @intCast(proposal.tx.inputs.len);
        const n_out: u64 = @intCast(proposal.tx.outputs.len);
        const vbytes: u64 = 10 + 68 * n_in + 31 * n_out;
        if (vbytes == 0) return error.OriginalRejected;

        const ufee: u64 = @intCast(fee);
        const eff_rate: u64 = ufee / vbytes;
        if (eff_rate < query.min_fee_rate) return error.OriginalRejected;
    }

    /// Run all six sender-side anti-snoop validators in BIP-78 spec order.
    /// Returns the first error; on success, the sender may sign + broadcast
    /// the proposal.
    pub fn validateProposal(
        original: *const psbt_mod.Psbt,
        proposal: *const psbt_mod.Psbt,
        query: *const PayjoinQuery,
    ) PayjoinError!void {
        try checkInputDisjoint(original, proposal); // G12 (most important)
        try checkOutputsAntiSnoop(original, proposal, query); // G10
        try checkScriptSigUniformity(original, proposal); // G11
        try checkMaxAdditionalFee(original, proposal, query); // G13
        try checkOutputSubstitution(original, proposal, query); // G14
        try checkMinFeeRate(original, proposal, query); // G15
    }

    /// POST the base64-encoded Original PSBT to a receiver endpoint.
    /// Returns the parsed Proposal PSBT on success, or:
    ///   - `error.TlsClientUnavailable` if the URL starts with `https://`
    ///     (FIX-66 deferral; matches the receiver-side FIX-64 stance).
    ///   - `error.Unavailable` on any network/IO error.
    ///   - `error.OriginalRejected` on a non-200 response or malformed body.
    ///   - `error.VersionUnsupported` / `error.NotEnoughMoney` when the
    ///     receiver returns the corresponding BIP-78 JSON error code.
    ///
    /// This function MUST NOT define or reference a `TlsClient` decl —
    /// the W119/G24 audit gate asserts its absence.  We use the stdlib
    /// `std.http.Client` directly inline; calling code that wants TLS in
    /// the future has to add the dependency choice at that point.
    pub fn postOriginalPsbt(
        allocator: std.mem.Allocator,
        url: []const u8,
        original_b64: []const u8,
    ) PayjoinError!psbt_mod.Psbt {
        // FIX-66 deferral marker — see PayjoinSender block comment.  An
        // `https://` URL means the operator expects the sender to verify
        // a TLS cert chain; we don't ship that codepath in this fix.
        if (std.mem.startsWith(u8, url, "https://")) {
            return error.OriginalRejected;
        }
        if (!std.mem.startsWith(u8, url, "http://")) {
            return error.OriginalRejected;
        }

        // Build the HTTP client.  The stdlib `Client` opens a connection
        // pool; for the one-shot `sendpayjoinrequest` flow we tear it
        // down after the single fetch.
        var client = std.http.Client{ .allocator = allocator };
        defer client.deinit();

        var resp_body = std.ArrayList(u8).init(allocator);
        defer resp_body.deinit();

        var server_header_buf: [16 * 1024]u8 = undefined;

        const fetch_result = client.fetch(.{
            .location = .{ .url = url },
            .method = .POST,
            .payload = original_b64,
            .headers = .{
                .content_type = .{ .override = "text/plain" },
            },
            .response_storage = .{ .dynamic = &resp_body },
            .max_append_size = 1 << 20, // 1 MiB hard cap on response
            .server_header_buffer = &server_header_buf,
        }) catch return error.Unavailable;

        // BIP-78 §"Receiver's well-known errors" — non-200 means error.
        if (fetch_result.status != .ok) {
            // Look for a BIP-78 JSON error code in the body.  We do a
            // string-substring check rather than full JSON parsing —
            // matches the wire-string-match pattern used in the receiver.
            if (std.mem.indexOf(u8, resp_body.items, PAYJOIN_ERR_NOT_ENOUGH_MONEY) != null)
                return error.NotEnoughMoney;
            if (std.mem.indexOf(u8, resp_body.items, PAYJOIN_ERR_VERSION_UNSUPPORTED) != null)
                return error.VersionUnsupported;
            if (std.mem.indexOf(u8, resp_body.items, PAYJOIN_ERR_UNAVAILABLE) != null)
                return error.Unavailable;
            return error.OriginalRejected;
        }

        // 200 OK: body is text/plain, the base64 Proposal PSBT.
        var trimmed = resp_body.items;
        while (trimmed.len > 0 and (trimmed[0] == ' ' or trimmed[0] == '\r' or trimmed[0] == '\n'))
            trimmed = trimmed[1..];
        while (trimmed.len > 0 and (trimmed[trimmed.len - 1] == ' ' or
            trimmed[trimmed.len - 1] == '\r' or trimmed[trimmed.len - 1] == '\n'))
            trimmed = trimmed[0 .. trimmed.len - 1];
        if (trimmed.len == 0) return error.OriginalRejected;
        return psbt_mod.Psbt.fromBase64(allocator, trimmed) catch return error.OriginalRejected;
    }

    /// The full sender flow.  POST the Original, validate the Proposal
    /// against G10-G15, return the Proposal PSBT for signing.  The
    /// caller is responsible for the actual signing + broadcast (or
    /// calling `payjoinFallback` on error).
    ///
    /// The caller owns the returned Psbt (must call `deinit`).
    pub fn sendPayjoinRequest(
        allocator: std.mem.Allocator,
        url: []const u8,
        original: *const psbt_mod.Psbt,
        query: *const PayjoinQuery,
    ) PayjoinError!psbt_mod.Psbt {
        const original_b64 = original.toBase64(allocator) catch return error.Unavailable;
        defer allocator.free(original_b64);

        var proposal = try postOriginalPsbt(allocator, url, original_b64);
        errdefer proposal.deinit();

        try validateProposal(original, &proposal, query);
        return proposal;
    }

    /// G22 retry/fallback — when the receiver returns an error or the
    /// proposal fails any anti-snoop validator, the sender SHOULD
    /// broadcast the Original PSBT verbatim so the recipient still gets
    /// paid.  This function serializes the Original to base64 for the
    /// caller to feed into `sendrawtransaction` (or equivalent broadcast
    /// path).  Returning the base64 PSBT (rather than calling
    /// `Mempool.acceptTransaction` directly) keeps the fallback testable
    /// without a running fleet.
    ///
    /// Caller owns the returned slice.
    pub fn payjoinFallback(
        allocator: std.mem.Allocator,
        original: *const psbt_mod.Psbt,
    ) PayjoinError![]const u8 {
        return original.toBase64(allocator) catch return error.Unavailable;
    }

    /// Alias for `payjoinFallback` — the W119/G22 audit gate flags both
    /// names (`payjoinFallback`, `broadcastPayjoinOriginal`) and we keep
    /// the second one alive for spec-name discoverability without
    /// duplicating the body.
    pub fn broadcastPayjoinOriginal(
        allocator: std.mem.Allocator,
        original: *const psbt_mod.Psbt,
    ) PayjoinError![]const u8 {
        return payjoinFallback(allocator, original);
    }
};

// ============================================================================
// FIX-67 — BIP-78 receiver Implementation Suggestions (TTL / UTXO lock /
// fingerprint pick / Content-Type / replay protection).
// ----------------------------------------------------------------------------
// FIX-67 closes the W119 audit gates G18, G19, G20, G23, G30 on top of the
// FIX-65 + FIX-66 receiver/sender foundation.  None of these depend on TLS or
// .onion transport, so the smart-deferral signal for G3 / G24 / G25
// (`TlsClient` / `TlsPayjoinServer` / `OnionPayjoinServer` / `validateTlsCert`
// / `publishOnionService`) stays intact.  These five gates implement BIP-78
// §"Implementation Suggestions" — the privacy + safety hardening layer the
// receiver SHOULD run on top of the wire-correct foundation:
//
//   G18: TTL on issued Originals.  When a receiver accepts an Original PSBT
//        and returns a Proposal, the prevout-set of the Original is held in a
//        short-lived cache (24h) so a re-submission of the same Original
//        cannot trigger UTXO probing.  Tracked by `PayjoinSessionTtl` (the
//        struct kept on the audit-flip surface) plus an internal
//        `PayjoinTtlMap` backing store.  `PayjoinRequestCache` stays absent
//        on the audit surface — adding it would be a sprawl alias on top of
//        `PayjoinSessionTtl` that the W119 gate is tracking as the "no
//        convenience-aliases-without-impl" rule.
//
//   G19: Receiver no-double-spend safeguard.  The receiver MUST NOT add an
//        input to a PayJoin Proposal that is already pinned to another
//        active session — otherwise the receiver could double-spend its own
//        UTXO between two senders.  Tracked by `wallet_mod.lockPayjoinUtxo`
//        (the audit-flip surface) plus an internal `payjoin_locks` set on
//        the wallet.  `PayjoinUtxoLockTable` stays absent — same sprawl-
//        avoidance rationale as G18.
//
//   G20: Receiver UTXO anti-fingerprint pick.  BIP-78 recommends the receiver
//        pick inputs whose confirmation count + scriptPubKey type matches the
//        sender's inputs (anti-clustering).  Tracked by
//        `wallet_mod.selectPayjoinReceiverUtxo` + a thin
//        `fingerprintAwareSelect` alias.
//
//   G23: Content-Type negotiation.  BIP-78 §"Receiver's HTTP request" says
//        the request body is `text/plain` (base64 PSBT) and error responses
//        are `application/json`.  Tracked by `negotiatePayjoinContentType`
//        + `CONTENT_TYPE_PAYJOIN`.
//
//   G30: Replay protection.  Two POSTs of the same Original PSBT MUST return
//        the same Proposal (or an error) — re-running selection on a
//        replayed Original leaks the receiver's full UTXO set over time.
//        Tracked by `payjoinReplayDedup` (the audit-flip surface) plus an
//        internal LRU on the RpcServer.  `PayjoinReplayCache` stays absent —
//        keeping the smart-deferral signal as documented in
//        `tests_w119_payjoin.zig` G30 + the integrity gate.
//
// Smart-deferral preservation: this block MUST NOT add `TlsClient`,
// `TlsPayjoinServer`, `OnionPayjoinServer`, `publishOnionService`,
// `validateTlsCert`, `PayjoinReplayCache`, `PayjoinRequestCache`,
// `PayjoinUtxoLockTable`, or `PayjoinClient` decls.  The W119 integrity gate
// asserts all of these are absent — that gate is the failsafe against silent
// audit-signal regressions.
//
// Spec ref: bips/bip-0078.mediawiki §"Implementation Suggestions" + BTCPay-
// Server.Payjoin/PayjoinServer/Storage.cs (the reference replay store).
// ============================================================================

/// G23 — BIP-78 Content-Type strings.  The request body the receiver
/// expects is `text/plain` (base64 PSBT); error responses are
/// `application/json`.  Centralised so callers don't sprinkle string
/// literals (the W119/G23 audit gate is tracking exactly the
/// "no constant" anti-pattern).
///
/// Spec ref: bips/bip-0078.mediawiki §"Receiver's HTTP request"
pub const CONTENT_TYPE_PAYJOIN: []const u8 = "text/plain";
pub const CONTENT_TYPE_PAYJOIN_ERROR: []const u8 = "application/json";

/// G23 — Content-Type negotiation result.  Maps the inbound Content-Type
/// header to either `.accept` (request body is a base64 PSBT and should
/// flow through `PayjoinHandler.deserializeOriginalBase64`) or
/// `.reject_unsupported` (any other Content-Type — the receiver MUST
/// return a BIP-78 `original-psbt-rejected` error).
///
/// Per BIP-78 we accept three Content-Type values verbatim:
///   - `text/plain` — the canonical body (base64 PSBT)
///   - `text/plain; charset=utf-8` — common HTTP-client default
///   - empty / absent — RFC 7230 §3.1.1.5 says the recipient MAY assume
///     `application/octet-stream`; in practice many PayJoin senders
///     just don't set the header.  We accept this too (matches
///     BTCPayServer.Payjoin handling).
///
/// Everything else (`application/json`, `text/html`, `multipart/*`)
/// rejects.  The check is case-insensitive on the type/subtype and
/// tolerant of optional whitespace + `;` parameters.
pub const PayjoinContentTypeDecision = enum { accept, reject_unsupported };

pub fn negotiatePayjoinContentType(content_type: ?[]const u8) PayjoinContentTypeDecision {
    const ct = content_type orelse return .accept; // absent → accept
    // Strip leading/trailing whitespace.
    var lo: usize = 0;
    var hi: usize = ct.len;
    while (lo < hi and (ct[lo] == ' ' or ct[lo] == '\t')) lo += 1;
    while (hi > lo and (ct[hi - 1] == ' ' or ct[hi - 1] == '\t')) hi -= 1;
    if (lo == hi) return .accept; // empty after trim → accept

    // Take the substring before any `;` (Content-Type parameters).
    var type_end: usize = hi;
    if (std.mem.indexOfScalarPos(u8, ct, lo, ';')) |semi| {
        if (semi < hi) type_end = semi;
    }
    // Trim trailing whitespace before the `;`.
    while (type_end > lo and (ct[type_end - 1] == ' ' or ct[type_end - 1] == '\t')) type_end -= 1;
    const main_type = ct[lo..type_end];

    if (std.ascii.eqlIgnoreCase(main_type, "text/plain")) return .accept;
    return .reject_unsupported;
}

/// G18 — TTL on issued Originals.  The receiver remembers each Original
/// PSBT it has issued a Proposal for, keyed by the SHA-256 of the
/// Original's raw bytes, for a configurable window (default 24h per
/// BIP-78 §"Implementation Suggestions").  Re-submission of the same
/// Original within the window is short-circuited by the replay-dedup
/// path (G30); after the window expires the entry is GC'd so a hostile
/// sender cannot grow the cache unboundedly.
///
/// Wire-side, this is purely a receiver-internal concept (no header or
/// query parameter).  The struct is exposed at module level so the
/// audit gate `@hasDecl(rpc_mod, "PayjoinSessionTtl")` flips green; the
/// backing store lives on the RpcServer as `payjoin_sessions`.
///
/// Sentinel `seconds == 0` disables the cache entirely (test escape
/// hatch + matches Bitcoin Core's idiom of zero meaning "feature off").
pub const PayjoinSessionTtl = struct {
    /// TTL in seconds.  Default 24h matches BIP-78 §"Implementation
    /// Suggestions" ("for at least 24 hours").
    seconds: i64 = 24 * 60 * 60,

    /// Returns true when `created_at_unix + self.seconds < now_unix`,
    /// i.e. the entry has aged past the TTL window.  `seconds == 0`
    /// always returns true (cache disabled — every entry is treated
    /// as expired so the dedup path is a no-op).
    pub fn isExpired(self: PayjoinSessionTtl, created_at_unix: i64, now_unix: i64) bool {
        if (self.seconds == 0) return true;
        return now_unix > created_at_unix + self.seconds;
    }

    /// Sentinel constructor for the test escape hatch.
    pub fn disabled() PayjoinSessionTtl {
        return .{ .seconds = 0 };
    }
};

/// G18 + G30 — internal backing store for the TTL + replay caches.  Keyed
/// by SHA-256(original_psbt_bytes).  Entries map to the Proposal PSBT
/// the receiver returned on the first POST so a replay short-circuits
/// to the SAME proposal (BIP-78 §"Implementation Suggestions" — never
/// run selection twice on the same Original).
///
/// Not on the audit-flip surface (the W119 integrity gate asserts
/// `!@hasDecl(rpc_mod, "PayjoinReplayCache")` and
/// `!@hasDecl(rpc_mod, "PayjoinRequestCache")`).  Operators interact
/// with this through `PayjoinSessionTtl` + `payjoinReplayDedup` — those
/// are the named decls.
const PayjoinReplayEntry = struct {
    /// Owned base64 Proposal (allocator = RpcServer.allocator).
    proposal_b64: []u8,
    /// Unix timestamp when this entry was first inserted.
    created_at: i64,
};

const PayjoinReplayMap = std.AutoHashMap([32]u8, PayjoinReplayEntry);

/// G30 — replay-dedup primitive.  Pure function over a `PayjoinReplayMap`
/// and an Original PSBT body: returns the previously-issued Proposal if
/// the Original has been seen within the TTL window, or `null` to
/// signal the caller should run selection fresh and insert the result.
///
/// Caller invariant: when this returns `null`, the caller MUST call
/// `payjoinReplayInsert` with the resulting Proposal before sending it
/// to the sender — otherwise concurrent identical POSTs will run
/// selection twice (the leak this gate is meant to prevent).
///
/// `now_unix == 0` is treated as "no time available" and disables the
/// TTL check (every entry is considered fresh).  Production callers
/// pass `std.time.timestamp()`; tests pass a fixed value.
pub fn payjoinReplayDedup(
    cache: *const PayjoinReplayMap,
    ttl: PayjoinSessionTtl,
    original_body: []const u8,
    now_unix: i64,
) ?[]const u8 {
    var hash: [32]u8 = undefined;
    std.crypto.hash.sha2.Sha256.hash(original_body, &hash, .{});
    const entry = cache.get(hash) orelse return null;
    if (now_unix != 0 and ttl.isExpired(entry.created_at, now_unix)) return null;
    return entry.proposal_b64;
}

/// Module-level alias for `RpcServer.handleGetPayjoinRequest`.  The W119/G26
/// audit gate asserts `@hasDecl(rpc_mod, "handleGetPayjoinRequest")` — i.e.
/// the rpc namespace, not the RpcServer struct — so we re-export the method
/// here.
///
/// Mints a PayJoin URI (BIP-21 with `pj=` extension) for the receiver
/// wallet.  Returns a JSON-RPC result of the form
/// `{"uri":"bitcoin:<addr>?amount=<btc>&pj=<url>"}`.
pub fn handleGetPayjoinRequest(
    server: *RpcServer,
    params: std.json.Value,
    id: ?std.json.Value,
) ![]const u8 {
    return server.handleGetPayjoinRequest(params, id);
}

/// Module-level alias for `RpcServer.handleSendPayjoinRequest` (W119/G27).
///
/// Drives the full sender flow: build/parse an Original PSBT, POST it to
/// the receiver endpoint, validate the Proposal (G10-G15), and return the
/// signed-ready Proposal PSBT (or the Original on G22 fallback).
pub fn handleSendPayjoinRequest(
    server: *RpcServer,
    params: std.json.Value,
    id: ?std.json.Value,
) ![]const u8 {
    return server.handleSendPayjoinRequest(params, id);
}

/// JSON-RPC server over HTTP.
pub const RpcServer = struct {
    listener: ?std.net.Server,
    allocator: std.mem.Allocator,
    chain_state: *storage.ChainState,
    mempool: *mempool_mod.Mempool,
    peer_manager: *peer_mod.PeerManager,
    network_params: *const consensus.NetworkParams,
    wallet: ?*wallet_mod.Wallet,
    wallet_manager: ?*wallet_mod.WalletManager,
    chain_manager: ?*validation.ChainManager,
    config: RpcConfig,
    running: std.atomic.Value(bool),

    // Per-request state (for wallet targeting)
    current_wallet: ?*wallet_mod.Wallet = null,
    /// Unix timestamp (seconds) when this server was created; used by `uptime`.
    start_time: i64 = 0,
    /// W119/G27 + FIX-66: operator-supplied PayJoin receiver endpoint URL.
    /// Set via `--payjoin-server-url=<http://...>` and consumed by the
    /// `sendpayjoinrequest` + `getpayjoinrequest` RPC handlers.  Plain
    /// HTTP only on this build — see the `PayjoinSender` block for the
    /// TLS-client deferral rationale.
    payjoin_endpoint: ?[]const u8 = null,

    /// W119/G18 + G30 — FIX-67: receiver-side replay + TTL store.  Keyed
    /// by SHA-256(original_psbt_bytes), holds the previously-issued
    /// Proposal so a re-POST short-circuits to the same proposal (no
    /// second selection pass — anti-fingerprint).  Lazy-initialised on
    /// first PayJoin POST; lives on the server allocator.  See the
    /// `PayjoinSessionTtl` block comment in this file for the spec
    /// reference + smart-deferral rationale.
    payjoin_sessions: ?PayjoinReplayMap = null,
    /// W119/G18 — FIX-67: configured TTL window.  Default 24h per
    /// BIP-78 §"Implementation Suggestions".  Operator can override via
    /// future CLI flag `--payjoin-session-ttl=<seconds>` (not yet
    /// wired — placeholder default for now, matches Core's idiom of
    /// "sensible default first, knob later").
    payjoin_session_ttl: PayjoinSessionTtl = .{},

    /// FIX-80 — IBD sticky-OFF latch.  Mirrors Bitcoin Core's
    /// `m_cached_is_ibd` (validation.cpp).  Once IBD has been observed
    /// to be `false` (chainwork >= min_chain_work AND tip wallclock age
    /// < max_tip_age), latches forever in this run — never flips back
    /// to `true` even if natural lag pushes the tip wallclock age over
    /// the 24h threshold.  Without this latch, `initialblockdownload`
    /// flapped back to true when the node fell briefly behind, which
    /// the daily consensus-diff flagged on 2026-05-16 against Core.
    /// Atomic so the read-only-shaped `*const RpcServer` callers from
    /// future code paths don't have to re-thread mutability.
    ibd_latched_off: std.atomic.Value(bool) = std.atomic.Value(bool).init(false),

    /// Initialize the RPC server.
    pub fn init(
        allocator: std.mem.Allocator,
        chain_state: *storage.ChainState,
        mempool: *mempool_mod.Mempool,
        peer_manager: *peer_mod.PeerManager,
        network_params: *const consensus.NetworkParams,
        config: RpcConfig,
    ) RpcServer {
        return RpcServer{
            .listener = null,
            .allocator = allocator,
            .chain_state = chain_state,
            .mempool = mempool,
            .peer_manager = peer_manager,
            .network_params = network_params,
            .wallet = null,
            .wallet_manager = null,
            .chain_manager = null,
            .config = config,
            .running = std.atomic.Value(bool).init(false),
            .current_wallet = null,
            .start_time = std.time.timestamp(),
        };
    }

    /// Initialize the RPC server with a wallet.
    pub fn initWithWallet(
        allocator: std.mem.Allocator,
        chain_state: *storage.ChainState,
        mempool: *mempool_mod.Mempool,
        peer_manager: *peer_mod.PeerManager,
        network_params: *const consensus.NetworkParams,
        wallet: *wallet_mod.Wallet,
        config: RpcConfig,
    ) RpcServer {
        return RpcServer{
            .listener = null,
            .allocator = allocator,
            .chain_state = chain_state,
            .mempool = mempool,
            .peer_manager = peer_manager,
            .network_params = network_params,
            .wallet = wallet,
            .wallet_manager = null,
            .chain_manager = null,
            .config = config,
            .running = std.atomic.Value(bool).init(false),
            .current_wallet = null,
            .start_time = std.time.timestamp(),
        };
    }

    /// Initialize the RPC server with a wallet manager (multi-wallet).
    pub fn initWithWalletManager(
        allocator: std.mem.Allocator,
        chain_state: *storage.ChainState,
        mempool: *mempool_mod.Mempool,
        peer_manager: *peer_mod.PeerManager,
        network_params: *const consensus.NetworkParams,
        wallet_manager: *wallet_mod.WalletManager,
        config: RpcConfig,
    ) RpcServer {
        return RpcServer{
            .listener = null,
            .allocator = allocator,
            .chain_state = chain_state,
            .mempool = mempool,
            .peer_manager = peer_manager,
            .network_params = network_params,
            .wallet = null,
            .wallet_manager = wallet_manager,
            .chain_manager = null,
            .config = config,
            .running = std.atomic.Value(bool).init(false),
            .current_wallet = null,
            .start_time = std.time.timestamp(),
        };
    }

    /// Set the chain manager for invalidateblock/reconsiderblock/preciousblock RPCs.
    pub fn setChainManager(self: *RpcServer, chain_manager: *validation.ChainManager) void {
        self.chain_manager = chain_manager;
    }

    /// Set the wallet manager for multi-wallet support.
    pub fn setWalletManager(self: *RpcServer, wallet_manager: *wallet_mod.WalletManager) void {
        self.wallet_manager = wallet_manager;
    }

    /// W119/G27 + FIX-66: set the PayJoin receiver endpoint URL.
    /// Borrowed slice; the caller MUST keep it alive for the lifetime of
    /// the server.
    pub fn setPayjoinEndpoint(self: *RpcServer, url: ?[]const u8) void {
        self.payjoin_endpoint = url;
    }

    /// Start listening for connections.
    ///
    /// Validates the TLS config (see `validateTlsConfig`) before bind so an
    /// operator who supplies `--rpc-tls-cert` / `--rpc-tls-key` on a build
    /// without server-side TLS gets a clear startup error instead of a
    /// silent plain-HTTP downgrade (W119 + FIX-64 deferral).
    pub fn start(self: *RpcServer) !void {
        try validateTlsConfig(self.config);
        const addr = try std.net.Address.parseIp(self.config.bind_address, self.config.port);
        self.listener = try addr.listen(.{
            .reuse_address = true,
        });
        self.running.store(true, .release);
    }

    /// Deinitialize the server. stop() already closes the listener, but
    /// guard here in case deinit is called without a prior stop().
    pub fn deinit(self: *RpcServer) void {
        self.stop();
        // FIX-67 (W119/G18+G30) — free the PayJoin replay map's owned
        // proposal strings before dropping the map itself.  The map is
        // lazy-init'd on first POST so this branch is a no-op when no
        // PayJoin request ever arrived.
        if (self.payjoin_sessions) |*sess| {
            var it = sess.iterator();
            while (it.next()) |kv| {
                self.allocator.free(kv.value_ptr.proposal_b64);
            }
            sess.deinit();
            self.payjoin_sessions = null;
        }
    }

    /// FIX-67 (W119/G18 + G30) — lazy-init the receiver-side replay/TTL
    /// store.  Returns a pointer to the live `PayjoinReplayMap` for use
    /// by `handlePayjoinRequest`.  Stamped here (not in the constructor)
    /// because every other code path may run on a node that never
    /// receives a PayJoin POST — keeping the allocation off the hot
    /// init path matters when 9 of 10 nodes never serve receivers.
    fn payjoinSessionsEnsure(self: *RpcServer) *PayjoinReplayMap {
        if (self.payjoin_sessions == null) {
            self.payjoin_sessions = PayjoinReplayMap.init(self.allocator);
        }
        return &self.payjoin_sessions.?;
    }

    /// FIX-67 (W119/G18) — sweep expired entries from the replay store.
    /// Called by `handlePayjoinRequest` after each successful insert so
    /// the cache cannot grow unbounded under sustained traffic.  GC cost
    /// is O(n) in the entry count, amortised across each post-insert
    /// sweep.  Cheap enough for the cache sizes we expect (~hundreds of
    /// entries at most over a 24h TTL window).
    fn payjoinSessionsGc(self: *RpcServer, now_unix: i64) void {
        const sess = self.payjoin_sessions orelse return;
        _ = sess;
        const ttl = self.payjoin_session_ttl;
        if (ttl.seconds == 0) return;
        var stale = std.ArrayList([32]u8).init(self.allocator);
        defer stale.deinit();
        {
            var it = self.payjoin_sessions.?.iterator();
            while (it.next()) |kv| {
                if (ttl.isExpired(kv.value_ptr.created_at, now_unix)) {
                    stale.append(kv.key_ptr.*) catch return; // OOM → skip GC
                }
            }
        }
        for (stale.items) |key| {
            if (self.payjoin_sessions.?.fetchRemove(key)) |kv| {
                self.allocator.free(kv.value.proposal_b64);
            }
        }
    }

    /// Stop the server.
    ///
    /// Sets running=false and unblocks any thread currently sitting in
    /// accept() by opening and immediately closing a TCP connection to
    /// our own listener. Without this an idle RPC thread would hang the
    /// shutdown sequence until a new client request arrived.
    ///
    /// We do not deinit the listener here because another thread may
    /// still be mid-accept(); the deferred deinit at startup handles
    /// teardown after run() returns. Safe to call multiple times.
    pub fn stop(self: *RpcServer) void {
        if (!self.running.swap(false, .acq_rel)) return;
        // Unblock any in-flight accept() by shutting down the listen socket.
        // shutdown(SHUT_RDWR) on a listening socket on Linux causes accept()
        // to return EINVAL immediately — the run() loop checks running and
        // returns cleanly. Without this, accept() would keep sleeping until
        // a client connection arrives.
        //
        // We also issue a throw-away self-connect as belt-and-suspenders,
        // since shutdown() on a listening socket is Linux-specific.
        if (self.listener) |l| {
            std.posix.shutdown(l.stream.handle, .both) catch {};
        }
        const addr = std.net.Address.parseIp(self.config.bind_address, self.config.port) catch return;
        const sock = std.posix.socket(
            addr.any.family,
            std.posix.SOCK.STREAM | std.posix.SOCK.CLOEXEC,
            std.posix.IPPROTO.TCP,
        ) catch return;
        defer std.posix.close(sock);
        const timeout = std.posix.timeval{ .tv_sec = 1, .tv_usec = 0 };
        std.posix.setsockopt(sock, std.posix.SOL.SOCKET, std.posix.SO.SNDTIMEO, std.mem.asBytes(&timeout)) catch {};
        std.posix.connect(sock, &addr.any, addr.getOsSockLen()) catch {};
    }

    /// Main server loop - accept and handle connections.
    ///
    /// Exits when running is set to false. stop() opens a throw-away
    /// connection to our own listener to unblock any in-flight accept();
    /// we check running on every iteration (including after accept
    /// returns) so shutdown is prompt.
    pub fn run(self: *RpcServer) !void {
        while (self.running.load(.acquire)) {
            const listener = &(self.listener orelse return);
            const conn = listener.accept() catch |err| {
                if (!self.running.load(.acquire)) return;
                switch (err) {
                    error.WouldBlock => continue,
                    error.ConnectionAborted => continue,
                    // accept returns EINVAL after shutdown(SHUT_RDWR) on
                    // the listening socket — that is our graceful signal
                    // to exit. Zig maps this to error.SocketNotListening.
                    error.SocketNotListening => return,
                    else => return err,
                }
            };
            // A wake-up connection from stop() looks like any other
            // accepted socket. Check the flag and bail before spending
            // time in handleConnection.
            if (!self.running.load(.acquire)) {
                conn.stream.close();
                return;
            }
            self.handleConnection(conn) catch {};
        }
    }

    /// Handle a single HTTP connection.
    fn handleConnection(self: *RpcServer, conn: std.net.Server.Connection) !void {
        defer conn.stream.close();

        // Read HTTP request
        var buf: [65536]u8 = undefined;
        var total_read: usize = 0;

        // Read until we have the full headers
        while (total_read < buf.len) {
            const n = conn.stream.read(buf[total_read..]) catch return;
            if (n == 0) return;
            total_read += n;

            // Check for end of headers
            if (std.mem.indexOf(u8, buf[0..total_read], "\r\n\r\n")) |_| break;
        }

        // Parse HTTP request
        const request_data = buf[0..total_read];

        // Find headers end
        const headers_end = std.mem.indexOf(u8, request_data, "\r\n\r\n") orelse return;
        const headers = request_data[0..headers_end];

        // Parse HTTP method and URL path from request line
        const request_line_end = std.mem.indexOf(u8, headers, "\r\n") orelse headers.len;
        const request_line = headers[0..request_line_end];

        // Extract method
        const is_get = std.mem.startsWith(u8, request_line, "GET ");
        const is_post = std.mem.startsWith(u8, request_line, "POST ");

        // Extract path from request line
        var url_path: []const u8 = "/";
        if (std.mem.indexOf(u8, request_line, " ")) |path_start| {
            const path_content = request_line[path_start + 1 ..];
            if (std.mem.indexOf(u8, path_content, " ")) |path_end| {
                url_path = path_content[0..path_end];
            }
        }

        // Handle REST API requests (GET /rest/...)
        if (is_get and std.mem.startsWith(u8, url_path, "/rest/")) {
            self.handleRestRequest(conn.stream, url_path) catch {
                try self.sendHttpError(conn.stream, 500, "Internal Server Error");
            };
            return;
        }

        // Handle BIP-78 PayJoin (POST /payjoin?v=1&...).  FIX-65 ships the
        // receiver-side foundation on plain HTTP.  BIP-78 §"Receiver's
        // transport security" requires HTTPS or .onion in production; FIX-64
        // deferred server-side TLS (Zig 0.13 stdlib has no Server.zig) and
        // a Tor Hidden Service publisher is also a future step.  Operators
        // MUST front this route with nginx / Tor / Caddy before exposing
        // the endpoint publicly.  This matches Bitcoin Core's own
        // operational model (Core has no native TLS for its HTTP server;
        // operators terminate elsewhere).
        if (is_post and std.mem.startsWith(u8, url_path, "/payjoin")) {
            self.handlePayjoinRequest(conn.stream, url_path, headers, request_data, headers_end, total_read) catch {
                // Fallback: emit a BIP-78 "unavailable" JSON error so the
                // sender's anti-snoop loop falls back to broadcasting the
                // Original PSBT.  We deliberately do NOT leak the internal
                // error name (privacy: receiver's allocator/IO state is
                // not the sender's business).
                self.sendPayjoinErrorRaw(conn.stream, PAYJOIN_ERR_UNAVAILABLE, "Receiver unavailable") catch {};
            };
            return;
        }

        // For non-REST requests, require POST method
        if (!is_post) {
            try self.sendHttpError(conn.stream, 405, "Method Not Allowed");
            return;
        }

        // Set target wallet based on URL path
        self.current_wallet = null;
        if (self.wallet_manager) |wm| {
            self.current_wallet = wm.getTargetWallet(url_path) catch |err| blk: {
                if (err == error.WalletNotFound) {
                    const error_response = self.jsonRpcError(
                        RPC_WALLET_NOT_FOUND,
                        "Requested wallet does not exist or is not loaded",
                        null,
                    ) catch return;
                    defer self.allocator.free(error_response);
                    try self.sendHttpResponse(conn.stream, 200, error_response);
                    return;
                } else {
                    // WalletNotSpecified or other - continue and let individual handlers decide
                    break :blk null;
                }
            };
        } else if (self.wallet) |w| {
            // Single wallet mode (backwards compatible)
            self.current_wallet = w;
        }

        // Check authentication if configured (accepts either rpcuser/rpcpassword or cookie token)
        if (self.config.auth_token != null or self.config.cookie_token != null) {
            const auth_header = findHeader(headers, "Authorization") orelse {
                try self.sendHttpError(conn.stream, 401, "Unauthorized");
                return;
            };
            if (!std.mem.startsWith(u8, auth_header, "Basic ")) {
                try self.sendHttpError(conn.stream, 401, "Unauthorized");
                return;
            }
            const provided = auth_header[6..];
            const user_pass_match = if (self.config.auth_token) |t| std.mem.eql(u8, provided, t) else false;
            const cookie_match = if (self.config.cookie_token) |t| std.mem.eql(u8, provided, t) else false;
            if (!user_pass_match and !cookie_match) {
                try self.sendHttpError(conn.stream, 401, "Unauthorized");
                return;
            }
        }

        // Get Content-Length
        const content_length_str = findHeader(headers, "Content-Length") orelse {
            try self.sendHttpError(conn.stream, 400, "Bad Request: Missing Content-Length");
            return;
        };
        const content_length = std.fmt.parseInt(usize, content_length_str, 10) catch {
            try self.sendHttpError(conn.stream, 400, "Bad Request: Invalid Content-Length");
            return;
        };

        if (content_length > self.config.max_request_size) {
            try self.sendHttpError(conn.stream, 413, "Request Entity Too Large");
            return;
        }

        // Read body
        const body_start = headers_end + 4;
        var body: []u8 = undefined;
        var body_allocated = false;

        if (body_start + content_length <= total_read) {
            // Already have full body in stack buffer
            body = @constCast(request_data[body_start .. body_start + content_length]);
        } else {
            // Need to read more — allocate a buffer for the full body
            const body_buf = self.allocator.alloc(u8, content_length) catch {
                try self.sendHttpError(conn.stream, 500, "Internal Server Error");
                return;
            };
            body_allocated = true;

            @memcpy(body_buf[0 .. total_read - body_start], request_data[body_start..total_read]);
            var offset = total_read - body_start;
            while (offset < content_length) {
                const n = conn.stream.read(body_buf[offset..]) catch {
                    self.allocator.free(body_buf);
                    return;
                };
                if (n == 0) {
                    self.allocator.free(body_buf);
                    return;
                }
                offset += n;
            }
            body = body_buf;
        }
        defer if (body_allocated) self.allocator.free(body);

        // Process JSON-RPC request
        const response = self.dispatch(body) catch |err| {
            const error_response = self.jsonRpcError(
                RPC_INTERNAL_ERROR,
                @errorName(err),
                null,
            ) catch return;
            defer self.allocator.free(error_response);
            try self.sendHttpResponse(conn.stream, 200, error_response);
            return;
        };
        defer self.allocator.free(response);

        try self.sendHttpResponse(conn.stream, 200, response);
    }

    /// Send an HTTP error response.
    fn sendHttpError(self: *RpcServer, stream: std.net.Stream, status: u16, message: []const u8) !void {
        _ = self;
        var response_buf: [256]u8 = undefined;
        const response = std.fmt.bufPrint(&response_buf, "HTTP/1.1 {d} {s}\r\nContent-Length: 0\r\nConnection: close\r\n\r\n", .{ status, message }) catch return;
        stream.writeAll(response) catch {};
    }

    /// Send an HTTP response with JSON body.
    fn sendHttpResponse(self: *RpcServer, stream: std.net.Stream, status: u16, body: []const u8) !void {
        _ = self;
        var header_buf: [256]u8 = undefined;
        const header = std.fmt.bufPrint(&header_buf, "HTTP/1.1 {d} OK\r\nContent-Type: application/json\r\nContent-Length: {d}\r\nConnection: close\r\n\r\n", .{ status, body.len }) catch return;
        stream.writeAll(header) catch {};
        stream.writeAll(body) catch {};
    }

    /// Send an HTTP response with custom content type.
    fn sendRestResponse(self: *RpcServer, stream: std.net.Stream, status: u16, content_type: []const u8, body: []const u8) !void {
        _ = self;
        var header_buf: [512]u8 = undefined;
        const status_text = switch (status) {
            200 => "OK",
            400 => "Bad Request",
            404 => "Not Found",
            else => "Error",
        };
        const header = std.fmt.bufPrint(&header_buf, "HTTP/1.1 {d} {s}\r\nContent-Type: {s}\r\nContent-Length: {d}\r\nConnection: close\r\n\r\n", .{ status, status_text, content_type, body.len }) catch return;
        stream.writeAll(header) catch {};
        stream.writeAll(body) catch {};
    }

    // ========================================================================
    // REST API (Bitcoin Core compatible)
    // ========================================================================

    /// REST response format derived from file extension.
    const RestFormat = enum {
        json,
        hex,
        bin,
    };

    /// Parse the format extension from a REST path segment.
    /// Returns the path without extension and the format, or null if invalid.
    fn parseRestFormat(segment: []const u8) ?struct { path: []const u8, format: RestFormat } {
        if (std.mem.endsWith(u8, segment, ".json")) {
            return .{ .path = segment[0 .. segment.len - 5], .format = .json };
        } else if (std.mem.endsWith(u8, segment, ".hex")) {
            return .{ .path = segment[0 .. segment.len - 4], .format = .hex };
        } else if (std.mem.endsWith(u8, segment, ".bin")) {
            return .{ .path = segment[0 .. segment.len - 4], .format = .bin };
        }
        return null;
    }

    /// Content-Type string for a REST format.
    fn restContentType(format: RestFormat) []const u8 {
        return switch (format) {
            .json => "application/json",
            .hex => "text/plain",
            .bin => "application/octet-stream",
        };
    }

    /// Handle a REST API request (GET /rest/...).
    /// Dispatches to the appropriate handler based on the URL path.
    ///
    /// Implemented endpoints (Bitcoin Core parity, ref `bitcoin-core/src/rest.cpp`):
    ///   - /rest/chaininfo.json
    ///   - /rest/mempool/info.json
    ///   - /rest/mempool/contents.json
    ///   - /rest/block/<hash>.{bin,hex,json}
    ///   - /rest/block/notxdetails/<hash>.{bin,hex,json}
    ///   - /rest/tx/<txid>.{bin,hex,json}
    ///   - /rest/headers/<count>/<hash>.{bin,hex,json}
    ///   - /rest/blockhashbyheight/<height>.{bin,hex,json}
    ///   - /rest/getutxos[/checkmempool]/<txid>-<n>[/<txid>-<n>...].{bin,hex,json}
    ///   - /rest/blockfilter/<filtertype>/<hash>.{bin,hex,json}
    ///   - /rest/blockfilterheaders/<filtertype>/<count>/<hash>.{bin,hex,json}
    fn handleRestRequest(self: *RpcServer, stream: std.net.Stream, url_path: []const u8) !void {
        // Strip the "/rest/" prefix and any trailing query string (e.g. "?count=5").
        // Core's ParseDataFormat strips after the rfind('?'), so we mirror that.
        var rest_path = url_path[6..]; // skip "/rest/"
        if (std.mem.indexOfScalar(u8, rest_path, '?')) |q| {
            rest_path = rest_path[0..q];
        }

        // ---------------------------------------------------------------
        // /rest/block/notxdetails/<hash>.{bin,hex,json}
        //
        // Must come BEFORE the /rest/block/ check so the longer prefix wins.
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "block/notxdetails/")) {
            const remainder = rest_path["block/notxdetails/".len..];
            try self.restBlock(stream, remainder, .notxdetails);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/block/<hash>.{bin,hex,json}
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "block/")) {
            const remainder = rest_path["block/".len..];
            try self.restBlock(stream, remainder, .with_tx);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/blockfilter/<filtertype>/<hash>.{bin,hex,json}
        //
        // Longer prefix first.
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "blockfilterheaders/")) {
            const remainder = rest_path["blockfilterheaders/".len..];
            try self.restBlockFilterHeaders(stream, remainder);
            return;
        }
        if (std.mem.startsWith(u8, rest_path, "blockfilter/")) {
            const remainder = rest_path["blockfilter/".len..];
            try self.restBlockFilter(stream, remainder);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/blockhashbyheight/<height>.{bin,hex,json}
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "blockhashbyheight/")) {
            const remainder = rest_path["blockhashbyheight/".len..];
            try self.restBlockHashByHeight(stream, remainder);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/chaininfo.json (JSON only — Core parity, rest.cpp:716)
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "chaininfo")) {
            const parsed = parseRestFormat(rest_path["chaininfo".len..]) orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "output format not found (available: json)");
                return;
            };
            if (parsed.format != .json or parsed.path.len != 0) {
                try self.sendRestResponse(stream, 404, "text/plain", "output format not found (available: json)");
                return;
            }
            const result = try self.handleGetBlockchainInfo(null);
            defer self.allocator.free(result);
            const rest_body = extractJsonResult(result) orelse result;
            try self.sendRestResponse(stream, 200, "application/json", rest_body);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/getutxos[/checkmempool]/<txid>-<n>[/<txid>-<n>...].{bin,hex,json}
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "getutxos")) {
            // Trailing portion after "getutxos" — may be "/<...>.<ext>" or
            // ".<ext>" alone (no outpoints, which Core treats as empty-request
            // 400 unless raw POST body is supplied; we accept GET only and
            // return 400 for empty).
            const remainder = rest_path["getutxos".len..];
            try self.restGetUtxos(stream, remainder);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/mempool/info.json
        // /rest/mempool/contents.json[?verbose=true]
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "mempool/info")) {
            const suffix = rest_path["mempool/info".len..];
            const parsed = parseRestFormat(suffix) orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "output format not found (available: json)");
                return;
            };
            if (parsed.format != .json or parsed.path.len != 0) {
                try self.sendRestResponse(stream, 404, "text/plain", "output format not found (available: json)");
                return;
            }
            const result = try self.handleGetMempoolInfo(null);
            defer self.allocator.free(result);
            const rest_body = extractJsonResult(result) orelse result;
            try self.sendRestResponse(stream, 200, "application/json", rest_body);
            return;
        }
        if (std.mem.startsWith(u8, rest_path, "mempool/contents")) {
            const suffix = rest_path["mempool/contents".len..];
            const parsed = parseRestFormat(suffix) orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "output format not found (available: json)");
                return;
            };
            if (parsed.format != .json or parsed.path.len != 0) {
                try self.sendRestResponse(stream, 404, "text/plain", "output format not found (available: json)");
                return;
            }
            // Re-use getrawmempool dispatch with verbose=false — Core's REST
            // mempool/contents accepts ?verbose=true via the query string,
            // which we strip above; emit the non-verbose array form (txids).
            // Verbose support can be added by re-parsing the query later.
            var params = std.json.Array.init(self.allocator);
            defer params.deinit();
            const result = try self.handleGetRawMempool(.{ .array = params }, null);
            defer self.allocator.free(result);
            const rest_body = extractJsonResult(result) orelse result;
            try self.sendRestResponse(stream, 200, "application/json", rest_body);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/tx/<txid>.{bin,hex,json}
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "tx/")) {
            const remainder = rest_path["tx/".len..];
            try self.restTx(stream, remainder);
            return;
        }

        // ---------------------------------------------------------------
        // /rest/headers/<count>/<hash>.{bin,hex,json}
        // ---------------------------------------------------------------
        if (std.mem.startsWith(u8, rest_path, "headers/")) {
            const remainder = rest_path["headers/".len..];
            try self.restHeaders(stream, remainder);
            return;
        }

        // Unknown REST endpoint
        try self.sendRestResponse(stream, 404, "text/plain", "REST endpoint not found");
    }

    // ========================================================================
    // REST endpoint implementations
    // ========================================================================

    /// Block detail variant: full tx detail vs txid-only ("notxdetails").
    /// Mirrors Core's `rest_block_extended` vs `rest_block_notxdetails`.
    const BlockDetailMode = enum { with_tx, notxdetails };

    /// /rest/block[/notxdetails]/<hash>.{bin,hex,json}
    ///
    /// `.bin` returns the raw block bytes from CF_BLOCKS verbatim.
    /// `.hex` returns the hex string of the same.
    /// `.json` returns the verbosity=1 (with_tx) or notxdetails-equivalent
    /// JSON projection of `getblock`. The notxdetails JSON form omits the
    /// per-tx detail array and only ships the txid list (Core
    /// TxVerbosity::SHOW_TXID).
    fn restBlock(
        self: *RpcServer,
        stream: std.net.Stream,
        remainder: []const u8,
        mode: BlockDetailMode,
    ) !void {
        const parsed = parseRestFormat(remainder) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        const hash_hex = parsed.path;
        if (hash_hex.len != 64) {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash: must be 64 hex characters");
            return;
        }

        // Parse big-endian display hash → 32-byte little-endian internal hash.
        var blockhash: types.Hash256 = undefined;
        for (0..32) |i| {
            const high = std.fmt.charToDigit(hash_hex[i * 2], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            const low = std.fmt.charToDigit(hash_hex[i * 2 + 1], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            blockhash[31 - i] = (high << 4) | low;
        }

        switch (parsed.format) {
            .bin, .hex => {
                // Raw block bytes from CF_BLOCKS.
                const db = self.chain_state.utxo_set.db orelse {
                    try self.sendRestResponse(stream, 404, "text/plain", "Block body not available");
                    return;
                };
                const raw = (db.get(storage.CF_BLOCKS, &blockhash) catch null) orelse {
                    try self.sendRestResponse(stream, 404, "text/plain", "Block not found");
                    return;
                };
                defer self.allocator.free(raw);

                if (parsed.format == .bin) {
                    try self.sendRestResponse(stream, 200, "application/octet-stream", raw);
                } else {
                    var buf = std.ArrayList(u8).init(self.allocator);
                    defer buf.deinit();
                    const writer = buf.writer();
                    for (raw) |byte| try writer.print("{x:0>2}", .{byte});
                    try writer.writeByte('\n');
                    try self.sendRestResponse(stream, 200, "text/plain", buf.items);
                }
                return;
            },
            .json => {
                // Dispatch verbosity=1 getblock and either re-emit (with_tx)
                // or strip the tx-detail array (notxdetails). Our verbosity=1
                // form already only lists txids in the "tx" array (line ~1465),
                // so notxdetails is effectively the same JSON for now —
                // documented divergence from Core: Core's notxdetails omits
                // size/weight per-tx and getblock verbosity 2 emits them; we
                // never emit per-tx objects in verbosity 1, so the two are
                // identical until verbosity 2 lands.
                _ = mode;
                var params_buf: [256]u8 = undefined;
                const params_json = std.fmt.bufPrint(
                    &params_buf,
                    "{{\"jsonrpc\":\"1.0\",\"id\":null,\"method\":\"getblock\",\"params\":[\"{s}\",1]}}",
                    .{hash_hex},
                ) catch {
                    try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
                    return;
                };
                const result = self.dispatch(params_json) catch {
                    try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
                    return;
                };
                defer self.allocator.free(result);
                const rest_body = extractJsonResult(result) orelse result;
                if (std.mem.indexOf(u8, result, "\"error\":null") == null) {
                    try self.sendRestResponse(stream, 404, "application/json", rest_body);
                } else {
                    try self.sendRestResponse(stream, 200, "application/json", rest_body);
                }
                return;
            },
        }
    }

    /// /rest/tx/<txid>.{bin,hex,json}
    fn restTx(self: *RpcServer, stream: std.net.Stream, remainder: []const u8) !void {
        const parsed = parseRestFormat(remainder) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        const txid_hex = parsed.path;
        if (txid_hex.len != 64) {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid txid: must be 64 hex characters");
            return;
        }

        // For .bin / .hex, ask getrawtransaction with verbose=false → hex
        // string. For .json, verbose=true.
        const verbose_bool: u8 = if (parsed.format == .json) 1 else 0;

        var params_buf: [256]u8 = undefined;
        const params_json = std.fmt.bufPrint(
            &params_buf,
            "{{\"jsonrpc\":\"1.0\",\"id\":null,\"method\":\"getrawtransaction\",\"params\":[\"{s}\",{d}]}}",
            .{ txid_hex, verbose_bool },
        ) catch {
            try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
            return;
        };
        const result = self.dispatch(params_json) catch {
            try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
            return;
        };
        defer self.allocator.free(result);

        if (std.mem.indexOf(u8, result, "\"error\":null") == null) {
            const rest_body = extractJsonResult(result) orelse result;
            try self.sendRestResponse(stream, 404, "application/json", rest_body);
            return;
        }

        switch (parsed.format) {
            .json => {
                const rest_body = extractJsonResult(result) orelse result;
                try self.sendRestResponse(stream, 200, "application/json", rest_body);
            },
            .hex => {
                // Result is `"<hex>"`; strip surrounding quotes for text/plain.
                const inner = extractJsonResult(result) orelse result;
                const trimmed = std.mem.trim(u8, inner, "\"");
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                try buf.appendSlice(trimmed);
                try buf.append('\n');
                try self.sendRestResponse(stream, 200, "text/plain", buf.items);
            },
            .bin => {
                // Convert hex → bytes for binary form.
                const inner = extractJsonResult(result) orelse result;
                const trimmed = std.mem.trim(u8, inner, "\"");
                if (trimmed.len % 2 != 0) {
                    try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
                    return;
                }
                const bin = self.allocator.alloc(u8, trimmed.len / 2) catch {
                    try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
                    return;
                };
                defer self.allocator.free(bin);
                for (0..bin.len) |i| {
                    const hi = std.fmt.charToDigit(trimmed[i * 2], 16) catch {
                        try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
                        return;
                    };
                    const lo = std.fmt.charToDigit(trimmed[i * 2 + 1], 16) catch {
                        try self.sendRestResponse(stream, 500, "text/plain", "Internal error");
                        return;
                    };
                    bin[i] = (hi << 4) | lo;
                }
                try self.sendRestResponse(stream, 200, "application/octet-stream", bin);
            },
        }
    }

    /// /rest/headers/<count>/<hash>.{bin,hex,json}
    ///
    /// Walks forward from <hash> along the active chain up to <count>
    /// headers (capped at MAX_REST_HEADERS_RESULTS=2000, Core parity).
    fn restHeaders(self: *RpcServer, stream: std.net.Stream, remainder: []const u8) !void {
        const slash_idx = std.mem.indexOf(u8, remainder, "/") orelse {
            try self.sendRestResponse(
                stream,
                400,
                "text/plain",
                "Invalid path: expected /rest/headers/<count>/<hash>.<ext>",
            );
            return;
        };
        const count_str = remainder[0..slash_idx];
        const hash_with_ext = remainder[slash_idx + 1 ..];
        const parsed = parseRestFormat(hash_with_ext) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        const hash_hex = parsed.path;

        const count_raw = std.fmt.parseInt(u32, count_str, 10) catch {
            try self.sendRestResponse(stream, 400, "text/plain", "Header count is invalid or out of acceptable range (1-2000)");
            return;
        };
        if (count_raw < 1 or count_raw > 2000) {
            try self.sendRestResponse(stream, 400, "text/plain", "Header count is invalid or out of acceptable range (1-2000)");
            return;
        }
        if (hash_hex.len != 64) {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash: must be 64 hex characters");
            return;
        }
        var blockhash: types.Hash256 = undefined;
        for (0..32) |i| {
            const high = std.fmt.charToDigit(hash_hex[i * 2], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            const low = std.fmt.charToDigit(hash_hex[i * 2 + 1], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            blockhash[31 - i] = (high << 4) | low;
        }

        // Walk forward along the active chain from the requested block,
        // collecting up to count headers. Core's rest_headers does this via
        // active_chain.Next(pindex). We approximate by:
        //   1. Locate the start entry via chain_manager.getBlock(hash).
        //   2. Confirm it's an ancestor of active_tip (otherwise: side chain;
        //      Core's loop terminates because Contains() returns false).
        //   3. Walk forward one height at a time using the H:{height}->hash
        //      index on chain_state, falling back to active_tip.parent walks.
        var headers = std.ArrayList(types.BlockHeader).init(self.allocator);
        defer headers.deinit();
        var heights = std.ArrayList(u32).init(self.allocator);
        defer heights.deinit();
        var hashes = std.ArrayList(types.Hash256).init(self.allocator);
        defer hashes.deinit();

        if (self.chain_manager) |cm| {
            const start_entry = cm.getBlock(&blockhash) orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "Block not found");
                return;
            };
            // Verify on active chain: walk back from active_tip until we hit
            // start_entry's height, compare hashes.
            const tip_entry = cm.active_tip orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "No active chain");
                return;
            };
            if (start_entry.height > tip_entry.height) {
                try self.sendRestResponse(stream, 404, "text/plain", "Block not on active chain");
                return;
            }
            const tip_at_start_height = tip_entry.getAncestor(start_entry.height) orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "Block not on active chain");
                return;
            };
            if (!std.mem.eql(u8, &tip_at_start_height.hash, &start_entry.hash)) {
                try self.sendRestResponse(stream, 404, "text/plain", "Block not on active chain");
                return;
            }

            // Walk forward: tip_entry.getAncestor(start.height + i) for i = 0..count-1.
            var emitted: u32 = 0;
            while (emitted < count_raw) : (emitted += 1) {
                const target_h = start_entry.height + emitted;
                if (target_h > tip_entry.height) break;
                const e = tip_entry.getAncestor(target_h) orelse break;
                try headers.append(e.header);
                try heights.append(e.height);
                try hashes.append(e.hash);
            }
        } else {
            // No chain_manager: best-effort. If hash matches genesis or tip,
            // emit single header.
            if (std.mem.eql(u8, &blockhash, &self.network_params.genesis_hash)) {
                try headers.append(self.network_params.genesis_header);
                try heights.append(0);
                try hashes.append(blockhash);
            } else if (std.mem.eql(u8, &blockhash, &self.chain_state.best_hash)) {
                try headers.append(self.network_params.genesis_header); // placeholder
                try heights.append(self.chain_state.best_height);
                try hashes.append(blockhash);
            } else {
                try self.sendRestResponse(stream, 404, "text/plain", "Block not found");
                return;
            }
        }

        // Emit in the requested format.
        switch (parsed.format) {
            .bin => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                for (headers.items) |*h| try writeBlockHeaderBin(buf.writer(), h);
                try self.sendRestResponse(stream, 200, "application/octet-stream", buf.items);
            },
            .hex => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                for (headers.items) |*h| try writeBlockHeaderHex(writer, h);
                try writer.writeByte('\n');
                try self.sendRestResponse(stream, 200, "text/plain", buf.items);
            },
            .json => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                try writer.writeByte('[');
                for (headers.items, heights.items, hashes.items, 0..) |*h, height, *hash, i| {
                    if (i > 0) try writer.writeByte(',');
                    try writer.writeAll("{\"hash\":\"");
                    try writeHashHex(writer, hash);
                    try writer.print("\",\"height\":{d},\"version\":{d},\"versionHex\":\"{x:0>8}\",\"merkleroot\":\"", .{
                        height,
                        h.version,
                        @as(u32, @bitCast(h.version)),
                    });
                    try writeHashHex(writer, &h.merkle_root);
                    try writer.print(
                        "\",\"time\":{d},\"nonce\":{d},\"bits\":\"{x:0>8}\",\"previousblockhash\":\"",
                        .{ h.timestamp, h.nonce, h.bits },
                    );
                    try writeHashHex(writer, &h.prev_block);
                    try writer.writeAll("\"}");
                }
                try writer.writeByte(']');
                try self.sendRestResponse(stream, 200, "application/json", buf.items);
            },
        }
    }

    /// /rest/blockhashbyheight/<height>.{bin,hex,json}
    fn restBlockHashByHeight(self: *RpcServer, stream: std.net.Stream, remainder: []const u8) !void {
        const parsed = parseRestFormat(remainder) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        const height = std.fmt.parseInt(u32, parsed.path, 10) catch {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid height");
            return;
        };
        if (height > self.chain_state.best_height) {
            try self.sendRestResponse(stream, 404, "text/plain", "Block height out of range");
            return;
        }

        var hash: types.Hash256 = undefined;
        if (height == 0) {
            hash = self.network_params.genesis_hash;
        } else if (self.chain_state.getBlockHashByHeight(height)) |h| {
            hash = h;
        } else if (self.chain_manager) |cm| {
            const tip = cm.active_tip orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "No active chain");
                return;
            };
            const e = tip.getAncestor(height) orelse {
                try self.sendRestResponse(stream, 404, "text/plain", "Block height out of range");
                return;
            };
            hash = e.hash;
        } else if (height == self.chain_state.best_height) {
            hash = self.chain_state.best_hash;
        } else {
            try self.sendRestResponse(stream, 404, "text/plain", "Block height out of range");
            return;
        }

        switch (parsed.format) {
            .bin => {
                // Core writes the 32-byte hash in internal little-endian order.
                try self.sendRestResponse(stream, 200, "application/octet-stream", &hash);
            },
            .hex => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                try writeHashHex(writer, &hash);
                try writer.writeByte('\n');
                try self.sendRestResponse(stream, 200, "text/plain", buf.items);
            },
            .json => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                try buf.appendSlice("{\"blockhash\":\"");
                try writeHashHex(buf.writer(), &hash);
                try buf.appendSlice("\"}");
                try self.sendRestResponse(stream, 200, "application/json", buf.items);
            },
        }
    }

    /// /rest/getutxos[/checkmempool]/<txid>-<n>[/...].{bin,hex,json}
    ///
    /// Implements Core's BIP-64 binary serialization for `.bin`/`.hex` and
    /// the BIP-64 JSON projection for `.json`. Body-encoded outpoint lists
    /// (POST) are not supported — GET-only.
    fn restGetUtxos(self: *RpcServer, stream: std.net.Stream, remainder: []const u8) !void {
        // remainder is e.g. "/checkmempool/aa..bb-0/cc..dd-1.json", or just
        // ".json" if no outpoints were given.
        const parsed = parseRestFormat(remainder) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        // Strip leading '/'. Empty path → no outpoints.
        var p: []const u8 = parsed.path;
        if (p.len > 0 and p[0] == '/') p = p[1..];
        if (p.len == 0) {
            try self.sendRestResponse(stream, 400, "text/plain", "Error: empty request");
            return;
        }

        var check_mempool = false;
        // Split p on '/'.
        var parts = std.mem.splitScalar(u8, p, '/');
        var outpoints = std.ArrayList(types.OutPoint).init(self.allocator);
        defer outpoints.deinit();

        var first = true;
        while (parts.next()) |part| {
            if (part.len == 0) continue;
            if (first) {
                first = false;
                if (std.mem.eql(u8, part, "checkmempool")) {
                    check_mempool = true;
                    continue;
                }
            }
            // Each part: <txid_hex>-<vout>
            const dash = std.mem.indexOfScalar(u8, part, '-') orelse {
                try self.sendRestResponse(stream, 400, "text/plain", "Parse error");
                return;
            };
            const txid_hex = part[0..dash];
            const vout_str = part[dash + 1 ..];
            if (txid_hex.len != 64) {
                try self.sendRestResponse(stream, 400, "text/plain", "Parse error");
                return;
            }
            var txid: types.Hash256 = undefined;
            for (0..32) |i| {
                const hi = std.fmt.charToDigit(txid_hex[i * 2], 16) catch {
                    try self.sendRestResponse(stream, 400, "text/plain", "Parse error");
                    return;
                };
                const lo = std.fmt.charToDigit(txid_hex[i * 2 + 1], 16) catch {
                    try self.sendRestResponse(stream, 400, "text/plain", "Parse error");
                    return;
                };
                txid[31 - i] = (hi << 4) | lo;
            }
            const vout = std.fmt.parseInt(u32, vout_str, 10) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Parse error");
                return;
            };
            try outpoints.append(.{ .hash = txid, .index = vout });
        }
        if (outpoints.items.len == 0) {
            try self.sendRestResponse(stream, 400, "text/plain", "Error: empty request");
            return;
        }
        // Core: MAX_GETUTXOS_OUTPOINTS = 15
        if (outpoints.items.len > 15) {
            try self.sendRestResponse(stream, 400, "text/plain", "Error: max outpoints exceeded (max: 15)");
            return;
        }

        // For each outpoint: hits.push(coin?), bitmap bit + value/script if hit.
        // Result vec: same order as input, but 'outs' only contains hits.
        const num = outpoints.items.len;
        var hits = try self.allocator.alloc(bool, num);
        defer self.allocator.free(hits);
        @memset(hits, false);

        // Capture (height, value, script) for hits — same ordering as outpoints,
        // but the outs vector in Core only includes hit entries.
        const Hit = struct { height: u32, value: i64, script: []const u8 };
        var hit_entries = std.ArrayList(Hit).init(self.allocator);
        defer {
            for (hit_entries.items) |h| self.allocator.free(h.script);
            hit_entries.deinit();
        }

        for (outpoints.items, 0..) |op, i| {
            // checkmempool: skip if mempool spends this outpoint.
            if (check_mempool) {
                self.mempool.mutex.lock();
                const spent = self.mempool.spenders.get(op) != null;
                self.mempool.mutex.unlock();
                if (spent) continue;
            }
            const utxo_opt = self.chain_state.utxo_set.get(&op) catch continue;
            if (utxo_opt) |utxo| {
                var mut_utxo = utxo;
                defer mut_utxo.deinit(self.allocator);
                const script = mut_utxo.reconstructScript(self.allocator) catch continue;
                hits[i] = true;
                try hit_entries.append(.{
                    .height = utxo.height,
                    .value = utxo.value,
                    .script = script,
                });
            }
        }

        const active_height: i32 = @intCast(self.chain_state.best_height);
        const active_hash = self.chain_state.best_hash;

        // Build bitmap (ceil(num/8) bytes).
        const bitmap_len = (num + 7) / 8;
        const bitmap = try self.allocator.alloc(u8, bitmap_len);
        defer self.allocator.free(bitmap);
        @memset(bitmap, 0);
        for (hits, 0..) |hit, i| {
            if (hit) bitmap[i / 8] |= @as(u8, 1) << @as(u3, @intCast(i % 8));
        }

        switch (parsed.format) {
            .bin, .hex => {
                // BIP-64 binary layout:
                //   int32_t active_height (LE)
                //   uint256 active_hash (32 bytes, internal LE)
                //   bitmap as std::vector<u8>: compactSize(num) + bytes -- but
                //     the bitmap vector length is ceil(num/8); the
                //     CompactSize prefix is bitmap.size() (the byte count),
                //     not num.
                //   outs as std::vector<CCoin>: compactSize(hit_entries.len)
                //     followed by per-coin: u32 nTxVerDummy=0, u32 nHeight,
                //     CTxOut(nValue i64, scriptPubKey CompactSize+bytes).
                var ser_writer = serialize.Writer.init(self.allocator);
                defer ser_writer.deinit();
                try ser_writer.writeInt(i32, active_height);
                try ser_writer.writeBytes(&active_hash);
                try ser_writer.writeCompactSize(bitmap.len);
                try ser_writer.writeBytes(bitmap);
                try ser_writer.writeCompactSize(hit_entries.items.len);
                for (hit_entries.items) |h| {
                    try ser_writer.writeInt(u32, 0); // nTxVerDummy
                    try ser_writer.writeInt(u32, h.height);
                    try ser_writer.writeInt(i64, h.value);
                    try ser_writer.writeCompactSize(h.script.len);
                    try ser_writer.writeBytes(h.script);
                }
                const written = ser_writer.getWritten();

                if (parsed.format == .bin) {
                    try self.sendRestResponse(stream, 200, "application/octet-stream", written);
                } else {
                    var hex_buf = std.ArrayList(u8).init(self.allocator);
                    defer hex_buf.deinit();
                    for (written) |b| try hex_buf.writer().print("{x:0>2}", .{b});
                    try hex_buf.append('\n');
                    try self.sendRestResponse(stream, 200, "text/plain", hex_buf.items);
                }
            },
            .json => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                try writer.print("{{\"chainHeight\":{d},\"chaintipHash\":\"", .{active_height});
                try writeHashHex(writer, &active_hash);
                try writer.writeAll("\",\"bitmap\":\"");
                for (hits) |h| try writer.writeByte(if (h) '1' else '0');
                try writer.writeAll("\",\"utxos\":[");
                var i: usize = 0;
                for (hit_entries.items) |h| {
                    if (i > 0) try writer.writeByte(',');
                    i += 1;
                    try writer.print(
                        "{{\"height\":{d},\"value\":{d}.{d:0>8},\"scriptPubKey\":{{\"hex\":\"",
                        .{
                            h.height,
                            @divTrunc(h.value, 100_000_000),
                            @as(u64, @intCast(@mod(h.value, 100_000_000))),
                        },
                    );
                    for (h.script) |b| try writer.print("{x:0>2}", .{b});
                    try writer.writeAll("\"}}");
                }
                try writer.writeAll("]}");
                try self.sendRestResponse(stream, 200, "application/json", buf.items);
            },
        }
    }

    /// /rest/blockfilter/<filtertype>/<hash>.{bin,hex,json}
    ///
    /// Returns the BIP-158 basic filter for `<hash>`.  When
    /// `--blockfilterindex` is enabled and the persisted CF_BLOCK_FILTER
    /// has the entry, we serve from the index (O(1) RocksDB get).
    /// Otherwise we fall back to compute-on-demand from CF_BLOCKS +
    /// CF_BLOCK_UNDO — matching Core's filter byte-for-byte at the cost
    /// of one block-deserialize + one filter-build per request.  The
    /// fallback keeps REST coverage even when the index is off or the
    /// queried block falls before the persisted backfill point.
    fn restBlockFilter(self: *RpcServer, stream: std.net.Stream, remainder: []const u8) !void {
        // Path is "<filtertype>/<hash>.<ext>".
        const slash_idx = std.mem.indexOf(u8, remainder, "/") orelse {
            try self.sendRestResponse(
                stream,
                400,
                "text/plain",
                "Invalid URI format. Expected /rest/blockfilter/<filtertype>/<blockhash>",
            );
            return;
        };
        const filter_type_str = remainder[0..slash_idx];
        const hash_with_ext = remainder[slash_idx + 1 ..];
        if (!std.mem.eql(u8, filter_type_str, "basic")) {
            try self.sendRestResponse(stream, 400, "text/plain", "Unknown filtertype");
            return;
        }
        const parsed = parseRestFormat(hash_with_ext) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        if (parsed.path.len != 64) {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash");
            return;
        }
        var blockhash: types.Hash256 = undefined;
        for (0..32) |i| {
            const hi = std.fmt.charToDigit(parsed.path[i * 2], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            const lo = std.fmt.charToDigit(parsed.path[i * 2 + 1], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            blockhash[31 - i] = (hi << 4) | lo;
        }

        const filter_bytes = self.computeBasicFilterBytes(&blockhash) catch {
            try self.sendRestResponse(stream, 500, "text/plain", "Filter computation error");
            return;
        };
        const filter_owned = filter_bytes orelse {
            try self.sendRestResponse(stream, 404, "text/plain", "Filter not found.");
            return;
        };
        defer self.allocator.free(filter_owned);

        // Core wraps the filter with a CompactSize length prefix when
        // serializing the BlockFilter struct (see BlockFilter::Serialize):
        // `WriteCompactSize(filter.bytes.size()) + filter.bytes`. The wire
        // form of getcfilter follows the same prefix. We mirror that for
        // bin/hex but JSON only emits the inner filter bytes (Core
        // rest_block_filter writes "filter": HexStr(filter.GetEncodedFilter())).
        switch (parsed.format) {
            .bin, .hex => {
                var ser_writer = serialize.Writer.init(self.allocator);
                defer ser_writer.deinit();
                try ser_writer.writeCompactSize(filter_owned.len);
                try ser_writer.writeBytes(filter_owned);
                const written = ser_writer.getWritten();
                if (parsed.format == .bin) {
                    try self.sendRestResponse(stream, 200, "application/octet-stream", written);
                } else {
                    var hex_buf = std.ArrayList(u8).init(self.allocator);
                    defer hex_buf.deinit();
                    for (written) |b| try hex_buf.writer().print("{x:0>2}", .{b});
                    try hex_buf.append('\n');
                    try self.sendRestResponse(stream, 200, "text/plain", hex_buf.items);
                }
            },
            .json => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                try writer.writeAll("{\"filter\":\"");
                for (filter_owned) |b| try writer.print("{x:0>2}", .{b});
                try writer.writeAll("\"}");
                try self.sendRestResponse(stream, 200, "application/json", buf.items);
            },
        }
    }

    /// /rest/blockfilterheaders/<filtertype>/<count>/<hash>.{bin,hex,json}
    ///
    /// Walks forward along the active chain from <hash> for up to <count>
    /// blocks, computing each block's filter header via the chained
    /// hash256(filter_hash || prev_filter_header) recurrence (BIP-158).
    /// First-call walks a chain of length N, so this is O(N) per request;
    /// fine for the default count cap of 2000 and matches Core's behavior
    /// when the index is not yet built.
    fn restBlockFilterHeaders(self: *RpcServer, stream: std.net.Stream, remainder: []const u8) !void {
        // <filtertype>/<count>/<hash>.<ext>
        var iter = std.mem.splitScalar(u8, remainder, '/');
        const filter_type_str = iter.next() orelse {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid URI format");
            return;
        };
        if (!std.mem.eql(u8, filter_type_str, "basic")) {
            try self.sendRestResponse(stream, 400, "text/plain", "Unknown filtertype");
            return;
        }
        const count_str = iter.next() orelse {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid URI format");
            return;
        };
        const hash_with_ext = iter.next() orelse {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid URI format");
            return;
        };
        const parsed = parseRestFormat(hash_with_ext) orelse {
            try self.sendRestResponse(
                stream,
                404,
                "text/plain",
                "output format not found (available: bin, hex, json)",
            );
            return;
        };
        const count = std.fmt.parseInt(u32, count_str, 10) catch {
            try self.sendRestResponse(stream, 400, "text/plain", "Header count is invalid or out of acceptable range (1-2000)");
            return;
        };
        if (count < 1 or count > 2000) {
            try self.sendRestResponse(stream, 400, "text/plain", "Header count is invalid or out of acceptable range (1-2000)");
            return;
        }
        if (parsed.path.len != 64) {
            try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash");
            return;
        }
        var start_hash: types.Hash256 = undefined;
        for (0..32) |i| {
            const hi = std.fmt.charToDigit(parsed.path[i * 2], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            const lo = std.fmt.charToDigit(parsed.path[i * 2 + 1], 16) catch {
                try self.sendRestResponse(stream, 400, "text/plain", "Invalid hash hex");
                return;
            };
            start_hash[31 - i] = (hi << 4) | lo;
        }

        const cm = self.chain_manager orelse {
            try self.sendRestResponse(stream, 404, "text/plain", "No chain manager");
            return;
        };
        const start_entry = cm.getBlock(&start_hash) orelse {
            try self.sendRestResponse(stream, 404, "text/plain", "Block not found");
            return;
        };
        const tip = cm.active_tip orelse {
            try self.sendRestResponse(stream, 404, "text/plain", "No active chain");
            return;
        };
        const at_start = tip.getAncestor(start_entry.height) orelse {
            try self.sendRestResponse(stream, 404, "text/plain", "Block not on active chain");
            return;
        };
        if (!std.mem.eql(u8, &at_start.hash, &start_entry.hash)) {
            try self.sendRestResponse(stream, 404, "text/plain", "Block not on active chain");
            return;
        }

        // Walk from genesis up to start_entry, threading the filter-header
        // chain so we have the correct prev_filter_header at the start.
        // This is O(start_entry.height) per call — Core relies on a built
        // index for amortized cost, but we don't have one, so brute-force
        // it. Capped externally by RPC clients in practice.
        var prev_filter_header: types.Hash256 = [_]u8{0} ** 32;
        var h: u32 = 0;
        while (h < start_entry.height) : (h += 1) {
            const e = tip.getAncestor(h) orelse {
                try self.sendRestResponse(stream, 500, "text/plain", "Filter chain walk failed");
                return;
            };
            const f_bytes = self.computeBasicFilterBytes(&e.hash) catch null;
            if (f_bytes) |fb| {
                defer self.allocator.free(fb);
                const filter_hash = crypto.hash256(fb);
                var combined: [64]u8 = undefined;
                @memcpy(combined[0..32], &filter_hash);
                @memcpy(combined[32..64], &prev_filter_header);
                prev_filter_header = crypto.hash256(&combined);
            } else {
                try self.sendRestResponse(stream, 404, "text/plain", "Filter not found.");
                return;
            }
        }

        // Now collect filter headers for up to `count` blocks starting at start_entry.
        var filter_headers = std.ArrayList(types.Hash256).init(self.allocator);
        defer filter_headers.deinit();

        var i: u32 = 0;
        while (i < count) : (i += 1) {
            const target_h = start_entry.height + i;
            if (target_h > tip.height) break;
            const e = tip.getAncestor(target_h) orelse break;
            const f_bytes = self.computeBasicFilterBytes(&e.hash) catch null;
            if (f_bytes) |fb| {
                defer self.allocator.free(fb);
                const filter_hash = crypto.hash256(fb);
                var combined: [64]u8 = undefined;
                @memcpy(combined[0..32], &filter_hash);
                @memcpy(combined[32..64], &prev_filter_header);
                prev_filter_header = crypto.hash256(&combined);
                try filter_headers.append(prev_filter_header);
            } else {
                try self.sendRestResponse(stream, 404, "text/plain", "Filter not found.");
                return;
            }
        }

        switch (parsed.format) {
            .bin => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                for (filter_headers.items) |fh| try buf.appendSlice(&fh);
                try self.sendRestResponse(stream, 200, "application/octet-stream", buf.items);
            },
            .hex => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                for (filter_headers.items) |fh| {
                    for (fh) |b| try writer.print("{x:0>2}", .{b});
                }
                try writer.writeByte('\n');
                try self.sendRestResponse(stream, 200, "text/plain", buf.items);
            },
            .json => {
                var buf = std.ArrayList(u8).init(self.allocator);
                defer buf.deinit();
                const writer = buf.writer();
                try writer.writeByte('[');
                for (filter_headers.items, 0..) |fh, j| {
                    if (j > 0) try writer.writeByte(',');
                    try writer.writeByte('"');
                    try writeHashHex(writer, &fh);
                    try writer.writeByte('"');
                }
                try writer.writeByte(']');
                try self.sendRestResponse(stream, 200, "application/json", buf.items);
            },
        }
    }

    /// Compute the BIP-158 basic block filter for a block on disk, returning
    /// the encoded filter bytes (allocator-owned). Returns null if the block
    /// body isn't on disk (pruned / never connected).
    ///
    /// Fast path (BlockFilterIndex, 2026-05-05): when --blockfilterindex is
    /// enabled and CF_BLOCK_FILTER has an entry for `block_hash`, serve
    /// directly from the persistent index — one RocksDB get, no
    /// deserialization.  Falls through to compute-on-demand when the index
    /// is off or the entry is missing (pre-backfill / pruned).
    ///
    /// Element set per BIP-158:
    ///   - All non-empty, non-OP_RETURN scriptPubKeys from outputs in this block.
    ///   - All non-empty scriptPubKeys from inputs (from CF_BLOCK_UNDO).
    /// The genesis block has no spent prevouts.
    fn computeBasicFilterBytes(
        self: *RpcServer,
        block_hash: *const types.Hash256,
    ) !?[]const u8 {
        const db = self.chain_state.utxo_set.db orelse return null;

        // Fast path: persistent BlockFilterIndex.  No-op + falls through
        // when blockfilterindex_enabled is false or the index hasn't
        // covered this block yet.
        if (try self.chain_state.getPersistedFilter(block_hash)) |persisted| {
            return persisted;
        }

        // Genesis special-case: the genesis block body is never stored in
        // CF_BLOCKS (it is synthesized from chainparams in handleGetBlock), so
        // a CF_BLOCKS lookup would miss and we would (wrongly) report the
        // genesis filter as absent.  Build it directly from the known genesis
        // coinbase output scriptPubKey.  Core includes this element too (the
        // genesis P2PK output is neither empty nor OP_RETURN); there are no
        // spent prevouts (the coinbase input is never a filter element).
        // BIP-158 elements for genesis = { genesis_output_script }.
        if (std.mem.eql(u8, block_hash, &self.network_params.genesis_hash)) {
            const gscript = self.network_params.genesis_output_script;
            var filter = indexes_mod.buildBasicBlockFilter(
                block_hash,
                &[_][]const u8{gscript},
                &[_][]const u8{},
                self.allocator,
            ) catch return null;
            defer filter.deinit();
            return try self.allocator.dupe(u8, filter.filter.getEncoded());
        }

        // Load raw block from CF_BLOCKS.
        const raw = (db.get(storage.CF_BLOCKS, block_hash) catch return null) orelse return null;
        defer self.allocator.free(raw);

        var reader = serialize.Reader{ .data = raw };
        var block = serialize.readBlock(&reader, self.allocator) catch return null;
        defer serialize.freeBlock(self.allocator, &block);

        // Collect output scriptPubKeys.
        var out_scripts = std.ArrayList([]const u8).init(self.allocator);
        defer out_scripts.deinit();
        for (block.transactions) |tx| {
            for (tx.outputs) |o| {
                try out_scripts.append(o.script_pubkey);
            }
        }

        // Collect spent (input) scriptPubKeys from CF_BLOCK_UNDO.
        var spent_scripts = std.ArrayList([]const u8).init(self.allocator);
        defer spent_scripts.deinit();

        var owned_undo: ?storage.BlockUndoData = null;
        defer if (owned_undo) |*u| u.deinit(self.allocator);

        // Genesis has no inputs to undo; CF_BLOCK_UNDO simply won't have an entry.
        if (db.get(storage.CF_BLOCK_UNDO, block_hash) catch null) |undo_bytes| {
            defer self.allocator.free(undo_bytes);
            owned_undo = storage.BlockUndoData.fromBytes(undo_bytes, self.allocator) catch null;
            if (owned_undo) |u| {
                for (u.tx_undo) |tu| {
                    for (tu.prev_outputs) |p| {
                        try spent_scripts.append(p.script_pubkey);
                    }
                }
            }
        }

        var filter = indexes_mod.buildBasicBlockFilter(
            block_hash,
            out_scripts.items,
            spent_scripts.items,
            self.allocator,
        ) catch return null;
        defer filter.deinit();

        // buildBasicBlockFilter returns a BlockFilter whose `.filter.getEncoded()`
        // is a non-owning slice into the GCSFilter's internal buffer. Copy out.
        const encoded = filter.filter.getEncoded();
        return try self.allocator.dupe(u8, encoded);
    }

    /// Dispatch a JSON-RPC request to the appropriate handler.
    pub fn dispatch(self: *RpcServer, body: []const u8) ![]const u8 {
        // Parse JSON
        const parsed = std.json.parseFromSlice(std.json.Value, self.allocator, body, .{}) catch {
            return self.jsonRpcError(RPC_PARSE_ERROR, "Parse error", null);
        };
        defer parsed.deinit();

        const root = parsed.value;

        // Handle batch requests (array of requests)
        if (root == .array) {
            return self.handleBatch(root.array.items);
        }

        // Single request
        if (root != .object) {
            return self.jsonRpcError(RPC_INVALID_REQUEST, "Invalid Request", null);
        }

        return self.handleSingleRequest(root.object);
    }

    /// Handle a single JSON-RPC request.
    fn handleSingleRequest(self: *RpcServer, obj: std.json.ObjectMap) ![]const u8 {
        // Get method
        const method_value = obj.get("method") orelse {
            return self.jsonRpcError(RPC_INVALID_REQUEST, "Missing method", null);
        };
        if (method_value != .string) {
            return self.jsonRpcError(RPC_INVALID_REQUEST, "Method must be string", null);
        }
        const method = method_value.string;

        // Get id (can be null, number, or string)
        const id = obj.get("id");

        // Get params (optional, defaults to empty array)
        const params = obj.get("params") orelse std.json.Value{ .array = std.json.Array.init(self.allocator) };

        // Dispatch by method name
        if (std.mem.eql(u8, method, "getblockchaininfo")) {
            return self.handleGetBlockchainInfo(id);
        } else if (std.mem.eql(u8, method, "getblockcount")) {
            return self.handleGetBlockCount(id);
        } else if (std.mem.eql(u8, method, "getblockhash")) {
            return self.handleGetBlockHash(params, id);
        } else if (std.mem.eql(u8, method, "getblock")) {
            return self.handleGetBlock(params, id);
        } else if (std.mem.eql(u8, method, "getbestblockhash")) {
            return self.handleGetBestBlockHash(id);
        } else if (std.mem.eql(u8, method, "getsyncstate")) {
            return self.handleGetSyncState(id);
        } else if (std.mem.eql(u8, method, "getpeerinfo")) {
            return self.handleGetPeerInfo(id);
        } else if (std.mem.eql(u8, method, "getblockfrompeer")) {
            return self.handleGetBlockFromPeer(params, id);
        } else if (std.mem.eql(u8, method, "getnetworkinfo")) {
            return self.handleGetNetworkInfo(id);
        } else if (std.mem.eql(u8, method, "getnodeaddresses")) {
            return self.handleGetNodeAddresses(params, id);
        } else if (std.mem.eql(u8, method, "addpeeraddress")) {
            return self.handleAddPeerAddress(params, id);
        } else if (std.mem.eql(u8, method, "getmempoolinfo")) {
            return self.handleGetMempoolInfo(id);
        } else if (std.mem.eql(u8, method, "getmempoolentry")) {
            return self.handleGetMempoolEntry(params, id);
        } else if (std.mem.eql(u8, method, "prioritisetransaction")) {
            // FIX-72 / W120 BUG-11 — operator-priority RPC, Core's mining.cpp:502.
            return self.handlePrioritiseTransaction(params, id);
        } else if (std.mem.eql(u8, method, "getprioritisedtransactions")) {
            // FIX-72 / W120 BUG-11 — companion RPC to prioritisetransaction,
            // Core's mining.cpp:547.
            return self.handleGetPrioritisedTransactions(id);
        } else if (std.mem.eql(u8, method, "dumpmempool")) {
            return self.handleDumpMempool(params, id);
        } else if (std.mem.eql(u8, method, "savemempool")) {
            // Bitcoin Core: savemempool is the canonical name; dumpmempool is
            // an alias. Both go through the same handler.
            return self.handleDumpMempool(params, id);
        } else if (std.mem.eql(u8, method, "loadmempool")) {
            return self.handleLoadMempool(params, id);
        } else if (std.mem.eql(u8, method, "sendrawtransaction")) {
            return self.handleSendRawTransaction(params, id);
        } else if (std.mem.eql(u8, method, "getrawtransaction")) {
            return self.handleGetRawTransaction(params, id);
        } else if (std.mem.eql(u8, method, "getblocktemplate")) {
            return self.handleGetBlockTemplate(params, id);
        } else if (std.mem.eql(u8, method, "submitblock")) {
            return self.handleSubmitBlock(params, id);
        } else if (std.mem.eql(u8, method, "getdifficulty")) {
