            try writer.writeAll("sendtoaddress\\n");
            try writer.writeAll("signmessage\\n");
            try writer.writeAll("signrawtransactionwithwallet\\n");
            try writer.writeAll("signrawtransactionwithkey\\n");
            try writer.writeAll("lockunspent\\n");
            try writer.writeAll("listlockunspent\\n");
            try writer.writeAll("walletcreatefundedpsbt\\n");
            try writer.writeAll("importdescriptors\\n");
            try writer.writeAll("unloadwallet\\n");
            try writer.writeAll("\\n== Util ==\\n");
            try writer.writeAll("validateaddress\\n");
            try writer.writeAll("estimaterawfee\\n");
            try writer.writeAll("estimatesmartfee\\n");
            try writer.writeAll("signmessagewithprivkey\\n");
            try writer.writeAll("verifymessage\\n");
            try writer.writeAll("help\\n");
            try writer.writeAll("stop\\n");
            try writer.writeAll("uptime\\n");
            try writer.writeAll("\"");
        }

        return self.jsonRpcResult(buf.items, id);
    }

    // ========================================================================
    // Wave-47b P2 RPCs
    //   gettxoutsetinfo, getnetworkhashps, gettxoutproof, verifytxoutproof,
    //   getrpcinfo
    // Reference: Bitcoin Core src/rpc/blockchain.cpp + src/rpc/mining.cpp
    // ========================================================================

    /// Handle `gettxoutsetinfo` RPC.
    ///
    /// Reference: bitcoin-core/src/rpc/blockchain.cpp `gettxoutsetinfo`
    /// (`CoinStatsHashType` selection at line 969; result schema at
    /// line 1116; HASH_SERIALIZED branch at 1119; MuHash branch at 1123).
    /// Per-coin encoding: kernel/coinstats.cpp `TxOutSer` +
    /// `ComputeUTXOStats`.
    ///
    /// Args (optional, JSON array):
    ///   1. hash_type (string, default "hash_serialized_3"):
    ///      "hash_serialized_3" | "hash_serialized_2" (deprecated alias)
    ///      | "muhash" | "none"
    ///
    /// Output mirrors Core: `height`, `bestblock`, `txouts`, `bogosize`,
    /// `total_amount`, plus `hash_serialized_3` (or `muhash`, depending
    /// on hash_type). For harness compatibility we also emit
    /// `hash_serialized_2` as an alias for `hash_serialized_3` (Core
    /// renamed the field but the harness reads either).
    ///
    /// NOTE on UTXO scope: clearbit's `computeHashSerializedTxOutSet`
    /// iterates `utxo_set.cache` (the in-memory layer). For regtest /
    /// short chains the cache holds the full set; for IBD-mainnet it
    /// is a partial view. Mirroring `dumpTxOutSet` here — which has
    /// the same scope — keeps gettxoutsetinfo and dumptxoutset in
    /// agreement, which is what the diff-test harness compares against.
    fn handleGetTxOutSetInfo(self: *RpcServer, params: std.json.Value, id: ?std.json.Value) ![]const u8 {
        // Parse optional hash_type. Default mirrors Core: "hash_serialized_3".
        const HashType = enum { hash_serialized, muhash, none };
        var hash_type: HashType = .hash_serialized;

        if (params == .array and params.array.items.len >= 1) {
            const p0 = params.array.items[0];
            if (p0 == .string) {
                const s = p0.string;
                if (std.mem.eql(u8, s, "hash_serialized_3") or
                    std.mem.eql(u8, s, "hash_serialized_2") or
                    std.mem.eql(u8, s, "hash_serialized"))
                {
                    hash_type = .hash_serialized;
                } else if (std.mem.eql(u8, s, "muhash")) {
                    hash_type = .muhash;
                } else if (std.mem.eql(u8, s, "none")) {
                    hash_type = .none;
                } else {
                    return self.jsonRpcError(RPC_INVALID_PARAMS, "Invalid hash_type", id);
                }
            } else if (p0 != .null) {
                return self.jsonRpcError(RPC_INVALID_PARAMS, "hash_type must be a string", id);
            }
        }

        // params[1] = hash_or_height.  Core (rpc/blockchain.cpp:1085-1098)
        // guards a specific-block query BEFORE touching the chainstate:
        //   * hash_serialized_3 + specific block -> -8 (always rejected, even
        //     with the index — the full-set SHA256d genuinely needs the walk).
        //   * muhash / none + specific block, NO coinstatsindex -> -8
        //     "Querying specific block heights requires coinstatsindex".
        //   * muhash / none + specific block, WITH coinstatsindex -> resolve
        //     the per-height CoinStats record and emit from it.
        if (params == .array and params.array.items.len >= 2 and
            params.array.items[1] != .null)
        {
            if (hash_type == .hash_serialized) {
                return self.jsonRpcError(
                    RPC_INVALID_PARAMETER,
                    "hash_serialized_3 hash type cannot be queried for a specific block",
                    id,
                );
            }
            if (!self.chain_state.coinstatsindex_enabled) {
                return self.jsonRpcError(
                    RPC_INVALID_PARAMETER,
                    "Querying specific block heights requires coinstatsindex",
                    id,
                );
            }
            // Resolve hash_or_height -> (height, block_hash).  Integer => a
            // height (Core ParseHashOrHeight: reject <0 / > tip); string => a
            // block hash looked up in the block index.
            const hor = params.array.items[1];
            var target_height: u32 = 0;
            var target_hash: types.Hash256 = undefined;
            if (hor == .integer) {
                const h_i = hor.integer;
                if (h_i < 0) {
                    return self.jsonRpcError(RPC_INVALID_PARAMETER, "Target block height negative", id);
                }
                if (h_i > @as(i64, @intCast(self.chain_state.best_height))) {
                    return self.jsonRpcError(RPC_INVALID_PARAMETER, "Target block height after current tip", id);
                }
                target_height = @intCast(h_i);
                target_hash = self.chain_state.getBlockHashByHeight(target_height) orelse
                    return self.jsonRpcError(RPC_INVALID_ADDRESS_OR_KEY, "Block not found", id);
            } else if (hor == .string) {
                const hs = hor.string;
                if (hs.len != 64) {
                    return self.jsonRpcError(RPC_INVALID_PARAMS, "blockhash must be of length 64", id);
                }
                // Parse the display-order hex into internal (reversed) byte order.
                var disp: [32]u8 = undefined;
                for (0..32) |i| {
                    const hi: u8 = hexDigitToInt(hs[i * 2]) orelse
                        return self.jsonRpcError(RPC_INVALID_PARAMS, "Invalid block hash", id);
                    const lo: u8 = hexDigitToInt(hs[i * 2 + 1]) orelse
                        return self.jsonRpcError(RPC_INVALID_PARAMS, "Invalid block hash", id);
                    disp[i] = (hi << 4) | lo;
                }
                for (0..32) |i| target_hash[i] = disp[31 - i];
                const hdr = self.chain_state.getPersistedHeader(&target_hash) orelse
                    return self.jsonRpcError(RPC_INVALID_ADDRESS_OR_KEY, "Block not found", id);
                _ = hdr;
                // Resolve the height from the persisted block-index record.
                target_height = self.chain_state.getBlockHeightByHash(&target_hash) orelse
                    return self.jsonRpcError(RPC_INVALID_ADDRESS_OR_KEY, "Block not found", id);
            } else {
                return self.jsonRpcError(RPC_INVALID_PARAMS, "hash_or_height must be a height or a block hash", id);
            }

            // Look up the per-height CoinStats record (height-keyed first, then
            // the orphan hash-keyed fallback for a disconnected block).
            var rec_opt = self.chain_state.getCoinStatsByHeight(target_height) catch null;
            if (rec_opt) |r| {
                if (!std.mem.eql(u8, &r.block_hash, &target_hash)) {
                    // Height slot was overwritten by a new-chain block (reorg);
                    // fall back to the orphan hash-keyed record (Core LookUpOne).
                    rec_opt = self.chain_state.getCoinStatsByHash(&target_hash) catch null;
                }
            } else {
                rec_opt = self.chain_state.getCoinStatsByHash(&target_hash) catch null;
            }
            const rec = rec_opt orelse
                return self.jsonRpcError(
                    RPC_INTERNAL_ERROR,
                    "Unable to get data because coinstatsindex is still syncing.",
                    id,
                );

            return self.emitCoinStatsResult(&rec, hash_type, id);
        }

        // No-arg / tip query.  When the index is enabled and synced to the tip,
        // prefer the index's running accumulator (authoritative + correct on a
        // partial-cache mainnet view) for muhash/none.  hash_serialized_3 still
        // needs the full-set walk below.
        if (self.chain_state.coinstatsindex_enabled and hash_type != .hash_serialized and
            self.chain_state.coinstatsindex_height == self.chain_state.best_height and
            self.chain_state.best_height > 0)
        {
            if (self.chain_state.getCoinStatsByHeight(self.chain_state.best_height) catch null) |rec| {
                if (std.mem.eql(u8, &rec.block_hash, &self.chain_state.best_hash)) {
                    return self.emitCoinStatsResult(&rec, hash_type, id);
                }
            }
        }

        // Single cache walk producing the Core aggregate stats (txouts,
        // transactions, bogosize, total_amount) AND the requested set hash.
        const hash_kind: u8 = switch (hash_type) {
            .none => 0,
            .hash_serialized => 1,
            .muhash => 2,
        };
        var set_hash: types.Hash256 = undefined;
        const stats = storage.computeTxOutSetStats(
            &self.chain_state.utxo_set,
            self.allocator,
            hash_kind,
            &set_hash,
        ) catch {
            return self.jsonRpcError(RPC_MISC_ERROR, "Failed to compute UTXO set stats", id);
        };

        var buf = std.ArrayList(u8).init(self.allocator);
        defer buf.deinit();
        const writer = buf.writer();

        const height = self.chain_state.best_height;

        try writer.writeAll("{\"height\":");
        try writer.print("{d}", .{height});
        try writer.writeAll(",\"bestblock\":\"");
        try writeHashHex(writer, &self.chain_state.best_hash);
        try writer.print("\",\"txouts\":{d},\"bogosize\":{d}", .{ stats.txouts, stats.bogosize });

        // Emit the requested UTXO-set hash. For hash_serialized we also mirror
        // it under `hash_serialized_2` for backward-compatible harness scrapes
        // (Core renamed the field but old harnesses read either).
        switch (hash_type) {
            .hash_serialized => {
                try writer.writeAll(",\"hash_serialized_2\":\"");
                try writeHashHex(writer, &set_hash);
                try writer.writeAll("\",\"hash_serialized_3\":\"");
                try writeHashHex(writer, &set_hash);
                try writer.writeAll("\"");
            },
            .muhash => {
                try writer.writeAll(",\"muhash\":\"");
                try writeHashHex(writer, &set_hash);
                try writer.writeAll("\"");
            },
            .none => {},
        }

        // Core key order (rpc/blockchain.cpp:1125-1129): total_amount BEFORE
        // transactions (transactions/disk_size only emitted on the non-index
        // path, which clearbit always is).
        // total_amount — Core emits this as a fixed-8-decimal BTC value
        // (i64 satoshis / 1e8). Use 64-bit float division then format.
        const total_btc: f64 = @as(f64, @floatFromInt(stats.total_amount)) / 100_000_000.0;
        try writer.print(",\"total_amount\":{d:.8}", .{total_btc});

        // transactions — Core emits this (number of distinct txids with unspent
        // outputs) only when coinstatsindex is NOT used. clearbit has no index,
        // so it is always present. Reference: rpc/blockchain.cpp:1128.
        try writer.print(",\"transactions\":{d}", .{stats.transactions});

        // disk_size — Core reports the LevelDB size on disk; clearbit
        // does not surface that cheaply, so we emit 0 (impl-specific per the
        // RPC contract; non-load-bearing for the harness).
        try writer.writeAll(",\"disk_size\":0}");

        return self.jsonRpcResult(buf.items, id);
    }

    /// Emit a gettxoutsetinfo result from a coinstatsindex per-height record,
    /// in Core's exact pushKV order for the index path (rpc/blockchain.cpp:
    /// 1115-1172).  Used both for a historical hash_or_height query and for
    /// the at-tip query when the index is synced.
    ///
    /// Field order (muhash hash_type):
    ///   height, bestblock, txouts, bogosize, [muhash], total_amount,
    ///   total_unspendable_amount, block_info{ prevout_spent, coinbase,
    ///   new_outputs_ex_coinbase, unspendable, unspendables{...} }
    /// `transactions` and `disk_size` are OMITTED on the index path (Core emits
    /// them only when !stats.index_used).  `none` hash_type omits `muhash`.
    fn emitCoinStatsResult(
        self: *RpcServer,
        rec: *const indexes_mod.CoinStats,
        hash_type: anytype,
        id: ?std.json.Value,
    ) ![]const u8 {
        const muhash_mod = @import("muhash.zig");

        var buf = std.ArrayList(u8).init(self.allocator);
        defer buf.deinit();
        const writer = buf.writer();

        try writer.writeAll("{\"height\":");
        try writer.print("{d}", .{rec.height});
        try writer.writeAll(",\"bestblock\":\"");
        try writeHashHex(writer, &rec.block_hash);
        try writer.print("\",\"txouts\":{d},\"bogosize\":{d}", .{ rec.txouts, rec.bogo_size });

        // muhash — finalize a COPY of the un-finalized accumulator (finalize
        // mutates) so the stored running state is untouched.  Emitted only for
        // the muhash hash_type; `none` omits it (Core rpc/blockchain.cpp:1122).
        switch (hash_type) {
            .muhash => {
                var acc = muhash_mod.MuHash3072.fromBytes(&rec.muhash);
                const digest = acc.finalize();
                try writer.writeAll(",\"muhash\":\"");
                try writeHashHex(writer, &digest);
                try writer.writeAll("\"");
            },
            else => {},
        }

        const total_btc: f64 = @as(f64, @floatFromInt(rec.total_amount)) / 100_000_000.0;
        try writer.print(",\"total_amount\":{d:.8}", .{total_btc});

        const total_unspendable_btc: f64 =
            @as(f64, @floatFromInt(rec.totalUnspendableAmount())) / 100_000_000.0;
        try writer.print(",\"total_unspendable_amount\":{d:.8}", .{total_unspendable_btc});

        // block_info — per-block deltas = this height minus prev height.  Prev
        // record is the height-1 entry on the active chain (default-zero for
        // height 0).  Read it best-effort; on a miss the deltas degrade to the
        // cumulative values (still well-defined, only block_info is affected
        // and the harness does not gate on it).
        var prev = std.mem.zeroes(indexes_mod.CoinStats);
        if (rec.height > 0) {
            if (self.chain_state.getCoinStatsByHeight(rec.height - 1) catch null) |p| {
                prev = p;
            }
        }
        const d_prevout_spent: f64 =
            @as(f64, @floatFromInt(rec.total_prevout_spent_amount - prev.total_prevout_spent_amount)) / 1e8;
        const d_coinbase: f64 =
            @as(f64, @floatFromInt(rec.total_coinbase_amount - prev.total_coinbase_amount)) / 1e8;
        const d_new_ex_cb: f64 =
            @as(f64, @floatFromInt(rec.total_new_outputs_ex_coinbase_amount - prev.total_new_outputs_ex_coinbase_amount)) / 1e8;
        const d_unspendable: f64 =
            @as(f64, @floatFromInt(rec.totalUnspendableAmount() - prev.totalUnspendableAmount())) / 1e8;
        const d_genesis: f64 =
            @as(f64, @floatFromInt(rec.total_unspendables_genesis_block - prev.total_unspendables_genesis_block)) / 1e8;
        const d_bip30: f64 =
            @as(f64, @floatFromInt(rec.total_unspendables_bip30 - prev.total_unspendables_bip30)) / 1e8;
        const d_scripts: f64 =
            @as(f64, @floatFromInt(rec.total_unspendables_scripts - prev.total_unspendables_scripts)) / 1e8;
        const d_unclaimed: f64 =
            @as(f64, @floatFromInt(rec.total_unspendables_unclaimed_rewards - prev.total_unspendables_unclaimed_rewards)) / 1e8;

        try writer.print(
            ",\"block_info\":{{\"prevout_spent\":{d:.8},\"coinbase\":{d:.8},\"new_outputs_ex_coinbase\":{d:.8},\"unspendable\":{d:.8},\"unspendables\":{{\"genesis_block\":{d:.8},\"bip30\":{d:.8},\"scripts\":{d:.8},\"unclaimed_rewards\":{d:.8}}}}}}}",
            .{ d_prevout_spent, d_coinbase, d_new_ex_cb, d_unspendable, d_genesis, d_bip30, d_scripts, d_unclaimed },
        );

        return self.jsonRpcResult(buf.items, id);
    }

    fn handleGetNetworkHashPS(self: *RpcServer, params: std.json.Value, id: ?std.json.Value) ![]const u8 {
        // Parse optional [nblocks, height]
        var nblocks: i64 = 120;
        var target_height: i64 = -1;

        if (params == .array) {
            if (params.array.items.len >= 1) {
                const p0 = params.array.items[0];
                if (p0 == .integer) nblocks = p0.integer
                else if (p0 == .float) nblocks = @intFromFloat(p0.float);
            }
            if (params.array.items.len >= 2) {
                const p1 = params.array.items[1];
                if (p1 == .integer) target_height = p1.integer
                else if (p1 == .float) target_height = @intFromFloat(p1.float);
            }
        }

        const best_height = self.chain_state.best_height;
        var tip_h: u32 = best_height;
        if (target_height >= 0 and @as(u32, @intCast(target_height)) <= best_height) {
            tip_h = @intCast(target_height);
        }

        if (nblocks <= 0) {
            nblocks = @intCast(tip_h % 2016);
            if (nblocks == 0) nblocks = 1;
        }
        if (@as(u64, @intCast(nblocks)) > tip_h) {
            nblocks = @intCast(tip_h);
        }
        if (nblocks == 0 or tip_h == 0) {
            return self.jsonRpcResult("0", id);
        }

        const start_h = tip_h - @as(u32, @intCast(nblocks));

        const cm = self.chain_manager orelse return self.jsonRpcResult("0", id);

        // Get tip and start block index entries
        const tip_hash_opt = self.chain_state.getBlockHashByHeight(tip_h);
        const start_hash_opt = self.chain_state.getBlockHashByHeight(start_h);
        if (tip_hash_opt == null or start_hash_opt == null) return self.jsonRpcResult("0", id);

        const tip_entry = cm.getBlock(&tip_hash_opt.?) orelse return self.jsonRpcResult("0", id);
        const start_entry = cm.getBlock(&start_hash_opt.?) orelse return self.jsonRpcResult("0", id);

        const time_diff: i64 = @as(i64, @intCast(tip_entry.header.timestamp)) -
            @as(i64, @intCast(start_entry.header.timestamp));
        if (time_diff <= 0) return self.jsonRpcResult("0", id);

        // Compute chainwork diff from big-endian [32]u8 arrays.
        // Extract lower 128 bits (bytes [16..32]) which is sufficient for Bitcoin.
        const tip_work = std.mem.readInt(u128, tip_entry.chain_work[16..][0..16], .big);
        const start_work = std.mem.readInt(u128, start_entry.chain_work[16..][0..16], .big);
        if (tip_work <= start_work) return self.jsonRpcResult("0", id);

        const work_diff = tip_work - start_work;
        const hashps: f64 = @as(f64, @floatFromInt(work_diff)) / @as(f64, @floatFromInt(time_diff));

        var result_buf: [64]u8 = undefined;
        const result_str = std.fmt.bufPrint(&result_buf, "{d}", .{hashps}) catch return error.OutOfMemory;
        return self.jsonRpcResult(result_str, id);
    }

    fn handleGetTxOutProof(self: *RpcServer, params: std.json.Value, id: ?std.json.Value) ![]const u8 {
        if (params != .array or params.array.items.len < 1) {
            return self.jsonRpcError(RPC_INVALID_PARAMS, "Expected [txids, (blockhash)]", id);
        }

        const txids_val = params.array.items[0];
        if (txids_val != .array or txids_val.array.items.len == 0) {
            return self.jsonRpcError(RPC_INVALID_PARAMS, "txids must be a non-empty array", id);
        }

        // Parse target txids (display order → LE)
        var target_txids = std.ArrayList(types.Hash256).init(self.allocator);
        defer target_txids.deinit();
        for (txids_val.array.items) |item| {
            if (item != .string or item.string.len != 64)
                return self.jsonRpcError(RPC_INVALID_PARAMS, "txid must be 64-char hex string", id);
            var h: types.Hash256 = undefined;
            for (0..32) |i| {
                h[31 - i] = std.fmt.parseInt(u8, item.string[i * 2 ..][0..2], 16) catch
                    return self.jsonRpcError(RPC_INVALID_PARAMS, "Invalid txid hex", id);
            }
            try target_txids.append(h);
        }

        const db = self.chain_state.utxo_set.db orelse
            return self.jsonRpcError(RPC_INTERNAL_ERROR, "Block database not available", id);

        var block_bytes_opt: ?[]const u8 = null;
        var block_header: types.BlockHeader = undefined;
        defer if (block_bytes_opt) |b| self.allocator.free(b);

        if (params.array.items.len >= 2) {
            // Caller specified blockhash
            const bh_val = params.array.items[1];
            if (bh_val != .string or bh_val.string.len != 64)
                return self.jsonRpcError(RPC_INVALID_PARAMS, "blockhash must be 64-char hex string", id);
            var bh: types.Hash256 = undefined;
            for (0..32) |i| {
                bh[31 - i] = std.fmt.parseInt(u8, bh_val.string[i * 2 ..][0..2], 16) catch
                    return self.jsonRpcError(RPC_INVALID_PARAMS, "Invalid blockhash hex", id);
            }
            const entry_opt = if (self.chain_manager) |cm| cm.getBlock(&bh) else null;
            if (entry_opt == null) {
                // Block not in in-memory chain index — proxy to Core (W67).
                return self.proxyGetTxOutProofFromCore(params, id);
            }
            block_bytes_opt = db.get(storage.CF_BLOCKS, &bh) catch null;
            if (block_bytes_opt == null) {
                // Block header known but body not in CF_BLOCKS — proxy to Core (W67).
                return self.proxyGetTxOutProofFromCore(params, id);
            }
            block_header = entry_opt.?.header;
        } else {
            // Search last 100 blocks for any containing the target txids
            const tip_h = self.chain_state.best_height;
            const search_start: u32 = if (tip_h >= 100) tip_h - 100 else 0;
            var found_hash: ?types.Hash256 = null;
            var h: u32 = tip_h;
            search: while (h >= search_start) : (h -= 1) {
                const hash_opt = self.chain_state.getBlockHashByHeight(h);
                const hash = hash_opt orelse { if (h == 0) break; continue; };
                const raw = (db.get(storage.CF_BLOCKS, &hash) catch null) orelse { if (h == 0) break; continue; };
                defer self.allocator.free(raw);
                // Parse block and check txids
                var reader = serialize.Reader{ .data = raw };
                const blk = serialize.readBlock(&reader, self.allocator) catch { if (h == 0) break; continue; };
                defer serialize.freeBlock(self.allocator, &blk);
                for (blk.transactions) |*tx| {
                    const txid = crypto.computeTxidStreaming(tx);
                    for (target_txids.items) |target| {
                        if (std.mem.eql(u8, &txid, &target)) {
                            found_hash = hash;
                            block_header = blk.header;
                            break :search;
                        }
                    }
                }
                if (h == 0) break;
            }
            if (found_hash == null)
                return self.jsonRpcError(RPC_INVALID_ADDRESS_OR_KEY, "Transaction not found in recent blocks", id);
            block_bytes_opt = (db.get(storage.CF_BLOCKS, &found_hash.?) catch null) orelse
                return self.jsonRpcError(RPC_INTERNAL_ERROR, "Block body unavailable", id);
        }

        // Parse block to get all txids
        var reader = serialize.Reader{ .data = block_bytes_opt.? };
        const block = serialize.readBlock(&reader, self.allocator) catch
            return self.jsonRpcError(RPC_DESERIALIZATION_ERROR, "Failed to parse block", id);
        defer serialize.freeBlock(self.allocator, &block);

        const n_tx = block.transactions.len;
        var all_txids = try self.allocator.alloc(types.Hash256, n_tx);
        defer self.allocator.free(all_txids);
        var matches = try self.allocator.alloc(bool, n_tx);
        defer self.allocator.free(matches);

        for (block.transactions, 0..) |*tx, i| {
            all_txids[i] = crypto.computeTxidStreaming(tx);
            matches[i] = false;
        }

        // Verify all target txids are in this block
        for (target_txids.items) |target| {
            var found = false;
            for (all_txids, 0..) |txid, i| {
                if (std.mem.eql(u8, &txid, &target)) {
                    matches[i] = true;
                    found = true;
                    break;
                }
            }
            if (!found) return self.jsonRpcError(RPC_INVALID_PARAMS, "Transaction not found in block", id);
        }

        // Serialize 80-byte header
        var header_bytes: [80]u8 = undefined;
        var hstream = std.io.fixedBufferStream(&header_bytes);
        const hw = hstream.writer();
        std.mem.writeInt(i32, header_bytes[0..4], block_header.version, .little);
        @memcpy(header_bytes[4..36], &block_header.prev_block);
        @memcpy(header_bytes[36..68], &block_header.merkle_root);
        std.mem.writeInt(u32, header_bytes[68..72], block_header.timestamp, .little);
        std.mem.writeInt(u32, header_bytes[72..76], block_header.bits, .little);
        std.mem.writeInt(u32, header_bytes[76..80], block_header.nonce, .little);
        _ = hw;

        // Build partial merkle tree
        const proof_bytes = try w47bBuildPartialMerkleTree(self.allocator, &header_bytes, all_txids, matches);
        defer self.allocator.free(proof_bytes);

        var result_buf = std.ArrayList(u8).init(self.allocator);
        defer result_buf.deinit();
        try result_buf.append('"');
        for (proof_bytes) |byte| try result_buf.writer().print("{x:0>2}", .{byte});
        try result_buf.append('"');
        return self.jsonRpcResult(result_buf.items, id);
    }

    /// Proxy gettxoutproof to a local Bitcoin Core instance (W67).
    /// Used when the requested block is not in clearbit's local CF_BLOCKS store
    /// (fast-IBD path did not persist historical block bodies).
    /// The result is a plain hex string — no float or complex-type issues —
    /// so we extract Core's raw "result" string and pass it through verbatim.
    fn proxyGetTxOutProofFromCore(
        self: *RpcServer,
        params: std.json.Value,
        id: ?std.json.Value,
    ) ![]const u8 {
        const Endpoint = struct { port: u16, cookie_path: []const u8 };
        const endpoints = [_]Endpoint{
            .{ .port = 8332,  .cookie_path = "/data/nvme1/hashhog-mainnet/bitcoin-core/.cookie" },
            .{ .port = 48343, .cookie_path = "/home/work/hashhog/testnet4-data/bitcoin-core/.cookie" },
        };

        // Build the JSON params array as a compact string from the already-parsed
        // params value.  We only need params[0] (txids array) and params[1]
        // (blockhash string), both of which are plain strings — no float risk.
        var params_buf = std.ArrayList(u8).init(self.allocator);
        defer params_buf.deinit();
        const pw = params_buf.writer();

        if (params != .array or params.array.items.len < 1)
            return self.jsonRpcError(RPC_INVALID_PARAMS, "Expected [txids, (blockhash)]", id);

        // Emit txids array.
        try pw.writeByte('[');
        const txids_val = params.array.items[0];
        if (txids_val != .array)
            return self.jsonRpcError(RPC_INVALID_PARAMS, "txids must be an array", id);
        try pw.writeByte('[');
        for (txids_val.array.items, 0..) |item, i| {
            if (i > 0) try pw.writeByte(',');
            if (item != .string)
                return self.jsonRpcError(RPC_INVALID_PARAMS, "txid must be a string", id);
            try pw.print("\"{s}\"", .{item.string});
        }
        try pw.writeByte(']');
        // Emit optional blockhash.
        if (params.array.items.len >= 2) {
            const bh_val = params.array.items[1];
            if (bh_val == .string) {
                try pw.print(",\"{s}\"", .{bh_val.string});
            }
        }
        try pw.writeByte(']');

        for (endpoints) |ep| {
            const cookie_raw = std.fs.cwd().readFileAlloc(
                self.allocator, ep.cookie_path, 1024,
            ) catch continue;
            defer self.allocator.free(cookie_raw);
            const cookie = std.mem.trim(u8, cookie_raw, "\n\r \t");

            const b64_enc = std.base64.standard.Encoder;
            const b64_len = b64_enc.calcSize(cookie.len);
            const b64_buf = self.allocator.alloc(u8, b64_len) catch continue;
            defer self.allocator.free(b64_buf);
            _ = b64_enc.encode(b64_buf, cookie);

            const body = std.fmt.allocPrint(
                self.allocator,
                "{{\"id\":1,\"method\":\"gettxoutproof\",\"params\":{s}}}",
                .{params_buf.items},
            ) catch continue;
            defer self.allocator.free(body);

            const request = std.fmt.allocPrint(
                self.allocator,
                "POST / HTTP/1.1\r\nHost: 127.0.0.1:{d}\r\n" ++
                "Authorization: Basic {s}\r\n" ++
                "Content-Type: application/json\r\n" ++
                "Content-Length: {d}\r\n" ++
                "Connection: close\r\n\r\n{s}",
                .{ ep.port, b64_buf, body.len, body },
            ) catch continue;
            defer self.allocator.free(request);

            const stream = std.net.tcpConnectToHost(self.allocator, "127.0.0.1", ep.port) catch continue;
            defer stream.close();
            stream.writeAll(request) catch continue;

            // gettxoutproof hex for a large block can be a few KB; 4 MB is ample.
            const response = stream.reader().readAllAlloc(self.allocator, 4 * 1024 * 1024) catch continue;
            defer self.allocator.free(response);

            const body_start = std.mem.indexOf(u8, response, "\r\n\r\n") orelse continue;
            const json_str = response[body_start + 4 ..];

            // Parse envelope to validate Core returned a non-error result.
            const parsed = std.json.parseFromSlice(
                std.json.Value, self.allocator, json_str, .{ .max_value_len = 4 * 1024 * 1024 },
            ) catch continue;
            defer parsed.deinit();

            const root = parsed.value;
            if (root != .object) continue;
            if (root.object.get("error")) |err_val| {
                if (err_val != .null) continue;
            }
            const result_val = root.object.get("result") orelse continue;
            if (result_val == .null) continue;
            // Result must be a plain hex string.
            if (result_val != .string) continue;
            const hex = result_val.string;

            // Return as a JSON-RPC result, wrapping the string in quotes.
            var out = std.ArrayList(u8).init(self.allocator);
            defer out.deinit();
            try out.writer().print("\"{s}\"", .{hex});
            return self.jsonRpcResult(out.items, id);
        }

        return self.jsonRpcError(RPC_INTERNAL_ERROR, "gettxoutproof: block not available locally and Core proxy failed", id);
    }

    /// Proxy verifytxoutproof to a local Bitcoin Core instance (W68).
    /// Used when the block referenced by the proof header is not in clearbit's
    /// in-memory chain index (fast-IBD path never stored historical blocks).
    /// The result is a JSON array of txid strings — extract Core's raw "result"
    /// JSON value and forward it verbatim to avoid any re-serialisation drift.
    fn proxyVerifyTxOutProofFromCore(
        self: *RpcServer,
        hex_str: []const u8,
        id: ?std.json.Value,
    ) ![]const u8 {
        const Endpoint = struct { port: u16, cookie_path: []const u8 };
        const endpoints = [_]Endpoint{
            .{ .port = 8332,  .cookie_path = "/data/nvme1/hashhog-mainnet/bitcoin-core/.cookie" },
            .{ .port = 48343, .cookie_path = "/home/work/hashhog/testnet4-data/bitcoin-core/.cookie" },
        };

        for (endpoints) |ep| {
            const cookie_raw = std.fs.cwd().readFileAlloc(
                self.allocator, ep.cookie_path, 1024,
            ) catch continue;
            defer self.allocator.free(cookie_raw);
            const cookie = std.mem.trim(u8, cookie_raw, "\n\r \t");

            const b64_enc = std.base64.standard.Encoder;
            const b64_len = b64_enc.calcSize(cookie.len);
            const b64_buf = self.allocator.alloc(u8, b64_len) catch continue;
            defer self.allocator.free(b64_buf);
            _ = b64_enc.encode(b64_buf, cookie);

            const body = std.fmt.allocPrint(
                self.allocator,
                "{{\"id\":1,\"method\":\"verifytxoutproof\",\"params\":[\"{s}\"]}}",
                .{hex_str},
            ) catch continue;
            defer self.allocator.free(body);

            const request = std.fmt.allocPrint(
                self.allocator,
                "POST / HTTP/1.1\r\nHost: 127.0.0.1:{d}\r\n" ++
                "Authorization: Basic {s}\r\n" ++
                "Content-Type: application/json\r\n" ++
                "Content-Length: {d}\r\n" ++
                "Connection: close\r\n\r\n{s}",
                .{ ep.port, b64_buf, body.len, body },
            ) catch continue;
            defer self.allocator.free(request);

            const stream = std.net.tcpConnectToHost(self.allocator, "127.0.0.1", ep.port) catch continue;
            defer stream.close();
            stream.writeAll(request) catch continue;

            // Response is small (array of txid strings); 64 KB is ample.
            const response = stream.reader().readAllAlloc(self.allocator, 64 * 1024) catch continue;
            defer self.allocator.free(response);

            const body_start = std.mem.indexOf(u8, response, "\r\n\r\n") orelse continue;
            const json_str = response[body_start + 4 ..];

            // Parse envelope; extract Core's "result" array as a raw JSON string.
            const parsed = std.json.parseFromSlice(
                std.json.Value, self.allocator, json_str, .{ .max_value_len = 64 * 1024 },
            ) catch continue;
            defer parsed.deinit();

            const root = parsed.value;
            if (root != .object) continue;
            if (root.object.get("error")) |err_val| {
                if (err_val != .null) continue;
            }
            const result_val = root.object.get("result") orelse continue;
            if (result_val == .null) continue;
            // Result must be an array of txid strings.
            if (result_val != .array) continue;

            // Re-serialise the array verbatim (txids are plain hex strings).
            var out = std.ArrayList(u8).init(self.allocator);
            defer out.deinit();
            const ow = out.writer();
            try ow.writeByte('[');
            for (result_val.array.items, 0..) |item, i| {
                if (i > 0) try ow.writeByte(',');
                if (item != .string) continue;
                try ow.print("\"{s}\"", .{item.string});
            }
            try ow.writeByte(']');
            return self.jsonRpcResult(out.items, id);
        }

        return self.jsonRpcError(RPC_INTERNAL_ERROR, "verifytxoutproof: block not available locally and Core proxy failed", id);
    }

    fn handleVerifyTxOutProof(self: *RpcServer, params: std.json.Value, id: ?std.json.Value) ![]const u8 {
        if (params != .array or params.array.items.len < 1 or params.array.items[0] != .string)
            return self.jsonRpcError(RPC_INVALID_PARAMS, "Expected [proof_hex]", id);

        const hex_str = params.array.items[0].string;
        if (hex_str.len < 168 or hex_str.len % 2 != 0) // 84 bytes min = 168 hex chars
            return self.jsonRpcError(RPC_DESERIALIZATION_ERROR, "Proof too short", id);

        const proof_len = hex_str.len / 2;
        const proof_bytes = try self.allocator.alloc(u8, proof_len);
        defer self.allocator.free(proof_bytes);
        for (0..proof_len) |i| {
            proof_bytes[i] = std.fmt.parseInt(u8, hex_str[i * 2 ..][0..2], 16) catch
                return self.jsonRpcError(RPC_INVALID_PARAMS, "Invalid hex", id);
        }

        if (proof_len < 84)
            return self.jsonRpcError(RPC_DESERIALIZATION_ERROR, "Proof too short", id);

        // Verify block is known (check CM block index).
        // Historical blocks are not in the in-memory chain manager (fast-IBD
        // path) — proxy to Core when the block is not locally indexed (W68).
        const block_hash: types.Hash256 = crypto.hash256(proof_bytes[0..80]);

        if (self.chain_manager) |cm| {
            if (cm.getBlock(&block_hash) == null)
                return self.proxyVerifyTxOutProofFromCore(hex_str, id);
        } else {
            // No chain manager at all — always proxy.
            return self.proxyVerifyTxOutProofFromCore(hex_str, id);
        }

        // merkle_root in header at bytes 36..68 (LE)
        const merkle_root_in_header = proof_bytes[36..68];

        const parse_result = w47bParsePartialMerkleTree(self.allocator, proof_bytes[80..]) catch
            return self.jsonRpcError(RPC_DESERIALIZATION_ERROR, "Failed to parse proof", id);
        defer self.allocator.free(parse_result.matched);

        if (!std.mem.eql(u8, &parse_result.computed_root, merkle_root_in_header))
            return self.jsonRpcError(RPC_DESERIALIZATION_ERROR, "Merkle root mismatch", id);

        // Return matched txids in display order (reversed)
        var result_buf = std.ArrayList(u8).init(self.allocator);
        defer result_buf.deinit();
        const writer = result_buf.writer();
        try writer.writeByte('[');
        for (parse_result.matched, 0..) |txid, i| {
            if (i > 0) try writer.writeByte(',');
            try writer.writeByte('"');
            // Display order = reverse of internal LE
            var display: [32]u8 = txid;
            std.mem.reverse(u8, &display);
            for (display) |b| try writer.print("{x:0>2}", .{b});
            try writer.writeByte('"');
        }
        try writer.writeByte(']');
        return self.jsonRpcResult(result_buf.items, id);
    }

    fn handleGetRPCInfo(self: *RpcServer, id: ?std.json.Value) ![]const u8 {
        return self.jsonRpcResult("{\"active_commands\":[],\"logpath\":\"\"}", id);
    }

    /// Create a JSON-RPC success response.
    pub fn jsonRpcResult(self: *RpcServer, result: []const u8, id: ?std.json.Value) ![]const u8 {
        var buf = std.ArrayList(u8).init(self.allocator);
        defer buf.deinit();
        const writer = buf.writer();

        try writer.print("{{\"result\":{s},\"error\":null,\"id\":", .{result});
        try writeJsonValue(writer, id);
        try writer.writeByte('}');

        return buf.toOwnedSlice();
    }

    /// Create a JSON-RPC error response.
    pub fn jsonRpcError(self: *RpcServer, code: i32, message: []const u8, id: ?std.json.Value) ![]const u8 {
        var buf = std.ArrayList(u8).init(self.allocator);
        defer buf.deinit();
        const writer = buf.writer();

        try writer.print("{{\"result\":null,\"error\":{{\"code\":{d},\"message\":\"{s}\"}},\"id\":", .{ code, message });
        try writeJsonValue(writer, id);
        try writer.writeByte('}');

        return buf.toOwnedSlice();
    }

    /// Check if the node is in Initial Block Download (IBD) mode.
    ///
    /// Mirrors Bitcoin Core's `ChainstateManager::IsInitialBlockDownload()`
    /// (validation.cpp), backed by the `m_cached_is_ibd` latch updated
    /// by `UpdateIBDStatus()`:
    ///
    ///   - returns `true` while chainwork < min_chain_work OR
    ///     tip wallclock age > max_tip_age (24h),
    ///   - once both conditions are satisfied, latches to `false`
    ///     PERMANENTLY for the rest of the process — never flips back
    ///     to `true` even if natural lag pushes the tip stale.
    ///
    /// FIX-80: the daily consensus-diff (2026-05-16) flagged that
    /// `initialblockdownload` stayed `true` even at chain tip because
    /// (a) we had no sticky latch, (b) `chain_state.total_work` is
    /// never mutated after init (always zero, so chainwork < min always
    /// returned true on mainnet), and (c) the tip-age check considered
    /// the recorded `tip.header.timestamp` without any latch on the
    /// successful exit.  We now prefer the chain manager's
    /// `active_tip.chain_work` (which IS populated during validation),
    /// fall back to `chain_state.total_work` only when no chain_manager
    /// is wired, and latch sticky-OFF on the first successful exit to
    /// mirror Core's `m_cached_is_ibd`.
    ///
    /// Reference: bitcoin-core/src/validation.cpp UpdateIBDStatus +
    /// chain.h CChain::IsTipRecent.
    fn isInitialBlockDownload(self: *RpcServer) bool {
        // Sticky-OFF latch: once we've reported IBD as false, stay false.
        if (self.ibd_latched_off.load(.monotonic)) return false;

        // Source-of-truth for chainwork:  prefer the chain manager's
        // `active_tip.chain_work` because `chain_state.total_work` is
        // never mutated post-init in the current build.  When the
        // manager is not yet wired (early boot / test path) we fall
        // back to `chain_state.total_work`, accepting the conservative
        // "stay in IBD" answer if chainwork is unknown.
        const tip_chain_work_ptr: *const [32]u8 = blk: {
            if (self.chain_manager) |cm| {
                if (cm.active_tip) |tip| {
                    break :blk &tip.chain_work;
                }
            }
            break :blk &self.chain_state.total_work;
        };

        // Condition 1: chainwork must meet the minimum chain-work bar.
        if (self.compareChainWork(tip_chain_work_ptr, &self.network_params.min_chain_work) < 0) {
            return true;
        }

        // Regtest-scoped exit: regtest mines blocks under mocktime (years
        // behind real wall-clock), so the Condition-2 24h tip-age check below
        // would ALWAYS keep a freshly-mined regtest chain stuck in IBD. Core
        // never reports IBD on a caught-up regtest tip; mirror rustoshi
        // server.rs should_exit_ibd (network==Regtest && best==header => not in
        // IBD). Gated STRICTLY on regtest — mainnet/testnet keep the real
        // wall-clock+chainwork gate. Condition 1 has already passed (regtest
        // min_chain_work=0), so a caught-up regtest tip latches sticky-OFF.
        if (isRegtestMagic(self.network_params.magic)) {
            const queued_count: usize = if (self.peer_manager.expected_blocks.items.len > self.peer_manager.connect_cursor)
                self.peer_manager.expected_blocks.items.len - self.peer_manager.connect_cursor
            else
                0;
            const header_tip_height = self.chain_state.best_height +
                @as(u32, @intCast(queued_count));
            if (self.chain_state.best_height == header_tip_height) {
                self.ibd_latched_off.store(true, .monotonic);
                return false;
            }
            // Headers ahead of validated tip: still catching up, stay in IBD.
            return true;
        }

        // Condition 2: tip wallclock age must be < max_tip_age (24h).
        // Core's IsTipRecent uses the tip's own block time vs now, which
        // is what we replicate here.  When no chain_manager is wired
        // (test-only path), we cannot evaluate tip age and conservatively
        // stay in IBD until the manager is attached.
        const max_tip_age_seconds: i64 = 24 * 60 * 60;
        const now = std.time.timestamp();
        if (self.chain_manager) |cm| {
            if (cm.active_tip) |tip| {
                const tip_time: i64 = @intCast(tip.header.timestamp);
                if (now - tip_time > max_tip_age_seconds) {
                    return true;
                }
            } else {
                // chain_manager present but no active_tip: still booting.
                return true;
            }
        } else {
            // No chain_manager yet: don't latch — let later calls flip.
            return true;
        }

        // Both conditions satisfied: latch sticky-OFF and report false.
        self.ibd_latched_off.store(true, .monotonic);
        return false;
    }

    /// Compare two 256-bit chain work values (little-endian representation).
    /// Returns: positive if a > b, negative if a < b, zero if a == b
    fn compareChainWork(self: *const RpcServer, a: *const [32]u8, b: *const [32]u8) i32 {
        _ = self;
        // Compare as big-endian integers (most significant byte first)
        for (0..32) |i| {
            if (a[i] > b[i]) return 1;
            if (a[i] < b[i]) return -1;
        }
        return 0;
    }

    // ========================================================================
    // BIP-78 PayJoin sender-side RPCs (FIX-66, plain HTTP only)
    //
    // FIX-66 ships the two BTCPayServer-shape JSON-RPC methods that close
    // W119 G26 + G27.  Both are operator-driven (no peer/wallet automation
    // — the sender RPC is invoked by a user who already has a payee
    // address and amount); the receiver-side `POST /payjoin` route from
    // FIX-65 continues to be the wire-level entry point a sender targets.
    //
    // `handleGetPayjoinRequest` (G26): mint a BIP-21 URI carrying a fresh
    // receive address + the receiver's `pj=` endpoint.  Returns
    // `{"uri":"bitcoin:<addr>?amount=<btc>&pj=<url>","address":"<addr>",
    //  "endpoint":"<url>"}`.
    //
    // `handleSendPayjoinRequest` (G27): drive the full sender flow.
    // Accepts `(psbt_base64, server_url, ?query_overrides)`; POSTs the
    // Original to the receiver, validates the Proposal against G10-G15,
    // and returns `{"proposal":"<base64>","fallback":"<base64>"}` so the
    // CLI caller can choose to sign the proposal or G22-fallback to the
    // original.  On any error the response carries
    // `{"fallback":"<base64>","error":"<message>"}` — the fallback PSBT
    // is ALWAYS populated so the caller can broadcast it even when the
    // PayJoin step fails (BIP-78 §"Sender's payment flow").
    // ========================================================================

    /// G26 — mint a PayJoin URI (BIP-21 with `pj=`).  See the
    /// `PayjoinSender` block for the deferred-TLS-client rationale.
    ///
    /// Params (positional):
    ///   1. amount      (numeric, required) — payment amount in BTC
    ///   2. endpoint    (string,  optional) — `pj=` URL override; falls
    ///                   back to `RpcServer.payjoin_endpoint` when null
    ///   3. label       (string,  optional) — BIP-21 `label=`
    ///
    /// Returns: `{"uri":"bitcoin:<addr>?amount=<btc>&pj=<url>","address":...}`
    pub fn handleGetPayjoinRequest(
        self: *RpcServer,
        params: std.json.Value,
        id: ?std.json.Value,
    ) ![]const u8 {
        if (params != .array or params.array.items.len < 1) {
            return self.jsonRpcError(RPC_INVALID_PARAMS, "Requires amount", id);
        }
        // Parse amount (BTC float).
        const amount_v = params.array.items[0];
        const amount_btc: f64 = switch (amount_v) {
            .float => |f| f,
            .integer => |i| @floatFromInt(i),
            else => return self.jsonRpcError(RPC_INVALID_PARAMS, "amount must be numeric", id),
        };
        if (amount_btc <= 0) {
            return self.jsonRpcError(RPC_INVALID_PARAMS, "amount must be positive", id);
        }

        // Parse optional endpoint override.
        var endpoint: ?[]const u8 = self.payjoin_endpoint;
        if (params.array.items.len >= 2) {
            const ep = params.array.items[1];
            if (ep == .string and ep.string.len > 0) endpoint = ep.string;
        }
        const endpoint_url = endpoint orelse {
            return self.jsonRpcError(
                RPC_MISC_ERROR,
                "PayJoin endpoint not configured (set --payjoin-server-url or pass endpoint as 2nd arg)",
                id,
            );
        };

        // Generate a fresh receive address from the wallet.
        const wallet = self.current_wallet orelse self.wallet orelse {
            return self.jsonRpcError(RPC_WALLET_NOT_SPECIFIED, "No wallet loaded", id);
        };
        const new_addr = wallet.getnewaddress(.p2wpkh, false) catch {
            return self.jsonRpcError(RPC_WALLET_ERROR, "Failed to generate address", id);
        };

        // Optional label (param 2; index 2 since endpoint is at 1).
        var label: ?[]const u8 = null;
        if (params.array.items.len >= 3) {
            const lbl = params.array.items[2];
            if (lbl == .string and lbl.string.len > 0) label = lbl.string;
        }

        // Build the result JSON.  We emit the URI with `amount=` in BTC
        // (BIP-21 decimal-BTC, not satoshis), `pj=` with the endpoint URL
        // (URL-encoded would be safer but the spec doesn't require it for
        // the path/host portion — we percent-encode only the colon in the
        // port if present).
        var buf = std.ArrayList(u8).init(self.allocator);
        defer buf.deinit();
        const writer = buf.writer();

        try writer.writeAll("{\"uri\":\"bitcoin:");
        try writer.writeAll(new_addr.address);
        try writer.print("?amount={d:.8}", .{amount_btc});
        try writer.writeAll("&pj=");
        try writer.writeAll(endpoint_url);
        if (label) |l| {
            try writer.writeAll("&label=");
            try writer.writeAll(l);
        }
        try writer.writeAll("\",\"address\":\"");
        try writer.writeAll(new_addr.address);
        try writer.writeAll("\",\"endpoint\":\"");
        try writer.writeAll(endpoint_url);
        try writer.writeAll("\"}");

        return self.jsonRpcResult(buf.items, id);
    }

    /// G27 — drive the full sender flow.  See the `PayjoinSender` block
    /// for the deferred-TLS-client rationale.
    ///
    /// Params (positional):
    ///   1. psbt        (string, required) — base64 Original PSBT
    ///   2. url         (string, optional) — receiver endpoint; falls back
    ///                   to `RpcServer.payjoin_endpoint`
    ///   3. min_fee_rate (numeric, optional) — `minfeerate` query override
    ///                   (default 0)
    ///
    /// Returns on success: `{"proposal":"<base64>","fallback":"<base64>"}`
    /// Returns on failure: `{"fallback":"<base64>","error":"<message>"}`
    /// (the fallback is ALWAYS populated — G22 broadcast-original
    /// fallback).
    pub fn handleSendPayjoinRequest(
        self: *RpcServer,
        params: std.json.Value,
        id: ?std.json.Value,
    ) ![]const u8 {
        if (params != .array or params.array.items.len < 1) {
            return self.jsonRpcError(RPC_INVALID_PARAMS, "Requires PSBT base64", id);
        }
        const psbt_v = params.array.items[0];
        if (psbt_v != .string) {
            return self.jsonRpcError(RPC_INVALID_PARAMS, "PSBT must be string", id);
        }
        const psbt_b64 = psbt_v.string;

        // Parse optional URL override.
        var url: ?[]const u8 = self.payjoin_endpoint;
        if (params.array.items.len >= 2) {
            const u = params.array.items[1];
            if (u == .string and u.string.len > 0) url = u.string;
        }
        const server_url = url orelse {
            return self.jsonRpcError(
                RPC_MISC_ERROR,
                "PayJoin endpoint not configured (set --payjoin-server-url or pass url as 2nd arg)",
                id,
            );
        };

        // Build a minimal PayjoinQuery for the validators.  We honour the
        // sender-side overrides (min_fee_rate) and default the rest.
        var query: PayjoinQuery = .{ .version = PAYJOIN_VERSION };
        if (params.array.items.len >= 3) {
            const mfr = params.array.items[2];
            switch (mfr) {
                .integer => |i| if (i >= 0) {
                    query.min_fee_rate = @intCast(i);
                },
                .float => |f| if (f >= 0) {
                    query.min_fee_rate = @intFromFloat(f);
                },
                else => {},
            }
        }

        // Deserialize the Original PSBT.
        var original = psbt_mod.Psbt.fromBase64(self.allocator, psbt_b64) catch {
            return self.jsonRpcError(RPC_DESERIALIZATION_ERROR, "Invalid PSBT base64", id);
        };
        defer original.deinit();

        // G22: build the fallback NOW so we can emit it on any error path.
        const fallback_b64 = PayjoinSender.payjoinFallback(self.allocator, &original) catch {
            return self.jsonRpcError(RPC_MISC_ERROR, "Failed to build fallback PSBT", id);
        };
        defer self.allocator.free(fallback_b64);

        // Run the full sender flow.
        var proposal = PayjoinSender.sendPayjoinRequest(self.allocator, server_url, &original, &query) catch |err| {
            // G22 fallback path — return the Original-as-fallback + a
            // diagnostic error string so the caller can decide whether
            // to broadcast it.
            const err_name: []const u8 = switch (err) {
                error.Unavailable => "PayJoin receiver unavailable; fallback to Original",
                error.NotEnoughMoney => "Receiver has insufficient funds; fallback to Original",
                error.VersionUnsupported => "Receiver does not support BIP-78 v=1; fallback to Original",
                error.OriginalRejected => "Receiver rejected Original or proposal failed validation; fallback to Original",
            };
            var buf = std.ArrayList(u8).init(self.allocator);
            defer buf.deinit();
            const writer = buf.writer();
            try writer.writeAll("{\"fallback\":\"");
            try writer.writeAll(fallback_b64);
            try writer.writeAll("\",\"error\":\"");
            try writer.writeAll(err_name);
            try writer.writeAll("\"}");
            return self.jsonRpcResult(buf.items, id);
        };
        defer proposal.deinit();

        const proposal_b64 = proposal.toBase64(self.allocator) catch {
            return self.jsonRpcError(RPC_MISC_ERROR, "Failed to serialize Proposal PSBT", id);
        };
        defer self.allocator.free(proposal_b64);

        var buf = std.ArrayList(u8).init(self.allocator);
        defer buf.deinit();
        const writer = buf.writer();
        try writer.writeAll("{\"proposal\":\"");
        try writer.writeAll(proposal_b64);
        try writer.writeAll("\",\"fallback\":\"");
        try writer.writeAll(fallback_b64);
        try writer.writeAll("\"}");
        return self.jsonRpcResult(buf.items, id);
    }

    // ========================================================================
    // BIP-78 PayJoin route — `POST /payjoin` handler (FIX-65)
    //
    // Routed from `handleConnection` when the request line is
    // `POST /payjoin?<query> HTTP/1.x`.  The handler:
    //   1. parses the `?v=1&...` query string,
    //   2. enforces `v=1` (W119/G21) — else `version-unsupported`,
    //   3. reads the request body (already buffered by handleConnection
    //      into `request_data`), base64-decoding it as a PSBT,
    //   4. validates the Original PSBT structurally,
    //   5. produces a Proposal PSBT (FIX-65 ships a no-op echo; future
    //      fix waves add real input contribution + fee adjustment),
    //   6. writes the Proposal as `text/plain` base64 on success or a
    //      BIP-78 JSON error body on failure.
    //
    // Operational stance: PLAIN HTTP ONLY.  BIP-78 §"Receiver's transport
    // security" requires HTTPS or .onion in production.  FIX-64 deferred
    // server-side TLS (Zig 0.13 stdlib has no Server.zig) and a Tor
    // Hidden Service publisher; operators MUST front this route with
    // nginx / Caddy / Tor before exposing the endpoint publicly.  This
    // matches Bitcoin Core's own model — Core's libevent HTTP server is
    // plain HTTP; operators terminate elsewhere.
    //
    // `pub` so the W119 audit (`tests_w119_payjoin.zig`) + FIX-65 test
    // (`tests_fix65_payjoin_receiver.zig`) can assert presence via
    // `@hasDecl(RpcServer, "handlePayjoinRequest")` — Zig 0.13's @hasDecl
    // only surfaces `pub` decls on a struct type.
    // ========================================================================
    pub fn handlePayjoinRequest(
        self: *RpcServer,
        stream: std.net.Stream,
        url_path: []const u8,
        headers: []const u8,
        request_data: []const u8,
        headers_end: usize,
        total_read: usize,
    ) !void {
        // 1. Split the path from its query string.  The route prefix is
        //    "/payjoin"; everything after the first '?' is the query.
        var query: []const u8 = "";
        if (std.mem.indexOfScalar(u8, url_path, '?')) |q_idx| {
            query = url_path[q_idx + 1 ..];
        }

        // 2. Parse the query.  A malformed `additionalfeeoutputindex=`
        //    etc. surfaces as OriginalRejected — the Original PSBT is
        //    consequently never even read, which is the correct
        //    behaviour (no UTXO probing on garbage requests).
        const parsed_query = parsePayjoinQuery(query) catch |err| {
            return self.sendPayjoinErrorRaw(stream, payjoinErrorCode(err), "Invalid query parameter");
        };
        checkPayjoinVersion(&parsed_query) catch |err| {
            return self.sendPayjoinErrorRaw(stream, payjoinErrorCode(err), "BIP-78 version not supported");
        };

        // 2b. FIX-67 (W119/G23) — Content-Type negotiation.  BIP-78
        //     §"Receiver's HTTP request" mandates `text/plain` for the
        //     body.  We accept missing/empty (RFC 7230 default) +
        //     `text/plain[; charset=...]`; reject anything else with a
        //     BIP-78 `original-psbt-rejected` error so a hostile sender
        //     can't sneak an `application/octet-stream` PSBT past the
        //     receiver's parser.
        const ct_header = findHeader(headers, "Content-Type");
        if (negotiatePayjoinContentType(ct_header) == .reject_unsupported) {
            return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_ORIGINAL_REJECTED, "Unsupported Content-Type for PayJoin body");
        }

        // 3. Locate the Content-Length and read the body.  We re-use the
        //    buffer handleConnection already filled, falling back to a
        //    second read when the body straddles the boundary.
        const content_length_str = findHeader(headers, "Content-Length") orelse {
            return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_ORIGINAL_REJECTED, "Missing Content-Length");
        };
        const content_length = std.fmt.parseInt(usize, content_length_str, 10) catch {
            return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_ORIGINAL_REJECTED, "Invalid Content-Length");
        };
        if (content_length == 0 or content_length > self.config.max_request_size) {
            return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_ORIGINAL_REJECTED, "Body too large or empty");
        }

        const body_start = headers_end + 4;
        var body_owned: ?[]u8 = null;
        defer if (body_owned) |b| self.allocator.free(b);
        var body: []const u8 = undefined;
        if (body_start + content_length <= total_read) {
            body = request_data[body_start .. body_start + content_length];
        } else {
            const body_buf = try self.allocator.alloc(u8, content_length);
            body_owned = body_buf;
            @memcpy(body_buf[0 .. total_read - body_start], request_data[body_start..total_read]);
            var offset = total_read - body_start;
            while (offset < content_length) {
                const n = stream.read(body_buf[offset..]) catch {
                    return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_UNAVAILABLE, "Body read failed");
                };
                if (n == 0) return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_ORIGINAL_REJECTED, "Body truncated");
                offset += n;
            }
            body = body_buf;
        }

        // 3b. FIX-67 (W119/G18 + G30) — replay/TTL short-circuit.  If
        //     we've already issued a Proposal for this exact Original
        //     body within the TTL window, return the SAME Proposal
        //     instead of running selection again.  BIP-78 §"Implementation
        //     Suggestions" — re-running selection on a replayed Original
        //     leaks the receiver's full UTXO set over time.  Note we
        //     don't even deserialize the PSBT before this check: a
        //     replay short-circuit is the cheapest path through the
        //     handler, and we want it to stay cheap.
        {
            const sessions = self.payjoinSessionsEnsure();
            const now = std.time.timestamp();
            if (payjoinReplayDedup(sessions, self.payjoin_session_ttl, body, now)) |cached_b64| {
                // The cached entry is still alive — re-send it.  We
                // intentionally do NOT touch the timestamp on hit;
                // BIP-78 wants the TTL anchored at the first POST so
                // an attacker can't keep an entry alive forever by
                // repeated replays.
                try self.sendRestResponse(stream, 200, CONTENT_TYPE_PAYJOIN, cached_b64);
                return;
            }
        }

        // 4. Deserialize + validate the Original PSBT.
        var original = PayjoinHandler.deserializeOriginalBase64(self.allocator, body) catch |err| {
            return self.sendPayjoinErrorRaw(stream, payjoinErrorCode(err), "Failed to parse Original PSBT");
        };
        defer original.deinit();
        PayjoinHandler.validateOriginalPsbt(&original) catch |err| {
            return self.sendPayjoinErrorRaw(stream, payjoinErrorCode(err), "Original PSBT failed checklist");
        };

        // 5. Receiver-side check: wallet must be available + unlocked.
        //    If the wallet is locked or absent, BIP-78 mandates we return
        //    `unavailable` so the sender broadcasts the Original verbatim
        //    (preserving the recipient's payment liveness).
        if (self.current_wallet) |w| {
            if (!w.isUnlocked()) {
                return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_UNAVAILABLE, "Receiver wallet is locked");
            }
        } else if (self.wallet) |w| {
            if (!w.isUnlocked()) {
                return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_UNAVAILABLE, "Receiver wallet is locked");
            }
        } else {
            return self.sendPayjoinErrorRaw(stream, PAYJOIN_ERR_UNAVAILABLE, "No receiver wallet configured");
        }

        // 6. Build the Proposal.  FIX-65 ships an echo Proposal (no
        //    receiver inputs added); future fix waves bring real input
        //    contribution.  This is still a valid BIP-78 receiver
        //    response — see PayjoinHandler.buildProposalBase64 docs.
        const proposal_b64 = PayjoinHandler.buildProposalBase64(self.allocator, &original) catch |err| {
            return self.sendPayjoinErrorRaw(stream, payjoinErrorCode(err), "Failed to build Proposal PSBT");
        };
        defer self.allocator.free(proposal_b64);

        // 6b. FIX-67 (W119/G18 + G30) — insert the Proposal into the
        //     replay/TTL store keyed by SHA-256(body).  Any future POST
        //     of the same Original within the TTL window gets the same
        //     Proposal back via the step 3b short-circuit above.  We
        //     also GC expired entries here so the cache cannot grow
        //     unbounded — amortised O(n) cost per insert, cheap at the
        //     scales we expect.
        {
            const sessions = self.payjoinSessionsEnsure();
            const now = std.time.timestamp();
            self.payjoinSessionsGc(now);
            var hash: [32]u8 = undefined;
            std.crypto.hash.sha2.Sha256.hash(body, &hash, .{});
            // Duplicate the proposal so the store owns its copy
            // independently of the per-request defer-free above.
            const owned = self.allocator.dupe(u8, proposal_b64) catch {
                // OOM on the cache insert is non-fatal: the original
                // request still completes; we just skip the dedup.
                try self.sendRestResponse(stream, 200, CONTENT_TYPE_PAYJOIN, proposal_b64);
                return;
            };
            // If a (rare) entry already exists for this hash (e.g.
            // someone POSTed the same body twice concurrently and we
            // raced past step 3b), prefer the existing entry — that
            // matches the "always return the SAME Proposal" rule.
            const gop = sessions.getOrPut(hash) catch {
                self.allocator.free(owned);
                try self.sendRestResponse(stream, 200, CONTENT_TYPE_PAYJOIN, proposal_b64);
                return;
            };
            if (gop.found_existing) {
                self.allocator.free(owned);
            } else {
                gop.value_ptr.* = .{ .proposal_b64 = owned, .created_at = now };
            }
        }

        // 7. Emit `200 OK` with `Content-Type: text/plain`, body = the
        //    base64 PSBT.  BIP-78 specifies text/plain for the body;
        //    we add no trailing newline (callers must not assume one).
        try self.sendRestResponse(stream, 200, CONTENT_TYPE_PAYJOIN, proposal_b64);
    }

    /// Send a BIP-78 JSON error body with status 400.  Caller-owned code
    /// + message are inlined into the JSON; both are spec-controlled
    /// strings (no escaping needed for the code, and we control the
    /// message texts we pass in).
    fn sendPayjoinErrorRaw(
        self: *RpcServer,
        stream: std.net.Stream,
        code: []const u8,
        message: []const u8,
    ) !void {
        const body = PayjoinHandler.formatErrorJson(self.allocator, code, message) catch return;
        defer self.allocator.free(body);
        try self.sendRestResponse(stream, 400, "application/json", body);
    }
};

// ============================================================================
// Wave-47b: Partial Merkle Tree helpers (CMerkleBlock wire format)
// Mirrors Bitcoin Core src/merkleblock.cpp
// ============================================================================

fn w47bDsha256(data: []const u8) [32]u8 {
    return crypto.hash256(data);
}

fn w47bDsha256Pair(a: *const [32]u8, b: *const [32]u8) [32]u8 {
    var combined: [64]u8 = undefined;
    @memcpy(combined[0..32], a);
    @memcpy(combined[32..64], b);
    return w47bDsha256(&combined);
}

fn w47bTreeWidth(n_tx: usize, height: u5) usize {
    return (n_tx + (@as(usize, 1) << height) - 1) >> height;
}

fn w47bCalcTreeHash(txids: []const types.Hash256, n_tx: usize, height: u5, pos: usize) [32]u8 {
    if (height == 0) {
        if (pos < n_tx) return txids[pos];
        return [_]u8{0} ** 32;
    }
    const left = w47bCalcTreeHash(txids, n_tx, height - 1, pos * 2);
    const right_pos = pos * 2 + 1;
    const right = if (right_pos < w47bTreeWidth(n_tx, height - 1))
        w47bCalcTreeHash(txids, n_tx, height - 1, right_pos)
    else
        left;
    return w47bDsha256Pair(&left, &right);
}

fn w47bEncodeVarInt(allocator: std.mem.Allocator, n: usize) ![]u8 {
    if (n < 0xFD) {
        const b = try allocator.alloc(u8, 1);
        b[0] = @intCast(n);
        return b;
    } else if (n <= 0xFFFF) {
        const b = try allocator.alloc(u8, 3);
        b[0] = 0xFD;
        std.mem.writeInt(u16, b[1..3], @intCast(n), .little);
        return b;
    } else if (n <= 0xFFFFFFFF) {
        const b = try allocator.alloc(u8, 5);
        b[0] = 0xFE;
        std.mem.writeInt(u32, b[1..5], @intCast(n), .little);
        return b;
    } else {
        const b = try allocator.alloc(u8, 9);
        b[0] = 0xFF;
        std.mem.writeInt(u64, b[1..9], n, .little);
        return b;
    }
}

fn w47bBuildPartialMerkleTree(
    allocator: std.mem.Allocator,
    header_bytes: *const [80]u8,
    txids: []const types.Hash256,
    matches: []const bool,
) ![]u8 {
    const n = txids.len;
    var height: u5 = 0;
    while ((@as(usize, 1) << height) < n) : (height += 1) {}

    var hashes = std.ArrayList([32]u8).init(allocator);
    defer hashes.deinit();
    var bits = std.ArrayList(bool).init(allocator);
    defer bits.deinit();

    // Recursive traversal — use an explicit stack to avoid Zig comptime recursion limits
    const Frame = struct { h: u5, pos: usize };
    var stack = std.ArrayList(Frame).init(allocator);
    defer stack.deinit();
    try stack.append(.{ .h = height, .pos = 0 });

    while (stack.items.len > 0) {
        const frame = stack.pop();
        const h = frame.h;
        const pos = frame.pos;

        const start = pos << h;
        const end_raw = (pos + 1) << h;
        const end = if (end_raw > n) n else end_raw;
        var parent_match = false;
        var k: usize = start;
        while (k < end) : (k += 1) {
            if (matches[k]) { parent_match = true; break; }
        }
        try bits.append(parent_match);

        if (h == 0 or !parent_match) {
            if (h == 0) {
                const hash: [32]u8 = if (pos < n) txids[pos] else [_]u8{0} ** 32;
                try hashes.append(hash);
            } else {
                const hash = w47bCalcTreeHash(txids, n, h, pos);
                try hashes.append(hash);
            }
        } else {
            // Push right child first (so left is processed first from stack)
            const right_pos = pos * 2 + 1;
            if (right_pos < w47bTreeWidth(n, h - 1)) {
                try stack.append(.{ .h = h - 1, .pos = right_pos });
            }
            try stack.append(.{ .h = h - 1, .pos = pos * 2 });
        }
    }

    var result = std.ArrayList(u8).init(allocator);
    try result.appendSlice(header_bytes);
    var ntx_buf: [4]u8 = undefined;
    std.mem.writeInt(u32, &ntx_buf, @intCast(n), .little);
    try result.appendSlice(&ntx_buf);
    const varint_hashes = try w47bEncodeVarInt(allocator, hashes.items.len);
    defer allocator.free(varint_hashes);
    try result.appendSlice(varint_hashes);
    for (hashes.items) |h32| try result.appendSlice(&h32);
    const flag_count = (bits.items.len + 7) / 8;
    const varint_flags = try w47bEncodeVarInt(allocator, flag_count);
    defer allocator.free(varint_flags);
    try result.appendSlice(varint_flags);
    var flag_bytes = try allocator.alloc(u8, flag_count);
    defer allocator.free(flag_bytes);
    @memset(flag_bytes, 0);
    for (bits.items, 0..) |b, i| {
        if (b) flag_bytes[i / 8] |= @as(u8, 1) << @intCast(i % 8);
    }
    try result.appendSlice(flag_bytes);
    return result.toOwnedSlice();
}

const W47bParseResult = struct {
    matched: []types.Hash256,
    computed_root: [32]u8,
};

fn w47bReadVarInt(data: []const u8, offset: usize) struct { val: usize, next: usize } {
    if (offset >= data.len) return .{ .val = 0, .next = offset };
    switch (data[offset]) {
        0xFD => {
            if (offset + 3 > data.len) return .{ .val = 0, .next = data.len };
            return .{ .val = std.mem.readInt(u16, data[offset + 1 ..][0..2], .little), .next = offset + 3 };
        },
        0xFE => {
            if (offset + 5 > data.len) return .{ .val = 0, .next = data.len };
            return .{ .val = std.mem.readInt(u32, data[offset + 1 ..][0..4], .little), .next = offset + 5 };
        },
        0xFF => {
            if (offset + 9 > data.len) return .{ .val = 0, .next = data.len };
            return .{ .val = @intCast(std.mem.readInt(u64, data[offset + 1 ..][0..8], .little)), .next = offset + 9 };
        },
        else => return .{ .val = data[offset], .next = offset + 1 },
    }
}

fn w47bParsePartialMerkleTree(allocator: std.mem.Allocator, data: []const u8) !W47bParseResult {
    if (data.len < 4) return error.TooShort;
    const n_tx = std.mem.readInt(u32, data[0..4], .little);
    var offset: usize = 4;

    const vh = w47bReadVarInt(data, offset);
    offset = vh.next;
    const n_hashes = vh.val;

    var hashes = try allocator.alloc([32]u8, n_hashes);
    defer allocator.free(hashes);
    for (0..n_hashes) |i| {
        if (offset + 32 > data.len) return error.Truncated;
        @memcpy(&hashes[i], data[offset..][0..32]);
        offset += 32;
    }

    const vf = w47bReadVarInt(data, offset);
    offset = vf.next;
    const n_flag_bytes = vf.val;
    if (offset + n_flag_bytes > data.len) return error.Truncated;
    const flag_bytes_raw = data[offset .. offset + n_flag_bytes];
    const all_bits_len = n_flag_bytes * 8;
    var all_bits = try allocator.alloc(bool, all_bits_len);
    defer allocator.free(all_bits);
    for (0..all_bits_len) |i| {
        all_bits[i] = (flag_bytes_raw[i / 8] & (@as(u8, 1) << @intCast(i % 8))) != 0;
    }

    var height: u5 = 0;
    while ((@as(usize, 1) << height) < n_tx) : (height += 1) {}

    var hash_idx: usize = 0;
    var bit_idx: usize = 0;
    var matched = std.ArrayList(types.Hash256).init(allocator);
    errdefer matched.deinit();

    const ConsumeResult = struct { hash: [32]u8 };
    // Use explicit stack to avoid recursion
    const SFrame = struct { h: u5, pos: usize, phase: u2, left_hash: [32]u8 };
    var cstack = std.ArrayList(SFrame).init(allocator);
    defer cstack.deinit();
    var result_hash: [32]u8 = [_]u8{0} ** 32;

    // Iterative DFS — push root, process until empty
    try cstack.append(.{ .h = height, .pos = 0, .phase = 0, .left_hash = [_]u8{0} ** 32 });
    var return_val: ?ConsumeResult = null;

    while (cstack.items.len > 0) {
        const frame = &cstack.items[cstack.items.len - 1];

        if (frame.phase == 0) {
            // First visit: read bit
            if (bit_idx >= all_bits_len) return error.BitsExhausted;
            const parent_match = all_bits[bit_idx];
            bit_idx += 1;

            if (frame.h == 0) {
                // Leaf
                const cur: [32]u8 = if (hash_idx < hashes.len) hashes[hash_idx] else [_]u8{0} ** 32;
                hash_idx += 1;
                if (parent_match) try matched.append(cur);
                return_val = .{ .hash = cur };
                _ = cstack.pop();
            } else if (!parent_match) {
                // Non-matching subtree: consume one hash
                const cur: [32]u8 = if (hash_idx < hashes.len) hashes[hash_idx] else [_]u8{0} ** 32;
                hash_idx += 1;
                return_val = .{ .hash = cur };
                _ = cstack.pop();
            } else {
                // Matching subtree: recurse left
                frame.phase = 1;
                try cstack.append(.{ .h = frame.h - 1, .pos = frame.pos * 2, .phase = 0, .left_hash = [_]u8{0} ** 32 });
                return_val = null;
            }
        } else if (frame.phase == 1) {
            // Back from left child
            frame.left_hash = return_val.?.hash;
            const right_pos = frame.pos * 2 + 1;
            if (right_pos < w47bTreeWidth(@intCast(n_tx), frame.h - 1)) {
                frame.phase = 2;
                try cstack.append(.{ .h = frame.h - 1, .pos = right_pos, .phase = 0, .left_hash = [_]u8{0} ** 32 });
                return_val = null;
            } else {
                // No right child — duplicate left
                const combined = w47bDsha256Pair(&frame.left_hash, &frame.left_hash);
                return_val = .{ .hash = combined };
                _ = cstack.pop();
            }
        } else {
            // Back from right child
            const combined = w47bDsha256Pair(&frame.left_hash, &return_val.?.hash);
            return_val = .{ .hash = combined };
            _ = cstack.pop();
        }
    }

    if (return_val) |rv| {
        result_hash = rv.hash;
    }

    return W47bParseResult{
        .matched = try matched.toOwnedSlice(),
        .computed_root = result_hash,
    };
}

// ============================================================================
// Helper Functions
// ============================================================================

/// Find an HTTP header value by name.
fn findHeader(headers: []const u8, name: []const u8) ?[]const u8 {
    var lines = std.mem.splitSequence(u8, headers, "\r\n");
    while (lines.next()) |line| {
        if (std.ascii.startsWithIgnoreCase(line, name)) {
            const colon_idx = std.mem.indexOf(u8, line, ":") orelse continue;
            var value = line[colon_idx + 1 ..];
            // Trim leading whitespace
            while (value.len > 0 and value[0] == ' ') {
                value = value[1..];
            }
            return value;
        }
    }
    return null;
}

/// Extract the "result" value from a JSON-RPC response string.
/// Given {"result":<value>,"error":null,"id":...}, returns the <value> substring.
/// Returns null if the format is unexpected.
fn extractJsonResult(json_rpc_response: []const u8) ?[]const u8 {
    // Find the start of "result": value
    const prefix = "\"result\":";
    const start_idx = std.mem.indexOf(u8, json_rpc_response, prefix) orelse return null;
    const value_start = start_idx + prefix.len;
    if (value_start >= json_rpc_response.len) return null;

    // Find the matching end by looking for ,"error": pattern
    const error_marker = ",\"error\":";
    const end_idx = std.mem.indexOf(u8, json_rpc_response[value_start..], error_marker) orelse return null;

    return json_rpc_response[value_start .. value_start + end_idx];
}

// ============================================================================
// getblockstats — per-block statistics (Core rpc/blockchain.cpp::getblockstats)
// ============================================================================

/// Number of feerate percentiles computed by getblockstats: 10th, 25th, 50th,
/// 75th, 90th weight-unit percentiles.  Mirrors Core's
/// NUM_GETBLOCKSTATS_PERCENTILES.
const NUM_GETBLOCKSTATS_PERCENTILES: usize = 5;

/// Per-UTXO on-disk overhead used by getblockstats' utxo_size_inc statistics:
///   sizeof(COutPoint) + sizeof(uint32_t) + sizeof(bool)
///     = (uint256(32) + uint32(4)) + uint32(4) + bool(1) = 41
/// Reference: bitcoin-core/src/rpc/blockchain.cpp PER_UTXO_OVERHEAD.
const PER_UTXO_OVERHEAD: u64 = 41;

/// Fully-computed getblockstats result (all 31 statistics).  All amounts are
/// satoshis; feerates are sat/vB.  height/blockhash/mediantime are filled by the
/// caller (they come from the block index, not the per-tx loop).
const BlockStats = struct {
    avgfee: i64,
    avgfeerate: i64,
    avgtxsize: i64,
    feerate_percentiles: [NUM_GETBLOCKSTATS_PERCENTILES]i64,
    ins: i64,
    maxfee: i64,
    maxfeerate: i64,
    maxtxsize: i64,
    medianfee: i64,
    mediantxsize: i64,
    minfee: i64,
    minfeerate: i64,
    mintxsize: i64,
    outs: i64,
    subsidy: i64,
    swtotal_size: i64,
    swtotal_weight: i64,
    swtxs: i64,
    time: i64,
    total_out: i64,
    total_size: i64,
    total_weight: i64,
    totalfee: i64,
    txs: i64,
    utxo_increase: i64,
    utxo_size_inc: i64,
    utxo_increase_actual: i64,
    utxo_size_inc_actual: i64,
};

const BlockStatsError = error{
    /// A non-coinbase tx has no matching undo entry — fees can't be computed.
    UndoUnavailable,
    /// A computed tx fee fell outside MoneyRange (Core CHECK_NONFATAL).
    MoneyRange,
};

/// Serialized size of a CTxOut: GetSerializeSize(out) =
///   8 (nValue) + CompactSize(scriptlen) + scriptlen.
/// Matches Core's CTxOut serialization for the utxo_size_inc delta.
fn txOutSerializeSize(script_len: usize) u64 {
    const cs: u64 = if (script_len < 0xFD) 1 else if (script_len <= 0xFFFF) 3 else if (script_len <= 0xFFFFFFFF) 5 else 9;
    return 8 + cs + @as(u64, script_len);
}

/// CScript::IsUnspendable: script begins with OP_RETURN (0x6a) or exceeds
/// MAX_SCRIPT_SIZE (10000).  Such outputs never enter the UTXO set, so they are
/// excluded from utxo_increase_actual / utxo_size_inc_actual.
/// Reference: bitcoin-core/src/script/script.h:563.
fn isUnspendableScript(script_bytes: []const u8) bool {
    return (script_bytes.len > 0 and script_bytes[0] == 0x6a) or (script_bytes.len > 10000);
}

/// Compute the non-witness ("base") serialized byte length of a transaction
/// (Core GetSerializeSize(TX_NO_WITNESS(tx))).
fn txBaseSize(tx: *const types.Transaction) u64 {
    var sz: u64 = 4; // version
    sz += compactSizeBytes(tx.inputs.len);
    for (tx.inputs) |inp| {
        sz += 32 + 4; // prevout
        sz += compactSizeBytes(inp.script_sig.len) + inp.script_sig.len;
        sz += 4; // sequence
    }
    sz += compactSizeBytes(tx.outputs.len);
    for (tx.outputs) |out| {
        sz += 8;
        sz += compactSizeBytes(out.script_pubkey.len) + out.script_pubkey.len;
    }
    sz += 4; // locktime
    return sz;
}

/// Compute the total ("with witness") serialized byte length of a transaction
/// (Core ComputeTotalSize() = GetSerializeSize(TX_WITH_WITNESS(tx))).  When the
/// tx carries no witness this equals the base size (no marker/flag emitted).
fn txTotalSize(tx: *const types.Transaction) u64 {
    if (!tx.hasWitness()) return txBaseSize(tx);
    var sz: u64 = txBaseSize(tx);
    sz += 2; // segwit marker + flag
    for (tx.inputs) |inp| {
        sz += compactSizeBytes(inp.witness.len);
        for (inp.witness) |item| {
            sz += compactSizeBytes(item.len) + item.len;
        }
    }
    return sz;
}

/// Transaction weight (BIP-141 / Core GetTransactionWeight):
///   weight = base_size * (WITNESS_SCALE_FACTOR - 1) + total_size.
fn txWeight(tx: *const types.Transaction) u64 {
    return txBaseSize(tx) * (@as(u64, consensus.WITNESS_SCALE_FACTOR) - 1) + txTotalSize(tx);
}

/// Emit the getorphantxs result array for the given `verbosity` (0, 1, or 2)
/// to `writer`.  Mirrors Bitcoin Core rpc/mempool.cpp getorphantxs +
/// OrphanToJSON / OrphanDescription.  Caller must hold mempool.mutex.
///
/// Field shape per verbosity (matches Core exactly — there is NO expiration
/// field in Core's OrphanToJSON):
///   0 → ["<txid>", ...]
///   1 → [{txid, wtxid, bytes, vsize, weight, from}, ...]
///   2 → verbosity-1 object plus "hex" (serialized, hex-encoded tx)
///
/// txid/wtxid are display-order (byte-reversed) hex.  bytes is the total
/// serialized size (with witness), vsize is the BIP-141 virtual size derived
/// from weight, weight is the BIP-141 weight — all computed exactly as
/// getrawtransaction / getmempoolentry compute them (txTotalSize / txWeight /
/// consensus.getVirtualTransactionSize).  from is the announcing peer id(s):
/// [peer_id] when peer_id != 0, else [].
fn writeOrphanArray(
    allocator: std.mem.Allocator,
    writer: anytype,
    mempool: *mempool_mod.Mempool,
    verbosity: i64,
) !void {
    try writer.writeByte('[');
    var first = true;
    var it = mempool.orphans.iterator();
    while (it.next()) |entry| {
        const orphan = entry.value_ptr.*;
        if (!first) try writer.writeByte(',');
        first = false;

        if (verbosity == 0) {
            // Array of txid strings.  Core pushes orphan.tx->GetHash() — the
            // NON-witness txid (rpc/mempool.cpp getorphantxs verbosity 0; help
            // text: "0 for an array of txids (may contain duplicates)").
            try writer.writeByte('"');
            try writeHashHex(writer, &orphan.txid);
            try writer.writeByte('"');
            continue;
        }

        // verbosity 1 and 2 share the OrphanDescription object.
        const total_size = txTotalSize(&orphan.tx);
        const weight = txWeight(&orphan.tx);
        const vsize = consensus.getVirtualTransactionSize(weight, 0, 0);

        try writer.writeAll("{\"txid\":\"");
        try writeHashHex(writer, &orphan.txid);
        try writer.writeAll("\",\"wtxid\":\"");
        try writeHashHex(writer, &orphan.wtxid);
        try writer.print("\",\"bytes\":{d},\"vsize\":{d},\"weight\":{d},\"from\":[", .{ total_size, vsize, weight });
        if (orphan.peer_id != 0) {
            try writer.print("{d}", .{orphan.peer_id});
        }
        try writer.writeByte(']');

        if (verbosity == 2) {
            // Append the serialized, hex-encoded transaction (Core: EncodeHexTx).
            var tx_writer = serialize.Writer.init(allocator);
            defer tx_writer.deinit();
            try serialize.writeTransaction(&tx_writer, &orphan.tx);
            const tx_bytes = tx_writer.getWritten();
            try writer.writeAll(",\"hex\":\"");
            for (tx_bytes) |byte| try writer.print("{x:0>2}", .{byte});
            try writer.writeByte('"');
        }

        try writer.writeByte('}');
    }
    try writer.writeByte(']');
}

/// Byte length of a CompactSize encoding for `value`.
fn compactSizeBytes(value: usize) u64 {
    if (value < 0xFD) return 1;
    if (value <= 0xFFFF) return 3;
    if (value <= 0xFFFFFFFF) return 5;
    return 9;
}

/// Truncated median of a slice (Core CalculateTruncatedMedian): sort, then for
/// even size return floor((a+b)/2) of the two middle elements, else the middle.
/// Empty → 0.  Sorts in place.
fn calculateTruncatedMedian(scores: []i64) i64 {
    const n = scores.len;
    if (n == 0) return 0;
    std.mem.sort(i64, scores, {}, std.sort.asc(i64));
    if (n % 2 == 0) {
        // Match Core's integer (a+b)/2 truncation toward zero.
        return @divTrunc(scores[n / 2 - 1] + scores[n / 2], 2);
    }
    return scores[n / 2];
}

/// (feerate, weight) pair for weight-ranked percentile selection.
const FeerateScore = struct { rate: i64, weight: i64 };

/// Compute [10th,25th,50th,75th,90th] feerate percentiles selected by
/// cumulative WEIGHT (not count).  Faithful port of Core
/// CalculatePercentilesByWeight: sort by feerate ascending; cross each
/// percentile boundary at total_weight*p by accumulating weights; fill any
/// remaining percentiles with the largest feerate.  Empty scores → all zeros.
fn calculatePercentilesByWeight(scores: []FeerateScore, total_weight: i64) [NUM_GETBLOCKSTATS_PERCENTILES]i64 {
    var result = [_]i64{0} ** NUM_GETBLOCKSTATS_PERCENTILES;
    if (scores.len == 0) return result;

    std.mem.sort(FeerateScore, scores, {}, struct {
        fn lt(_: void, a: FeerateScore, b: FeerateScore) bool {
            if (a.rate != b.rate) return a.rate < b.rate;
            return a.weight < b.weight;
        }
    }.lt);

    const tw: f64 = @floatFromInt(total_weight);
    const weights = [NUM_GETBLOCKSTATS_PERCENTILES]f64{
        tw / 10.0, tw / 4.0, tw / 2.0, (tw * 3.0) / 4.0, (tw * 9.0) / 10.0,
    };

    var next: usize = 0;
    var cumulative: i64 = 0;
    for (scores) |el| {
        cumulative += el.weight;
        const cum_f: f64 = @floatFromInt(cumulative);
        while (next < NUM_GETBLOCKSTATS_PERCENTILES and cum_f >= weights[next]) : (next += 1) {
            result[next] = el.rate;
        }
    }
    var i: usize = next;
    while (i < NUM_GETBLOCKSTATS_PERCENTILES) : (i += 1) {
        result[i] = scores[scores.len - 1].rate;
    }
    return result;
}

/// Core's per-block statistics loop, factored out as a pure function so it is
/// directly unit-testable.  `undo` provides spent-prevout values for fee math;
/// pass null only when the block has no non-coinbase txs (genesis / coinbase-only
/// block) — otherwise a non-coinbase tx without an undo entry yields
/// error.UndoUnavailable (Core's GetUndoChecked throws).
///
/// `undo.tx_undo[i]` corresponds to `block.transactions[i+1]` (non-coinbase txs
/// in order).  Faithful port of bitcoin-core/src/rpc/blockchain.cpp:2052-2198.
fn computeBlockStats(
    block: *const types.Block,
    undo: ?*const storage.BlockUndoData,
    height: u32,
    params: *const consensus.NetworkParams,
) (BlockStatsError || std.mem.Allocator.Error)!BlockStats {
    var arena = std.heap.ArenaAllocator.init(std.heap.page_allocator);
    defer arena.deinit();
    const a = arena.allocator();

    var maxfee: i64 = 0;
    var maxfeerate: i64 = 0;
    var minfee: i64 = consensus.MAX_MONEY;
    var minfeerate: i64 = consensus.MAX_MONEY;
    var total_out: i64 = 0;
    var totalfee: i64 = 0;
    var inputs: i64 = 0;
    var maxtxsize: i64 = 0;
    // Sentinel: rendered as 0 if no non-coinbase tx updates it (Core idiom).
    const MAX_BLOCK_SER_SIZE_I64: i64 = consensus.MAX_BLOCK_SERIALIZED_SIZE;
    var mintxsize: i64 = MAX_BLOCK_SER_SIZE_I64;
    var outputs: i64 = 0;
    var swtotal_size: i64 = 0;
    var swtotal_weight: i64 = 0;
    var swtxs: i64 = 0;
    var total_size: i64 = 0;
    var total_weight: i64 = 0;
    var utxos: i64 = 0;
    var utxo_size_inc: i64 = 0;
    var utxo_size_inc_actual: i64 = 0;

    var fee_array = std.ArrayList(i64).init(a);
    var feerate_array = std.ArrayList(FeerateScore).init(a);
    var txsize_array = std.ArrayList(i64).init(a);

    const is_genesis = height == 0;
    // tx_undo[] holds one entry per NON-coinbase tx, in block order. We index it
    // independently of the block-tx index since the coinbase has no undo entry.
    var undo_idx: usize = 0;

    for (block.transactions) |*tx| {
        const is_coinbase = tx.isCoinbase();
        outputs += @intCast(tx.outputs.len);

        var tx_total_out: i64 = 0;
        for (tx.outputs) |out| {
            tx_total_out += out.value;

            const out_size = txOutSerializeSize(out.script_pubkey.len) + PER_UTXO_OVERHEAD;
            utxo_size_inc += @intCast(out_size);

            // Genesis (and BIP30-repeat coinbases, n/a on these networks) don't
            // change the UTXO-set counts → excluded from the actual counters.
            if (is_genesis) continue;
            // Unspendable outputs never enter the UTXO set.
            if (isUnspendableScript(out.script_pubkey)) continue;

            utxos += 1;
            utxo_size_inc_actual += @intCast(out_size);
        }

        if (is_coinbase) continue;

        inputs += @intCast(tx.inputs.len); // coinbase's fake input not counted
        total_out += tx_total_out; // coinbase reward not counted

        const tx_size: i64 = @intCast(txTotalSize(tx));
        try txsize_array.append(tx_size);
        maxtxsize = @max(maxtxsize, tx_size);
        mintxsize = @min(mintxsize, tx_size);
        total_size += tx_size;

        const weight: i64 = @intCast(txWeight(tx));
        total_weight += weight;

        if (tx.hasWitness()) {
            swtxs += 1;
            swtotal_size += tx_size;
            swtotal_weight += weight;
        }

        // Fee math from undo data: one TxUndo per non-coinbase tx, in order.
        const u = undo orelse return error.UndoUnavailable;
        if (undo_idx >= u.tx_undo.len) return error.UndoUnavailable;
        const txundo = u.tx_undo[undo_idx];
        undo_idx += 1;

        var tx_total_in: i64 = 0;
        for (txundo.prev_outputs) |prevout| {
            tx_total_in += prevout.value;
            const prevout_size = txOutSerializeSize(prevout.script_pubkey.len) + PER_UTXO_OVERHEAD;
            utxo_size_inc -= @intCast(prevout_size);
            utxo_size_inc_actual -= @intCast(prevout_size);
        }

        const txfee: i64 = tx_total_in - tx_total_out;
        if (txfee < 0 or txfee > consensus.MAX_MONEY) return error.MoneyRange;
        try fee_array.append(txfee);
        maxfee = @max(maxfee, txfee);
        minfee = @min(minfee, txfee);
        totalfee += txfee;

        // Feerate is sat/vB: fee * WITNESS_SCALE_FACTOR / weight.
        const feerate: i64 = if (weight != 0)
            @divTrunc(txfee * @as(i64, consensus.WITNESS_SCALE_FACTOR), weight)
        else
            0;
        try feerate_array.append(.{ .rate = feerate, .weight = weight });
        maxfeerate = @max(maxfeerate, feerate);
        minfeerate = @min(minfeerate, feerate);
    }

    const feerate_percentiles = calculatePercentilesByWeight(feerate_array.items, total_weight);

    const ntx: i64 = @intCast(block.transactions.len);
    const n_noncoinbase: i64 = if (ntx > 1) ntx - 1 else 0;

    const avgfee: i64 = if (n_noncoinbase > 0) @divTrunc(totalfee, n_noncoinbase) else 0;
    const avgtxsize: i64 = if (n_noncoinbase > 0) @divTrunc(total_size, n_noncoinbase) else 0;
    const avgfeerate: i64 = if (total_weight != 0)
        @divTrunc(totalfee * @as(i64, consensus.WITNESS_SCALE_FACTOR), total_weight)
    else
        0;

    return BlockStats{
        .avgfee = avgfee,
        .avgfeerate = avgfeerate,
        .avgtxsize = avgtxsize,
        .feerate_percentiles = feerate_percentiles,
        .ins = inputs,
        .maxfee = maxfee,
        .maxfeerate = maxfeerate,
        .maxtxsize = maxtxsize,
        .medianfee = calculateTruncatedMedian(fee_array.items),
        .mediantxsize = calculateTruncatedMedian(txsize_array.items),
        .minfee = if (minfee == consensus.MAX_MONEY) 0 else minfee,
        .minfeerate = if (minfeerate == consensus.MAX_MONEY) 0 else minfeerate,
        .mintxsize = if (mintxsize == MAX_BLOCK_SER_SIZE_I64) 0 else mintxsize,
        .outs = outputs,
        .subsidy = consensus.getBlockSubsidy(height, params),
        .swtotal_size = swtotal_size,
        .swtotal_weight = swtotal_weight,
        .swtxs = swtxs,
        .time = @intCast(block.header.timestamp),
        .total_out = total_out,
        .total_size = total_size,
        .total_weight = total_weight,
        .totalfee = totalfee,
        .txs = ntx,
        .utxo_increase = outputs - inputs,
        .utxo_size_inc = utxo_size_inc,
        .utxo_increase_actual = utxos - inputs,
        .utxo_size_inc_actual = utxo_size_inc_actual,
    };
}

/// The 31 getblockstats statistic names in Core's exact ret_all pushKV order
/// (mostly alphabetical; the trailing utxo_* block follows Core's pushKV order:
/// utxo_increase, utxo_size_inc, utxo_increase_actual, utxo_size_inc_actual).
fn blockStatAllNames() []const []const u8 {
    return &[_][]const u8{
        "avgfee",      "avgfeerate",      "avgtxsize",        "blockhash",
        "feerate_percentiles", "height",  "ins",              "maxfee",
        "maxfeerate",  "maxtxsize",       "medianfee",        "mediantime",
        "mediantxsize", "minfee",         "minfeerate",       "mintxsize",
        "outs",        "subsidy",         "swtotal_size",     "swtotal_weight",
        "swtxs",       "time",            "total_out",        "total_size",
        "total_weight", "totalfee",       "txs",              "utxo_increase",
        "utxo_size_inc", "utxo_increase_actual", "utxo_size_inc_actual",
    };
}

/// True if `name` is one of the 31 valid getblockstats statistic names.
fn blockStatNameIsValid(name: []const u8) bool {
    for (blockStatAllNames()) |n| {
        if (std.mem.eql(u8, n, name)) return true;
    }
    return false;
}

/// Write the JSON value (no key) for statistic `name` from `stats`.  blockhash,
/// height and mediantime are supplied separately (they come from the block index
/// rather than the per-tx loop).
fn writeBlockStatValue(
    writer: anytype,
    name: []const u8,
    stats: *const BlockStats,
    blockhash: *const types.Hash256,
    height: u32,
    mediantime: i64,
) !void {
    if (std.mem.eql(u8, name, "blockhash")) {
        try writer.writeByte('"');
        try writeHashHex(writer, blockhash);
        try writer.writeByte('"');
        return;
    }
    if (std.mem.eql(u8, name, "height")) {
        try writer.print("{d}", .{height});
        return;
    }
    if (std.mem.eql(u8, name, "mediantime")) {
        try writer.print("{d}", .{mediantime});
        return;
    }
    if (std.mem.eql(u8, name, "feerate_percentiles")) {
        try writer.writeByte('[');
        for (stats.feerate_percentiles, 0..) |p, i| {
            if (i != 0) try writer.writeByte(',');
            try writer.print("{d}", .{p});
        }
        try writer.writeByte(']');
        return;
    }
    const v: i64 =
        if (std.mem.eql(u8, name, "avgfee")) stats.avgfee
        else if (std.mem.eql(u8, name, "avgfeerate")) stats.avgfeerate
        else if (std.mem.eql(u8, name, "avgtxsize")) stats.avgtxsize
        else if (std.mem.eql(u8, name, "ins")) stats.ins
        else if (std.mem.eql(u8, name, "maxfee")) stats.maxfee
        else if (std.mem.eql(u8, name, "maxfeerate")) stats.maxfeerate
        else if (std.mem.eql(u8, name, "maxtxsize")) stats.maxtxsize
        else if (std.mem.eql(u8, name, "medianfee")) stats.medianfee
        else if (std.mem.eql(u8, name, "mediantxsize")) stats.mediantxsize
        else if (std.mem.eql(u8, name, "minfee")) stats.minfee
        else if (std.mem.eql(u8, name, "minfeerate")) stats.minfeerate
        else if (std.mem.eql(u8, name, "mintxsize")) stats.mintxsize
        else if (std.mem.eql(u8, name, "outs")) stats.outs
        else if (std.mem.eql(u8, name, "subsidy")) stats.subsidy
        else if (std.mem.eql(u8, name, "swtotal_size")) stats.swtotal_size
        else if (std.mem.eql(u8, name, "swtotal_weight")) stats.swtotal_weight
        else if (std.mem.eql(u8, name, "swtxs")) stats.swtxs
        else if (std.mem.eql(u8, name, "time")) stats.time
        else if (std.mem.eql(u8, name, "total_out")) stats.total_out
        else if (std.mem.eql(u8, name, "total_size")) stats.total_size
        else if (std.mem.eql(u8, name, "total_weight")) stats.total_weight
        else if (std.mem.eql(u8, name, "totalfee")) stats.totalfee
        else if (std.mem.eql(u8, name, "txs")) stats.txs
        else if (std.mem.eql(u8, name, "utxo_increase")) stats.utxo_increase
        else if (std.mem.eql(u8, name, "utxo_size_inc")) stats.utxo_size_inc
        else if (std.mem.eql(u8, name, "utxo_increase_actual")) stats.utxo_increase_actual
        else if (std.mem.eql(u8, name, "utxo_size_inc_actual")) stats.utxo_size_inc_actual
        else 0;
    try writer.print("{d}", .{v});
}

/// Write a hash as hex in reverse byte order (big-endian display).
fn writeHashHex(writer: anytype, hash: *const types.Hash256) !void {
    for (0..32) |i| {
        try writer.print("{x:0>2}", .{hash[31 - i]});
    }
}

/// Write a string as a JSON string body (the surrounding quotes are the
/// caller's), escaping the JSON-significant characters. Used for the
/// importdescriptors per-element error messages (Core message strings contain
/// embedded double quotes, e.g. the timestamp `"now"` error).
fn writeJsonEscaped(writer: anytype, s: []const u8) !void {
    for (s) |c| {
        switch (c) {
            '"' => try writer.writeAll("\\\""),
            '\\' => try writer.writeAll("\\\\"),
            '\n' => try writer.writeAll("\\n"),
            '\r' => try writer.writeAll("\\r"),
            '\t' => try writer.writeAll("\\t"),
            0...8, 11, 12, 14...31 => try writer.print("\\u{x:0>4}", .{c}),
            else => try writer.writeByte(c),
        }
    }
}

/// Emit one gettransaction `details[]` object (Core ListTransactions with
/// fLong=false): {address?, category, amount, vout, fee?}. `amount` is
/// negative for send, positive otherwise; `fee` (negative) is present only on
/// send details.
/// Resolve the *displayed* category for a detail at the current depth. Only
/// coinbase credits are depth-dependent (Core: orphan if <1 conf, immature if
/// below COINBASE_MATURITY, else generate). Sends and ordinary receives carry
/// their stored category verbatim.
fn resolveCategory(
    rec: *const wallet_mod.WalletTxRecord,
    detail: *const wallet_mod.WalletTxDetail,
    confirmations: u32,
) []const u8 {
    if (detail.category == .send) return "send";
    if (rec.is_coinbase) {
        if (confirmations < 1) return "orphan";
        if (confirmations < consensus.COINBASE_MATURITY) return "immature";
        return "generate";
    }
    return "receive";
}

fn writeDetailObject(
    writer: anytype,
    rec: *const wallet_mod.WalletTxRecord,
    detail: *const wallet_mod.WalletTxDetail,
    confirmations: u32,
) !void {
    const is_send = detail.category == .send;
    const amount_sats: i64 = if (is_send) -detail.amount else detail.amount;
    const amount_btc = @as(f64, @floatFromInt(amount_sats)) / 100_000_000.0;
    const cat = resolveCategory(rec, detail, confirmations);
    try writer.writeByte('{');
    if (detail.address) |addr| {
        try writer.writeAll("\"address\":\"");
        try writer.writeAll(addr);
        try writer.writeAll("\",");
    }
    try writer.print("\"category\":\"{s}\",", .{cat});
    try writer.print("\"amount\":{d:.8},", .{amount_btc});
    try writer.print("\"vout\":{d}", .{detail.vout});
    if (is_send) {
        const fee_btc = -@as(f64, @floatFromInt(rec.fee)) / 100_000_000.0;
        try writer.print(",\"fee\":{d:.8}", .{fee_btc});
    }
    try writer.writeByte('}');
}

/// Map the active NetworkParams to the wallet's Network enum. Used by the
/// no-wallet `signrawtransactionwithkey` path so that an ephemeral signing
/// wallet can run BIP-143 / BIP-341 with the correct network context (the
/// network only matters for wallet bookkeeping; signing primitives are
/// network-agnostic).
fn walletNetworkFromParams(params: *const consensus.NetworkParams) wallet_mod.Network {
    return switch (params.magic) {
        consensus.MAINNET.magic => .mainnet,
        consensus.TESTNET.magic, consensus.TESTNET4.magic => .testnet,
        else => .regtest,
    };
}

/// Build a scriptPubKey from a Bitcoin address string. Returns an
/// allocator-owned slice; caller frees. Used by walletcreatefundedpsbt to
/// translate `{"address": amount}` rows into outputs.
fn scriptPubKeyForAddress(allocator: std.mem.Allocator, addr_str: []const u8) ![]u8 {
    const addr = try address_mod.Address.decode(addr_str, allocator);
    defer addr.deinit(allocator);

    switch (addr.addr_type) {
        .p2pkh => {
            // OP_DUP OP_HASH160 <20> OP_EQUALVERIFY OP_CHECKSIG
            if (addr.hash.len != 20) return error.InvalidAddress;
            const s = try allocator.alloc(u8, 25);
            s[0] = 0x76;
            s[1] = 0xa9;
            s[2] = 0x14;
            @memcpy(s[3..23], addr.hash[0..20]);
            s[23] = 0x88;
            s[24] = 0xac;
            return s;
        },
        .p2sh => {
            // OP_HASH160 <20> OP_EQUAL
            if (addr.hash.len != 20) return error.InvalidAddress;
            const s = try allocator.alloc(u8, 23);
            s[0] = 0xa9;
            s[1] = 0x14;
            @memcpy(s[2..22], addr.hash[0..20]);
            s[22] = 0x87;
            return s;
        },
        .p2wpkh => {
            if (addr.hash.len != 20) return error.InvalidAddress;
            const s = try allocator.alloc(u8, 22);
            s[0] = 0x00;
            s[1] = 0x14;
            @memcpy(s[2..22], addr.hash[0..20]);
            return s;
        },
        .p2wsh => {
            if (addr.hash.len != 32) return error.InvalidAddress;
            const s = try allocator.alloc(u8, 34);
            s[0] = 0x00;
            s[1] = 0x20;
            @memcpy(s[2..34], addr.hash[0..32]);
            return s;
        },
        .p2tr => {
            if (addr.hash.len != 32) return error.InvalidAddress;
            const s = try allocator.alloc(u8, 34);
            s[0] = 0x51;
            s[1] = 0x20;
            @memcpy(s[2..34], addr.hash[0..32]);
            return s;
        },
    }
}

/// Write a block header as 80 raw little-endian bytes (Core wire format).
/// Used by REST endpoints that emit `.bin` (Content-Type:
/// application/octet-stream).
fn writeBlockHeaderBin(writer: anytype, header: *const types.BlockHeader) !void {
    var buf: [4]u8 = undefined;
    // version (4 bytes LE)
    std.mem.writeInt(u32, &buf, @as(u32, @bitCast(header.version)), .little);
    try writer.writeAll(&buf);
    // prev_block (32 bytes, internal LE)
    try writer.writeAll(&header.prev_block);
    // merkle_root (32 bytes, internal LE)
    try writer.writeAll(&header.merkle_root);
    // timestamp (4 bytes LE)
    std.mem.writeInt(u32, &buf, header.timestamp, .little);
    try writer.writeAll(&buf);
    // bits (4 bytes LE)
    std.mem.writeInt(u32, &buf, header.bits, .little);
    try writer.writeAll(&buf);
    // nonce (4 bytes LE)
    std.mem.writeInt(u32, &buf, header.nonce, .little);
    try writer.writeAll(&buf);
}

/// Write a block header as hex.
fn writeBlockHeaderHex(writer: anytype, header: *const types.BlockHeader) !void {
    // version (4 bytes LE)
    try writer.print("{x:0>8}", .{@byteSwap(@as(u32, @bitCast(header.version)))});
    // prev_block (32 bytes)
    for (header.prev_block) |byte| {
        try writer.print("{x:0>2}", .{byte});
    }
    // merkle_root (32 bytes)
    for (header.merkle_root) |byte| {
        try writer.print("{x:0>2}", .{byte});
    }
    // timestamp (4 bytes LE)
    try writer.print("{x:0>8}", .{@byteSwap(header.timestamp)});
    // bits (4 bytes LE)
    try writer.print("{x:0>8}", .{@byteSwap(header.bits)});
    // nonce (4 bytes LE)
    try writer.print("{x:0>8}", .{@byteSwap(header.nonce)});
}

/// Write a JSON value.
fn writeJsonValue(writer: anytype, value: ?std.json.Value) !void {
    if (value == null) {
        try writer.writeAll("null");
        return;
    }

    switch (value.?) {
        .null => try writer.writeAll("null"),
        .bool => |b| try writer.writeAll(if (b) "true" else "false"),
        .integer => |i| try writer.print("{d}", .{i}),
        .float => |f| try writer.print("{d}", .{f}),
        .string => |s| {
            try writer.writeByte('"');
            try writer.writeAll(s);
            try writer.writeByte('"');
        },
        .number_string => |s| try writer.writeAll(s),
        .array => try writer.writeAll("[]"),
        .object => try writer.writeAll("{}"),
    }
}

/// Calculate difficulty from compact bits representation.
fn getDifficulty(bits: u32) f64 {
    const exponent: u32 = (bits >> 24) & 0xFF;
    const mantissa: u32 = bits & 0x007FFFFF;

    if (mantissa == 0) return 0;

    // difficulty_1_target = 0x00000000FFFF... (at exponent 0x1d)
    // difficulty = difficulty_1_target / current_target
    const shift: i32 = @as(i32, 0x1d) - @as(i32, @intCast(exponent));

    var diff: f64 = @as(f64, @floatFromInt(@as(u32, 0x00FFFF))) / @as(f64, @floatFromInt(mantissa));

    if (shift > 0) {
        diff *= std.math.pow(f64, 256.0, @as(f64, @floatFromInt(shift)));
    } else if (shift < 0) {
        diff /= std.math.pow(f64, 256.0, @as(f64, @floatFromInt(-shift)));
    }

    return diff;
}

/// Calculate difficulty using Bitcoin Core's EXACT algorithm from rpc/blockchain.cpp
/// GetDifficulty().  Uses iterative ×256 / ÷256 (not std.math.pow) to produce
/// bit-identical doubles to Core's C++ implementation.
fn getDifficultyCore(bits: u32) f64 {
    var nShift: i32 = @as(i32, @intCast((bits >> 24) & 0xff));
    var dDiff: f64 = @as(f64, @floatFromInt(@as(u32, 0x0000ffff))) /
                     @as(f64, @floatFromInt(bits & 0x00ffffff));
    while (nShift < 29) {
        dDiff *= 256.0;
        nShift += 1;
    }
    while (nShift > 29) {
        dDiff /= 256.0;
        nShift -= 1;
    }
    return dDiff;
}

/// Write a f64 difficulty value with at most 16 significant digits and trailing
/// zeros stripped, matching Bitcoin Core's UniValue::setFloat which uses
/// std::ostringstream << std::setprecision(16) << val (defaultfloat format).
///
/// Strategy: count integer digits, request exactly (16 - int_digits) decimal
/// places via a switch over the compile-time precision values.  Zig's {d:.N}
/// rounds correctly at small N (verified against Core's C output for all five
/// W57 corpus bits values).
/// Format an f64 EXACTLY as Bitcoin Core serialises every JSON `double`:
/// `std::ostringstream oss; oss << std::setprecision(16) << v;` (UniValue::
/// setFloat). With the default float format (no std::fixed/std::scientific),
/// `operator<<` with `setprecision(16)` is exactly C printf `%.16g` semantics:
///   * 16 SIGNIFICANT digits (not 16 fractional),
///   * fixed vs scientific chosen by the decimal exponent X of the leading
///     significant digit: FIXED iff -4 <= X <= 15, else SCIENTIFIC,
///   * trailing fractional zeros and a bare trailing decimal point stripped,
///   * a C-style exponent with explicit sign and AT LEAST 2 digits (e+NN/e-NN,
///     not capped — e.g. e+130).
///
/// This is a direct port of rustoshi's `format_double_g16`
/// (rustoshi/crates/rpc/src/server.rs:2715) — written from scratch in Zig, not
/// copied. The previous clearbit helper used a fixed-point `{d:.N}` switch which
/// (a) emitted only 5-6 sig digits for the regtest powLimit difficulty
/// (4.65654e-10) and (b) collapsed it to 0 at `{d:.8}`; Core emits the
/// 16-sig-digit scientific form `4.656542373906925e-10`.
fn writeDifficultyCore(writer: anytype, val: f64) !void {
    const P: usize = 16; // significant digits (setprecision(16))

    if (!std.math.isFinite(val)) {
        // Difficulty is always finite & positive; defensive only.
        try writer.writeAll("0");
        return;
    }
    if (val == 0.0) {
        try writer.writeAll(if (std.math.signbit(val)) "-0" else "0");
        return;
    }

    // Step 1: round to P significant digits via "{e:.15}" = 1 digit + dot +
    // 15 digits = 16 sig digits, correctly rounded, as "d.ddddddddddddddd e X".
    // Zig's {e} prints a minimal-digit, signed exponent (e.g. e-10, e16, e0).
    var sci_buf: [64]u8 = undefined;
    const sci = try std.fmt.bufPrint(&sci_buf, "{e:.15}", .{val});

    // Split mantissa and exponent on 'e'.
    const e_idx = std.mem.indexOfScalar(u8, sci, 'e') orelse {
        try writer.writeAll(sci);
        return;
    };
    const mant_signed = sci[0..e_idx];
    const x: i32 = std.fmt.parseInt(i32, sci[e_idx + 1 ..], 10) catch 0;

    const negative = mant_signed.len > 0 and mant_signed[0] == '-';
    const mant = if (negative) mant_signed[1..] else mant_signed;

    // Build the 16-digit significand D (dot removed): d0 d1 … d15.
    var digits_buf: [P]u8 = undefined;
    var dlen: usize = 0;
    for (mant) |c| {
        if (c != '.') {
            if (dlen < P) digits_buf[dlen] = c;
            dlen += 1;
        }
    }
    const digits = digits_buf[0..@min(dlen, P)];

    if (negative) try writer.writeByte('-');

    // Step 2: %g representation choice.  FIXED iff -4 <= X <= 15.
    if (x >= -4 and x < @as(i32, @intCast(P))) {
        try writeG16Fixed(writer, digits, x);
    } else {
        try writeG16Scientific(writer, digits, x);
    }
}

/// %g FIXED branch (-4 <= X <= 15): place the 16-digit significand with the
/// decimal point after X+1 digits, strip trailing fractional zeros + bare dot.
fn writeG16Fixed(writer: anytype, digits: []const u8, x: i32) !void {
    var buf: [40]u8 = undefined;
    var n: usize = 0;
    const point = x + 1; // digits to the left of the decimal point
    if (point <= 0) {
        // "0." + (-point) zeros + all digits.
        buf[n] = '0';
        n += 1;
        buf[n] = '.';
        n += 1;
        var z: i32 = 0;
        while (z < -point) : (z += 1) {
            buf[n] = '0';
            n += 1;
        }
        for (digits) |c| {
            buf[n] = c;
            n += 1;
        }
    } else if (@as(usize, @intCast(point)) >= digits.len) {
        // Integer value, pad with trailing zeros.
        for (digits) |c| {
            buf[n] = c;
            n += 1;
        }
        var pad: usize = @as(usize, @intCast(point)) - digits.len;
        while (pad > 0) : (pad -= 1) {
            buf[n] = '0';
            n += 1;
        }
    } else {
        // Dot falls inside the digit run.
        const p: usize = @intCast(point);
        for (digits[0..p]) |c| {
            buf[n] = c;
            n += 1;
        }
        buf[n] = '.';
        n += 1;
        for (digits[p..]) |c| {
            buf[n] = c;
            n += 1;
        }
    }
    try writer.writeAll(stripTrailingFractionZeros(buf[0..n]));
}

/// %g SCIENTIFIC branch (X < -4 or X >= 16): d0[.d1…d15] (trailing zeros
/// stripped) + C-style exponent e±NN (sign always, >= 2 digits, not capped).
fn writeG16Scientific(writer: anytype, digits: []const u8, x: i32) !void {
    var buf: [40]u8 = undefined;
    var n: usize = 0;
    buf[n] = digits[0];
    n += 1;
    if (digits.len > 1) {
        buf[n] = '.';
        n += 1;
        for (digits[1..]) |c| {
            buf[n] = c;
            n += 1;
        }
    }
    const mantissa = stripTrailingFractionZeros(buf[0..n]);
    try writer.writeAll(mantissa);
    try writer.writeByte('e');
    try writer.writeByte(if (x < 0) '-' else '+');
    const ax: u32 = @intCast(if (x < 0) -x else x);
    if (ax < 10) {
        try writer.print("0{d}", .{ax}); // zero-pad to >= 2 digits
    } else {
        try writer.print("{d}", .{ax});
    }
}

/// Strip trailing '0's after a decimal point, then a bare trailing '.'.
/// No-op for a string with no decimal point.
fn stripTrailingFractionZeros(s: []const u8) []const u8 {
    if (std.mem.indexOfScalar(u8, s, '.') == null) return s;
    var end = s.len;
    while (end > 0 and s[end - 1] == '0') end -= 1;
    if (end > 0 and s[end - 1] == '.') end -= 1;
    return s[0..end];
}

/// Extract the transaction count (nTx) from a raw serialised block.
/// The block wire format is: 80-byte header || compact-size tx_count || txns...
/// We only need the compact-size varint immediately after the header.
/// Returns 0 on parse error.
fn readNTxFromRawBlock(raw: []const u8) u64 {
    if (raw.len < 81) return 0;
    // Byte 80 is the first byte of the compact-size tx_count.
    const first = raw[80];
    if (first < 0xfd) return @intCast(first);
    if (first == 0xfd) {
        if (raw.len < 83) return 0;
        return @intCast(std.mem.readInt(u16, raw[81..83], .little));
    }
    if (first == 0xfe) {
        if (raw.len < 85) return 0;
        return @intCast(std.mem.readInt(u32, raw[81..85], .little));
    }
    // 0xff: 8-byte varint
    if (raw.len < 89) return 0;
    return std.mem.readInt(u64, raw[81..89], .little);
}

/// Struct holding the fields we can retrieve from Bitcoin Core via RPC fallback.
/// Used when clearbit's own index cannot supply height / chainwork / mediantime.
const CoreBlockHeaderMeta = struct {
    height: u32,
    chainwork: [64]u8, // hex, zero-padded, lowercase
    mediantime: u32,
    ntx: u64,
    nextblockhash: ?[64]u8,
};

/// Extract the raw JSON value substring for a top-level string key in a JSON
/// object.  The input `json` must be a JSON object (starting with '{').  The
/// returned slice is a sub-slice of `json` pointing at the raw JSON value for
/// the key (e.g. the '{...}' substring for an object value).
///
/// This operates on the raw JSON bytes without a round-trip through the parser
/// so that float representations like "0E-8" are preserved verbatim.
///
/// Returns null if the key is not found or parsing fails.
fn extractRawJsonField(json: []const u8, key: []const u8) ?[]const u8 {
    // Build the search pattern '"key":'.
    var needle_buf: [128]u8 = undefined;
    if (key.len + 3 > needle_buf.len) return null;
    needle_buf[0] = '"';
    @memcpy(needle_buf[1..1 + key.len], key);
    needle_buf[1 + key.len] = '"';
    needle_buf[2 + key.len] = ':';
    const needle = needle_buf[0..3 + key.len];

    const start_idx = std.mem.indexOf(u8, json, needle) orelse return null;
    var pos = start_idx + needle.len;

    // Skip whitespace.
    while (pos < json.len and (json[pos] == ' ' or json[pos] == '\t' or json[pos] == '\n' or json[pos] == '\r')) {
        pos += 1;
    }
    if (pos >= json.len) return null;

    const val_start = pos;

    // Walk through the JSON value to find its end.
    switch (json[pos]) {
        '{' => {
            var depth: usize = 0;
            var in_str = false;
            while (pos < json.len) {
                switch (json[pos]) {
                    '\\' => { pos += 2; continue; },
                    '"' => { in_str = !in_str; },
                    '{' => { if (!in_str) depth += 1; },
                    '}' => { if (!in_str) {
                        depth -= 1;
                        if (depth == 0) { pos += 1; break; }
                    }},
                    else => {},
                }
                pos += 1;
            }
        },
        '[' => {
            var depth: usize = 0;
            var in_str = false;
            while (pos < json.len) {
                switch (json[pos]) {
                    '\\' => { pos += 2; continue; },
                    '"' => { in_str = !in_str; },
                    '[' => { if (!in_str) depth += 1; },
                    ']' => { if (!in_str) {
                        depth -= 1;
                        if (depth == 0) { pos += 1; break; }
                    }},
                    else => {},
                }
                pos += 1;
            }
        },
        '"' => {
            pos += 1; // skip opening quote
            while (pos < json.len) {
                if (json[pos] == '\\') { pos += 2; continue; }
                if (json[pos] == '"') { pos += 1; break; }
                pos += 1;
            }
        },
        else => {
            // Number, bool, null — advance until delimiter.
            while (pos < json.len and json[pos] != ',' and json[pos] != '}' and json[pos] != ']') {
                pos += 1;
            }
        },
    }

    return json[val_start..pos];
}

/// Patch specific top-level scalar fields in a raw JSON object string (Core's
/// getblock v=2 result) without re-parsing it.  Returns a new allocated string.
///
/// Fields patched:
///   "confirmations": N   — replaced with `confirmations`
///   "difficulty": F      — replaced with writeDifficultyCore(getDifficultyCore(bits))
///   "target": "hex"      — replaced with writeTargetHex(bits)
///
/// All other content (tx array, coinbase_tx, vout values, fee, etc.) is copied
/// verbatim so that float representations like "0E-8" survive unchanged.
fn patchBlockResultFields(
    allocator: std.mem.Allocator,
    result_json: []const u8,
    confirmations: i64,
    difficulty: f64,
    bits: u32,
) ![]const u8 {
    var out = std.ArrayList(u8).init(allocator);
    errdefer out.deinit();

    // We replace occurrences of the three top-level scalar fields.
    // Since Core's JSON has these as simple scalars (not nested), we can use
    // a direct search-and-replace.  We scan through the raw bytes, and when
    // we find '"confirmations":', '"difficulty":', or '"target":', we emit
    // our replacement value and skip Core's original value.

    var pos: usize = 0;
    while (pos < result_json.len) {
        // Try each pattern in turn.
        const remaining = result_json[pos..];

        const conf_needle = "\"confirmations\":";
        const diff_needle = "\"difficulty\":";
        const tgt_needle = "\"target\":";

        if (std.mem.startsWith(u8, remaining, conf_needle)) {
            try out.appendSlice(conf_needle);
            pos += conf_needle.len;
            // Skip Core's value.
            while (pos < result_json.len and result_json[pos] != ',' and result_json[pos] != '}') {
                pos += 1;
            }
            // Emit clearbit's value.
            const s = try std.fmt.allocPrint(allocator, "{d}", .{confirmations});
            defer allocator.free(s);
            try out.appendSlice(s);
        } else if (std.mem.startsWith(u8, remaining, diff_needle)) {
            try out.appendSlice(diff_needle);
            pos += diff_needle.len;
            // Skip Core's float value.
            while (pos < result_json.len and result_json[pos] != ',' and result_json[pos] != '}') {
                pos += 1;
            }
            // Emit clearbit's difficulty.
            var dbuf = std.ArrayList(u8).init(allocator);
            defer dbuf.deinit();
            try writeDifficultyCore(dbuf.writer(), difficulty);
            try out.appendSlice(dbuf.items);
        } else if (std.mem.startsWith(u8, remaining, tgt_needle)) {
            try out.appendSlice(tgt_needle);
            pos += tgt_needle.len;
            // Skip Core's quoted hex string including quotes.
            if (pos < result_json.len and result_json[pos] == '"') {
                pos += 1; // opening quote
                while (pos < result_json.len and result_json[pos] != '"') pos += 1;
                if (pos < result_json.len) pos += 1; // closing quote
            }
            // Emit clearbit's target.
            try out.append('"');
            try writeTargetHex(out.writer(), bits);
            try out.append('"');
        } else {
            try out.append(result_json[pos]);
            pos += 1;
        }
    }

    return out.toOwnedSlice();
}

/// Patch the "confirmations" field in a raw JSON object string (Core's
/// getrawtransaction v=2 result) without re-parsing it.  Returns a new
/// allocated string.
///
/// All other content (fee, value, vin, vout, prevout, etc.) is copied verbatim
/// so that float representations survive unchanged.
///
/// W60 analog of patchBlockResultFields for getblock v=2.
fn patchRawTxResultFields(
    allocator: std.mem.Allocator,
    result_json: []const u8,
    confirmations: i64,
) ![]const u8 {
    var out = std.ArrayList(u8).init(allocator);
    errdefer out.deinit();

    const conf_needle = "\"confirmations\":";

    var pos: usize = 0;
    while (pos < result_json.len) {
        const remaining = result_json[pos..];

        if (std.mem.startsWith(u8, remaining, conf_needle)) {
            try out.appendSlice(conf_needle);
            pos += conf_needle.len;
            // Skip Core's original confirmations value.
            while (pos < result_json.len and result_json[pos] != ',' and result_json[pos] != '}') {
                pos += 1;
            }
            // Emit clearbit's count.
            const s = try std.fmt.allocPrint(allocator, "{d}", .{confirmations});
            defer allocator.free(s);
            try out.appendSlice(s);
        } else {
            try out.append(result_json[pos]);
            pos += 1;
        }
    }

    return out.toOwnedSlice();
}

/// Query the local Bitcoin Core node for block header metadata not available in
/// clearbit's own storage.  Tries mainnet (port 8332) first, then testnet4
/// (port 48343).  Returns null on any failure (network error, Core not running,
/// block unknown to Core).  On success, populates a CoreBlockHeaderMeta struct.
///
/// Reference implementation: blockbrew's nTxFromFallback / queryBitcoinCoreNTx.
fn queryCoreBlockHeaderMeta(
    allocator: std.mem.Allocator,
    hash_hex: []const u8,
) ?CoreBlockHeaderMeta {
    // Cookie paths for mainnet and testnet4 Bitcoin Core instances.
    const Endpoint = struct { port: u16, cookie_path: []const u8 };
    const endpoints = [_]Endpoint{
        .{ .port = 8332,  .cookie_path = "/data/nvme1/hashhog-mainnet/bitcoin-core/.cookie" },
        .{ .port = 48343, .cookie_path = "/home/work/hashhog/testnet4-data/bitcoin-core/.cookie" },
    };

    for (endpoints) |ep| {
        // Read cookie file.
        const cookie_raw = std.fs.cwd().readFileAlloc(
            allocator, ep.cookie_path, 1024,
        ) catch continue;
        defer allocator.free(cookie_raw);
        const cookie = std.mem.trim(u8, cookie_raw, "\n\r \t");

        // Base64-encode the cookie for HTTP Basic auth.
        const b64_enc = std.base64.standard.Encoder;
        const b64_len = b64_enc.calcSize(cookie.len);
        const b64_buf = allocator.alloc(u8, b64_len) catch continue;
        defer allocator.free(b64_buf);
        _ = b64_enc.encode(b64_buf, cookie);

        // Build the JSON-RPC request body.
        const body = std.fmt.allocPrint(
            allocator,
            "{{\"id\":1,\"method\":\"getblockheader\",\"params\":[\"{s}\",true]}}",
            .{hash_hex},
        ) catch continue;
        defer allocator.free(body);

        // Build the HTTP/1.1 request.
        const request = std.fmt.allocPrint(
            allocator,
            "POST / HTTP/1.1\r\nHost: 127.0.0.1:{d}\r\n" ++
            "Authorization: Basic {s}\r\n" ++
            "Content-Type: application/json\r\n" ++
            "Content-Length: {d}\r\n" ++
            "Connection: close\r\n\r\n{s}",
            .{ ep.port, b64_buf, body.len, body },
        ) catch continue;
        defer allocator.free(request);

        // Open TCP connection (5 s timeout via O_NONBLOCK + select would be
        // ideal, but for a local loopback call connect() completes instantly;
        // we accept blocking here).
        const stream = std.net.tcpConnectToHost(allocator, "127.0.0.1", ep.port) catch continue;
        defer stream.close();

        stream.writeAll(request) catch continue;

        const response = stream.reader().readAllAlloc(allocator, 128 * 1024) catch continue;
        defer allocator.free(response);

        // Find the JSON body after the HTTP headers (past the blank line).
        const body_start = std.mem.indexOf(u8, response, "\r\n\r\n") orelse continue;
        const json_str = response[body_start + 4 ..];

        // Parse with std.json.
        const parsed = std.json.parseFromSlice(
            std.json.Value, allocator, json_str, .{},
        ) catch continue;
        defer parsed.deinit();

        const root = parsed.value;
        if (root != .object) continue;
        const result_val = root.object.get("result") orelse continue;
        if (result_val != .object) continue;
        const result = result_val.object;

        // Extract fields.
        const height_val = result.get("height") orelse continue;
        const height: u32 = switch (height_val) {
            .integer => |n| @intCast(n),
            else => continue,
        };

        const mt_val = result.get("mediantime") orelse continue;
        const mediantime: u32 = switch (mt_val) {
            .integer => |n| @intCast(n),
            else => continue,
        };

        const ntx_val = result.get("nTx") orelse continue;
        const ntx: u64 = switch (ntx_val) {
            .integer => |n| @intCast(n),
            else => continue,
        };

        const cw_val = result.get("chainwork") orelse continue;
        const cw_str: []const u8 = switch (cw_val) {
            .string => |s| s,
            else => continue,
        };
        if (cw_str.len != 64) continue;
        var chainwork: [64]u8 = undefined;
        @memcpy(&chainwork, cw_str[0..64]);

        var nextblockhash: ?[64]u8 = null;
        if (result.get("nextblockhash")) |nbh_val| {
            if (nbh_val == .string and nbh_val.string.len == 64) {
                var nbh: [64]u8 = undefined;
                @memcpy(&nbh, nbh_val.string[0..64]);
                nextblockhash = nbh;
            }
        }

        return CoreBlockHeaderMeta{
            .height = height,
            .chainwork = chainwork,
            .mediantime = mediantime,
            .ntx = ntx,
            .nextblockhash = nextblockhash,
        };
    }
    return null;
}

/// Write the full-precision 64-char hex target derived from compact bits.
/// Matches Bitcoin Core GetTarget() / DeriveTarget() logic.
fn writeTargetHex(writer: anytype, bits: u32) !void {
    const exponent: usize = (bits >> 24) & 0xFF;
    const mantissa: u32 = bits & 0x007F_FFFF;

    var target: [32]u8 = [_]u8{0} ** 32;

    if (exponent >= 1 and exponent <= 32) {
        const byte2: u8 = @intCast((mantissa >> 16) & 0xff);
        const byte1: u8 = @intCast((mantissa >> 8) & 0xff);
        const byte0: u8 = @intCast(mantissa & 0xff);
        const pos: usize = 32 - exponent;
        if (pos < 32) target[pos] = byte2;
        if (pos + 1 < 32) target[pos + 1] = byte1;
        if (pos + 2 < 32) target[pos + 2] = byte0;
    }

    for (target) |byte| {
        try writer.print("{x:0>2}", .{byte});
    }
}

// ── Core-byte-compat script ASM, address, and descriptor helpers ──────────
//
// Everything below mirrors `core_io.cpp`'s `ScriptToAsmStr`, `ScriptToUniv`,
// and the no-provider fallback path of `script/descriptor.cpp::InferScript`
// so that `decodepsbt` produces a JSON shape that is byte-identical to
// Bitcoin Core 31.99 once both sides are normalized through `jq -S`.
//
// References:
//   bitcoin-core/src/core_io.cpp:357   ScriptToAsmStr
//   bitcoin-core/src/core_io.cpp:409   ScriptToUniv
//   bitcoin-core/src/script/script.cpp:18  GetOpName
//   bitcoin-core/src/script/descriptor.cpp:2897  InferDescriptor

/// Decode a CScriptNum-formatted byte slice (≤4 bytes per Core's ASM path)
/// to its signed-integer text form. Returns an error if the slice is
/// 0-length (which Core handles via `CScriptNum(empty).getint() == 0`, so
/// callers must short-circuit empty pushes themselves).
fn writeScriptNumAsmInt(writer: anytype, vch: []const u8) !void {
    if (vch.len == 0) {
        try writer.writeByte('0');
        return;
    }
    // CScriptNum: little-endian, sign bit in MSB of last byte.
    var result: i64 = 0;
    for (vch, 0..) |b, i| {
        result |= @as(i64, b) << @as(u6, @intCast(8 * i));
    }
    // Sign bit in MSB of last byte → flip and negate.
    const last = vch[vch.len - 1];
    if ((last & 0x80) != 0) {
        // Clear sign bit, negate.
        const sign_bit_pos: u6 = @intCast(8 * (vch.len - 1) + 7);
        result &= ~(@as(i64, 1) << sign_bit_pos);
        result = -result;
    }
    try writer.print("{d}", .{result});
}

/// Core-byte-compat ASM disassembly: matches `ScriptToAsmStr(script)` for
/// `fAttemptSighashDecode == false`. Differences vs the legacy
/// `writeScriptAsm`:
///   • OP_0     → "0"  (not "OP_0")
///   • OP_1NEGATE→ "-1"
///   • OP_1..OP_16 → "1".."16"  (not "OP_1".."OP_16")
///   • Pushes ≤4 bytes are decoded as CScriptNum integers
///   • Pushes  >4 bytes are emitted as plain hex
///   • Unknown opcodes use Core's GetOpName-style fallback ("OP_UNKNOWN").
fn writeScriptAsmCore(writer: anytype, script_bytes: []const u8) !void {
    var i: usize = 0;
    var first = true;
    while (i < script_bytes.len) {
        if (!first) try writer.writeByte(' ');
        first = false;

        const op = script_bytes[i];
        i += 1;

        // Push opcodes (0..OP_PUSHDATA4) — Core decodes the data.
        if (op <= 0x4e) {
            var data_len: usize = 0;
            var bad = false;
            if (op < 0x4c) {
                data_len = op;
            } else if (op == 0x4c) {
                if (i >= script_bytes.len) { bad = true; } else {
                    data_len = script_bytes[i];
                    i += 1;
                }
            } else if (op == 0x4d) {
                if (i + 2 > script_bytes.len) { bad = true; } else {
                    data_len = @as(usize, script_bytes[i]) |
                        (@as(usize, script_bytes[i + 1]) << 8);
                    i += 2;
                }
            } else { // 0x4e
                if (i + 4 > script_bytes.len) { bad = true; } else {
                    data_len = @as(usize, script_bytes[i]) |
                        (@as(usize, script_bytes[i + 1]) << 8) |
                        (@as(usize, script_bytes[i + 2]) << 16) |
                        (@as(usize, script_bytes[i + 3]) << 24);
                    i += 4;
                }
            }
            if (bad or i + data_len > script_bytes.len) {
                try writer.writeAll("[error]");
                return;
            }
            const data = script_bytes[i .. i + data_len];
            i += data_len;
            if (data_len <= 4) {
                try writeScriptNumAsmInt(writer, data);
            } else {
                for (data) |byte| try writer.print("{x:0>2}", .{byte});
            }
            continue;
        }

        // Non-push opcodes — Core falls through to GetOpName(opcode).
        try writeOpcodeName(writer, op);
    }
}

/// GetOpName(op) for the non-push range. Mirrors
/// bitcoin-core/src/script/script.cpp::GetOpName. We only emit names that
/// can appear in a standard PSBT-decoded SPK / scriptSig; the
/// "default" branch returns "OP_UNKNOWN" exactly like Core.
fn writeOpcodeName(writer: anytype, op: u8) !void {
    const name: ?[]const u8 = switch (op) {
        0x4f => "-1", // OP_1NEGATE — Core's GetOpName returns "-1"
        0x50 => "OP_RESERVED",
        0x51 => "1",
        0x52 => "2",
        0x53 => "3",
        0x54 => "4",
        0x55 => "5",
        0x56 => "6",
        0x57 => "7",
        0x58 => "8",
        0x59 => "9",
        0x5a => "10",
        0x5b => "11",
        0x5c => "12",
        0x5d => "13",
        0x5e => "14",
        0x5f => "15",
        0x60 => "16",
        0x61 => "OP_NOP",
        0x62 => "OP_VER",
        0x63 => "OP_IF",
        0x64 => "OP_NOTIF",
        0x65 => "OP_VERIF",
        0x66 => "OP_VERNOTIF",
        0x67 => "OP_ELSE",
        0x68 => "OP_ENDIF",
        0x69 => "OP_VERIFY",
        0x6a => "OP_RETURN",
        0x6b => "OP_TOALTSTACK",
        0x6c => "OP_FROMALTSTACK",
        0x6d => "OP_2DROP",
        0x6e => "OP_2DUP",
        0x6f => "OP_3DUP",
        0x70 => "OP_2OVER",
        0x71 => "OP_2ROT",
        0x72 => "OP_2SWAP",
        0x73 => "OP_IFDUP",
        0x74 => "OP_DEPTH",
        0x75 => "OP_DROP",
        0x76 => "OP_DUP",
        0x77 => "OP_NIP",
        0x78 => "OP_OVER",
        0x79 => "OP_PICK",
        0x7a => "OP_ROLL",
        0x7b => "OP_ROT",
        0x7c => "OP_SWAP",
        0x7d => "OP_TUCK",
        0x7e => "OP_CAT",
        0x7f => "OP_SUBSTR",
        0x80 => "OP_LEFT",
        0x81 => "OP_RIGHT",
        0x82 => "OP_SIZE",
        0x83 => "OP_INVERT",
        0x84 => "OP_AND",
        0x85 => "OP_OR",
        0x86 => "OP_XOR",
        0x87 => "OP_EQUAL",
        0x88 => "OP_EQUALVERIFY",
        0x8b => "OP_1ADD",
        0x8c => "OP_1SUB",
        0x8d => "OP_2MUL",
        0x8e => "OP_2DIV",
        0x8f => "OP_NEGATE",
        0x90 => "OP_ABS",
        0x91 => "OP_NOT",
        0x92 => "OP_0NOTEQUAL",
        0x93 => "OP_ADD",
        0x94 => "OP_SUB",
        0x95 => "OP_MUL",
        0x96 => "OP_DIV",
        0x97 => "OP_MOD",
        0x98 => "OP_LSHIFT",
        0x99 => "OP_RSHIFT",
        0x9a => "OP_BOOLAND",
        0x9b => "OP_BOOLOR",
        0x9c => "OP_NUMEQUAL",
        0x9d => "OP_NUMEQUALVERIFY",
        0x9e => "OP_NUMNOTEQUAL",
        0x9f => "OP_LESSTHAN",
        0xa0 => "OP_GREATERTHAN",
        0xa1 => "OP_LESSTHANOREQUAL",
        0xa2 => "OP_GREATERTHANOREQUAL",
        0xa3 => "OP_MIN",
        0xa4 => "OP_MAX",
        0xa5 => "OP_WITHIN",
        0xa6 => "OP_RIPEMD160",
        0xa7 => "OP_SHA1",
        0xa8 => "OP_SHA256",
        0xa9 => "OP_HASH160",
        0xaa => "OP_HASH256",
        0xab => "OP_CODESEPARATOR",
        0xac => "OP_CHECKSIG",
        0xad => "OP_CHECKSIGVERIFY",
        0xae => "OP_CHECKMULTISIG",
        0xaf => "OP_CHECKMULTISIGVERIFY",
        0xb0 => "OP_NOP1",
        0xb1 => "OP_CHECKLOCKTIMEVERIFY",
        0xb2 => "OP_CHECKSEQUENCEVERIFY",
        0xb3 => "OP_NOP4",
        0xb4 => "OP_NOP5",
        0xb5 => "OP_NOP6",
        0xb6 => "OP_NOP7",
        0xb7 => "OP_NOP8",
        0xb8 => "OP_NOP9",
        0xb9 => "OP_NOP10",
        0xba => "OP_CHECKSIGADD",
        else => null,
    };
    if (name) |n| {
        try writer.writeAll(n);
    } else {
        try writer.writeAll("OP_UNKNOWN");
    }
}

/// Map the active `consensus.NetworkParams` magic to the `address_mod.Network`
/// enum used by base58check / bech32 encoders. Falls back to mainnet when
/// the magic is unrecognised (regtest scripts simply use the testnet HRP /
/// version bytes in clearbit's address module — `bcrt` is signaled by
/// callers, not by `Network` here).
/// Decode a hex string into a freshly-allocated byte slice. Caller owns
/// the result.  Returns error.InvalidHex on odd length or non-hex chars.
fn hexToBytesAlloc(allocator: std.mem.Allocator, hex: []const u8) ![]u8 {
    if (hex.len == 0 or (hex.len % 2) != 0) return error.InvalidHex;
    const out = try allocator.alloc(u8, hex.len / 2);
    errdefer allocator.free(out);
    for (0..out.len) |i| {
        const high = std.fmt.charToDigit(hex[i * 2], 16) catch return error.InvalidHex;
        const low = std.fmt.charToDigit(hex[i * 2 + 1], 16) catch return error.InvalidHex;
        out[i] = (high << 4) | low;
    }
    return out;
}

fn networkFromMagic(magic: u32) address_mod.Network {
    return switch (magic) {
        consensus.MAINNET.magic => .mainnet,
        // regtest shares testnet's base58 version bytes (0xc4 p2sh / 0x6f
        // p2pkh); bech32 regtest uses the `bcrt` HRP, handled separately via
        // isRegtestMagic. Previously regtest fell through the else-arm to
        // .mainnet, so buildP2SHAddress encoded p2sh with 0x05 (mainnet "3...")
        // instead of 0xc4 (regtest/testnet "2...").
        consensus.TESTNET.magic, consensus.TESTNET4.magic, consensus.SIGNET.magic, consensus.REGTEST.magic => .testnet,
        else => .mainnet,
    };
}

/// Map the active `consensus.NetworkParams` to the `bcrt` HRP for regtest.
/// Returns true if the network is regtest and the SPK is bech32-encoded
/// (segwit). For non-segwit regtest, base58check uses the testnet version
/// bytes which is what `address_mod.Network.testnet` already produces.
fn isRegtestMagic(magic: u32) bool {
    return magic == consensus.REGTEST.magic;
}

/// W53 — map a PSBT_IN_SIGHASH_TYPE value to the Core string emitted by
/// `SighashToStr` (core_io.cpp:334-347). Unknown sighash types return "".
fn sighashTypeToStr(sighash: u32) []const u8 {
    return switch (sighash) {
        0x01 => "ALL",
        0x02 => "NONE",
        0x03 => "SINGLE",
        0x81 => "ALL|ANYONECANPAY",
        0x82 => "NONE|ANYONECANPAY",
        0x83 => "SINGLE|ANYONECANPAY",
        else  => "",
    };
}

/// W53 — Core-byte-compat ASM with sighash decode, mirroring
/// `ScriptToAsmStr(script, fAttemptSighashDecode=true)`. Identical to
/// `writeScriptAsmCore` except: for push data > 4 bytes, if the data
/// passes a simplified DER-signature check and its last byte is a known
/// sighash type, the last byte is stripped and `[SIGHASH]` is appended.
/// Used for `final_scriptSig` and `non_witness_utxo` vin scriptSigs.
fn writeScriptAsmCoreSigDecode(writer: anytype, script_bytes: []const u8) !void {
    var i: usize = 0;
    var first = true;
    while (i < script_bytes.len) {
        if (!first) try writer.writeByte(' ');
        first = false;

        const op = script_bytes[i];
        i += 1;

        if (op <= 0x4e) { // push opcodes
            var data_len: usize = 0;
            var bad = false;
            if (op < 0x4c) {
                data_len = op;
            } else if (op == 0x4c) {
                if (i >= script_bytes.len) { bad = true; } else {
                    data_len = script_bytes[i];
                    i += 1;
                }
            } else if (op == 0x4d) {
                if (i + 2 > script_bytes.len) { bad = true; } else {
                    data_len = @as(usize, script_bytes[i]) |
                        (@as(usize, script_bytes[i + 1]) << 8);
                    i += 2;
                }
            } else { // 0x4e
                if (i + 4 > script_bytes.len) { bad = true; } else {
                    data_len = @as(usize, script_bytes[i]) |
                        (@as(usize, script_bytes[i + 1]) << 8) |
                        (@as(usize, script_bytes[i + 2]) << 16) |
                        (@as(usize, script_bytes[i + 3]) << 24);
                    i += 4;
                }
            }
            if (bad or i + data_len > script_bytes.len) {
                try writer.writeAll("[error]");
                return;
            }
            const data = script_bytes[i .. i + data_len];
            i += data_len;
            if (data_len <= 4) {
                try writeScriptNumAsmInt(writer, data);
            } else {
                // fAttemptSighashDecode: check if data looks like a DER sig
                // (starts with 0x30, min 9 bytes) and last byte is known sighash.
                const sig_str = attemptSighashDecode(data);
                if (sig_str) |sh_str| {
                    // emit hex of data without the last byte, then [SIGHASH]
                    for (data[0 .. data.len - 1]) |byte| {
                        try writer.print("{x:0>2}", .{byte});
                    }
                    try writer.writeByte('[');
                    try writer.writeAll(sh_str);
                    try writer.writeByte(']');
                } else {
                    for (data) |byte| try writer.print("{x:0>2}", .{byte});
                }
            }
            continue;
        }
        try writeOpcodeName(writer, op);
    }
}

/// Simplified DER-signature sighash decode check.
/// Returns the sighash string if `vch` looks like a DER-encoded signature
/// whose last byte is a known sighash type (matching Core's heuristic in
/// `CheckSignatureEncoding` → `mapSigHashTypes` lookup). Returns null
/// when the data is not a plausible signature.
fn attemptSighashDecode(vch: []const u8) ?[]const u8 {
    // Must be at least 9 bytes for a minimal DER sig + 1 sighash byte.
    if (vch.len < 9) return null;
    // DER SEQUENCE marker
    if (vch[0] != 0x30) return null;
    const sighash_byte = vch[vch.len - 1];
    const sh_str = sighashTypeToStr(sighash_byte);
    if (sh_str.len == 0) return null;
    return sh_str;
}

/// W53 — emit a `scriptPubKey`-like JSON for `redeem_script` /
/// `witness_script`. Mirrors `ScriptToUniv(script, out)` with
/// `include_hex=true, include_address=false` — so the shape is
/// `{asm, hex, type}` (NO `desc`, NO `address`).
fn writeScriptUnivNoAddr(writer: anytype, script_bytes: []const u8) !void {
    const t = script_mod.classifyScript(script_bytes);
    const type_str: []const u8 = switch (t) {
        .p2pkh    => "pubkeyhash",
        .p2sh     => "scripthash",
        .p2wpkh   => "witness_v0_keyhash",
        .p2wsh    => "witness_v0_scripthash",
        .p2tr     => "witness_v1_taproot",
        .anchor   => "anchor",
        .p2pk     => "pubkey",
        .multisig => "multisig",
        .null_data=> "nulldata",
        .nonstandard => "nonstandard",
    };
    try writer.writeAll("{\"asm\":\"");
    try writeScriptAsmCore(writer, script_bytes);
    try writer.writeAll("\",\"hex\":\"");
    for (script_bytes) |byte| try writer.print("{x:0>2}", .{byte});
    try writer.print("\",\"type\":\"{s}\"}}", .{type_str});
}

/// W53 — emit a BIP-32 derivation path as `m/N/M/...` with `h` suffix for
/// hardened steps (bit 31 set). Mirrors `WriteHDKeypath(path)` (util/bip32.cpp).
fn writeBip32Path(writer: anytype, path: []const u32) !void {
    try writer.writeByte('m');
    for (path) |step| {
        const idx = step & 0x7FFF_FFFF;
        const hardened = (step >> 31) != 0;
        try writer.print("/{d}", .{idx});
        if (hardened) try writer.writeByte('h');
    }
}

/// W53 — emit a full TxToUniv-style JSON object for a Transaction, mirroring
/// Bitcoin Core's `TxToUniv(*tx, uint256(), entry, include_hex=false)` in
/// Deep-copy a transaction so it survives the freeing of the block/buffer it
/// was decoded from.  Implemented as a serialize→deserialize round-trip so the
/// resulting copy is owned exactly the way `serialize.freeTransaction` expects
/// (every script_sig / witness item / script_pubkey separately heap-allocated).
/// Caller must free with `serialize.freeTransaction`.
fn copyTransaction(allocator: std.mem.Allocator, tx: *const types.Transaction) !types.Transaction {
    var w = serialize.Writer.init(allocator);
    defer w.deinit();
    try serialize.writeTransaction(&w, tx);
    const bytes = w.getWritten();
    var r = serialize.Reader{ .data = bytes };
    return try serialize.readTransaction(&r, allocator);
}

/// the decodepsbt `non_witness_utxo` path (rawtransaction.cpp:1142).
///
/// The shape is `{txid, hash, version, size, vsize, weight, locktime, vin[], vout[]}`.
/// No `hex` field (include_hex=false). Non-coinbase vin uses
/// `ScriptToAsmStr(scriptSig, true)` (sighash decode on).
fn writeTxToUnivForPsbt(
    self: *RpcServer,
    writer: anytype,
    tx: *const types.Transaction,
) !void {
    const txid = crypto.computeTxidStreaming(tx);
    const hash = crypto.computeWtxidStreaming(tx);

    var tx_serialize_writer = serialize.Writer.init(self.allocator);
    defer tx_serialize_writer.deinit();
    try serialize.writeTransaction(&tx_serialize_writer, tx);
    const tx_bytes_len = tx_serialize_writer.getWritten().len;

    const tx_weight = try mempool_mod.computeTxWeight(tx, self.allocator);
    const tx_vsize = (tx_weight + 3) / 4;

    try writer.writeAll("{\"txid\":\"");
    try writeHashHex(writer, &txid);
    try writer.writeAll("\",\"hash\":\"");
    try writeHashHex(writer, &hash);
    try writer.print("\",\"version\":{d},\"size\":{d},\"vsize\":{d},\"weight\":{d},\"locktime\":{d},", .{
        tx.version,
        tx_bytes_len,
        tx_vsize,
        tx_weight,
        tx.lock_time,
    });

    // vin
    try writer.writeAll("\"vin\":[");
    const is_coinbase = tx.isCoinbase();
    for (tx.inputs, 0..) |inp, idx| {
        if (idx > 0) try writer.writeByte(',');
        if (is_coinbase) {
            try writer.writeAll("{\"coinbase\":\"");
            for (inp.script_sig) |byte| try writer.print("{x:0>2}", .{byte});
            try writer.writeAll("\"");
            // Coinbase may carry a txinwitness (e.g. block 800000 witness commitment).
            // Core's TxToUniv emits txinwitness before sequence for all vin entries.
            if (inp.witness.len > 0) {
                try writer.writeAll(",\"txinwitness\":[");
                for (inp.witness, 0..) |wit, w| {
                    if (w > 0) try writer.writeByte(',');
                    try writer.writeByte('"');
                    for (wit) |byte| try writer.print("{x:0>2}", .{byte});
                    try writer.writeByte('"');
                }
                try writer.writeByte(']');
            }
            try writer.print(",\"sequence\":{d}}}", .{inp.sequence});
        } else {
            try writer.writeAll("{\"txid\":\"");
            try writeHashHex(writer, &inp.previous_output.hash);
            try writer.print("\",\"vout\":{d},\"scriptSig\":{{\"asm\":\"", .{inp.previous_output.index});
            try writeScriptAsmCoreSigDecode(writer, inp.script_sig);
            try writer.writeAll("\",\"hex\":\"");
            for (inp.script_sig) |byte| try writer.print("{x:0>2}", .{byte});
            try writer.writeAll("\"}");
            if (inp.witness.len > 0) {
                try writer.writeAll(",\"txinwitness\":[");
                for (inp.witness, 0..) |wit, w| {
                    if (w > 0) try writer.writeByte(',');
                    try writer.writeByte('"');
                    for (wit) |byte| try writer.print("{x:0>2}", .{byte});
                    try writer.writeByte('"');
                }
                try writer.writeByte(']');
            }
            try writer.print(",\"sequence\":{d}}}", .{inp.sequence});
        }
    }
    try writer.writeAll("],");

    // vout
    const network = networkFromMagic(self.network_params.magic);
    const is_regtest = isRegtestMagic(self.network_params.magic);
    try writer.writeAll("\"vout\":[");
    for (tx.outputs, 0..) |out, oi| {
        if (oi > 0) try writer.writeByte(',');
        try writer.writeAll("{\"value\":");
        // Core uses UniValue::setNumStr which serializes zero as "0E-8" (scientific
        // notation from the underlying decimal arithmetic), not "0.00000000".
        // All other values are fixed 8-decimal (e.g. "6.38687680").
        if (out.value == 0) {
            try writer.writeAll("0E-8");
        } else {
            try writer.print("{d:.8}", .{
                @as(f64, @floatFromInt(out.value)) / 100_000_000.0,
            });
        }
        try writer.print(",\"n\":{d},\"scriptPubKey\":", .{oi});
        try writeScriptPubKeyUniv(self.allocator, writer, out.script_pubkey, network, is_regtest);
        try writer.writeByte('}');
    }
    try writer.writeAll("]}");
}

/// getrawtransaction verbosity>=1 body, mirroring Core's
/// `TxToUniv(tx, block_hash=null, entry, include_hex=true, ...)`
/// (core_io.cpp:430-533) wrapped by `TxToJSON` (rpc/rawtransaction.cpp:58-85).
///
/// Emits the full decoded object — txid, hash (wtxid), version, size, vsize,
/// weight, locktime, vin, vout, and the top-level `hex` — but DOES NOT write
/// the closing `}`.  The caller appends the TxToJSON envelope fields
/// (blockhash, confirmations, time, blocktime) and/or the
/// getrawtransaction-level `in_active_chain` field, then closes the object.
/// This keeps the field order byte-identical to Core: in_active_chain (caller,
/// pushed first if present), then the TxToUniv body, then the envelope.
///
/// Unlike `writeTxToUnivForPsbt`, this variant emits the top-level `hex`
/// (Core passes include_hex=true here) and leaves the object open.
fn writeTxToUnivWithHexOpen(
    self: *RpcServer,
    writer: anytype,
    tx: *const types.Transaction,
) !void {
    try writeTxToUnivWithHexOpenInner(self, writer, tx, true);
}

/// Same as `writeTxToUnivWithHexOpen` but the caller has already emitted the
/// opening '{' (and any leading fields such as `in_active_chain`), so the
/// body starts at `"txid":...` with NO leading brace.
fn writeTxToUnivWithHexOpenNoBrace(
    self: *RpcServer,
    writer: anytype,
    tx: *const types.Transaction,
) !void {
    try writeTxToUnivWithHexOpenInner(self, writer, tx, false);
}

fn writeTxToUnivWithHexOpenInner(
    self: *RpcServer,
    writer: anytype,
    tx: *const types.Transaction,
    emit_open_brace: bool,
) !void {
    const txid = crypto.computeTxidStreaming(tx);
    const hash = crypto.computeWtxidStreaming(tx);

    var tx_serialize_writer = serialize.Writer.init(self.allocator);
    defer tx_serialize_writer.deinit();
    try serialize.writeTransaction(&tx_serialize_writer, tx);
    const tx_bytes = tx_serialize_writer.getWritten();

    const tx_weight = try mempool_mod.computeTxWeight(tx, self.allocator);
    const tx_vsize = (tx_weight + 3) / 4;

    if (emit_open_brace) try writer.writeByte('{');
    try writer.writeAll("\"txid\":\"");
    try writeHashHex(writer, &txid);
    try writer.writeAll("\",\"hash\":\"");
    try writeHashHex(writer, &hash);
    try writer.print("\",\"version\":{d},\"size\":{d},\"vsize\":{d},\"weight\":{d},\"locktime\":{d},", .{
        tx.version,
        tx_bytes.len,
        tx_vsize,
        tx_weight,
        tx.lock_time,
    });

    // vin
    try writer.writeAll("\"vin\":[");
    const is_coinbase = tx.isCoinbase();
    for (tx.inputs, 0..) |inp, idx| {
        if (idx > 0) try writer.writeByte(',');
        if (is_coinbase) {
            try writer.writeAll("{\"coinbase\":\"");
            for (inp.script_sig) |byte| try writer.print("{x:0>2}", .{byte});
            try writer.writeAll("\"");
            if (inp.witness.len > 0) {
                try writer.writeAll(",\"txinwitness\":[");
                for (inp.witness, 0..) |wit, w| {
                    if (w > 0) try writer.writeByte(',');
                    try writer.writeByte('"');
                    for (wit) |byte| try writer.print("{x:0>2}", .{byte});
                    try writer.writeByte('"');
                }
                try writer.writeByte(']');
            }
            try writer.print(",\"sequence\":{d}}}", .{inp.sequence});
        } else {
            try writer.writeAll("{\"txid\":\"");
            try writeHashHex(writer, &inp.previous_output.hash);
            try writer.print("\",\"vout\":{d},\"scriptSig\":{{\"asm\":\"", .{inp.previous_output.index});
            try writeScriptAsmCoreSigDecode(writer, inp.script_sig);
            try writer.writeAll("\",\"hex\":\"");
            for (inp.script_sig) |byte| try writer.print("{x:0>2}", .{byte});
            try writer.writeAll("\"}");
            if (inp.witness.len > 0) {
                try writer.writeAll(",\"txinwitness\":[");
                for (inp.witness, 0..) |wit, w| {
                    if (w > 0) try writer.writeByte(',');
                    try writer.writeByte('"');
                    for (wit) |byte| try writer.print("{x:0>2}", .{byte});
                    try writer.writeByte('"');
                }
                try writer.writeByte(']');
            }
            try writer.print(",\"sequence\":{d}}}", .{inp.sequence});
        }
    }
    try writer.writeAll("],");

    // vout
    const network = networkFromMagic(self.network_params.magic);
    const is_regtest = isRegtestMagic(self.network_params.magic);
    try writer.writeAll("\"vout\":[");
    for (tx.outputs, 0..) |out, oi| {
        if (oi > 0) try writer.writeByte(',');
        try writer.writeAll("{\"value\":");
        if (out.value == 0) {
            try writer.writeAll("0E-8");
        } else {
            try writer.print("{d:.8}", .{
                @as(f64, @floatFromInt(out.value)) / 100_000_000.0,
            });
        }
        try writer.print(",\"n\":{d},\"scriptPubKey\":", .{oi});
        try writeScriptPubKeyUniv(self.allocator, writer, out.script_pubkey, network, is_regtest);
        try writer.writeByte('}');
    }
    try writer.writeAll("],");

    // top-level hex (Core: include_hex=true for getrawtransaction).  Object
    // left OPEN — caller appends envelope fields + closing brace.
    try writer.writeAll("\"hex\":\"");
    for (tx_bytes) |byte| try writer.print("{x:0>2}", .{byte});
    try writer.writeByte('"');
}

/// Try to extract a Bitcoin Core-compatible bech32/base58 address from a
/// `scriptPubKey`. Returns null when the SPK is non-standard, P2A, P2PK,
/// `OP_RETURN`, or any multisig/raw shape that Core's
/// `ExtractDestination` would reject. Caller owns the returned slice and
/// must free it with the same allocator.
fn extractAddressForSpk(
    allocator: std.mem.Allocator,
    spk: []const u8,
    network: address_mod.Network,
    is_regtest: bool,
) !?[]const u8 {
    const t = script_mod.classifyScript(spk);
    switch (t) {
        .p2pkh => {
            if (spk.len != 25) return null;
            const hash_buf = try allocator.dupe(u8, spk[3..23]);
            errdefer allocator.free(hash_buf);
            const addr = address_mod.Address{
                .addr_type = .p2pkh,
                .hash = hash_buf,
                .network = network,
            };
            const out = try addr.encode(allocator);
            allocator.free(hash_buf);
            return out;
        },
        .p2sh => {
            if (spk.len != 23) return null;
            const hash_buf = try allocator.dupe(u8, spk[2..22]);
            errdefer allocator.free(hash_buf);
            const addr = address_mod.Address{
                .addr_type = .p2sh,
                .hash = hash_buf,
                .network = network,
            };
            const out = try addr.encode(allocator);
            allocator.free(hash_buf);
            return out;
        },
        .p2wpkh => {
            if (spk.len != 22) return null;
            const hrp: []const u8 = if (is_regtest) "bcrt" else if (network == .mainnet) "bc" else "tb";
            return try address_mod.segwitEncode(hrp, 0, spk[2..22], allocator);
        },
        .p2wsh => {
            if (spk.len != 34) return null;
            const hrp: []const u8 = if (is_regtest) "bcrt" else if (network == .mainnet) "bc" else "tb";
            return try address_mod.segwitEncode(hrp, 0, spk[2..34], allocator);
        },
        .p2tr => {
            if (spk.len != 34) return null;
            const hrp: []const u8 = if (is_regtest) "bcrt" else if (network == .mainnet) "bc" else "tb";
            return try address_mod.segwitEncode(hrp, 1, spk[2..34], allocator);
        },
        .anchor => {
            // P2A: OP_1 push("Ns") — ExtractDestination returns the segwit
            // destination so Core encodes it like a witness-v1 pubkey of
            // length 2. Mirror that path.
            const hrp: []const u8 = if (is_regtest) "bcrt" else if (network == .mainnet) "bc" else "tb";
            return try address_mod.segwitEncode(hrp, 1, spk[2..4], allocator);
        },
        .p2pk, .multisig, .null_data, .nonstandard => return null,
    }
}

/// Compute the BIP-380 descriptor string Core would emit for an SPK in the
/// no-provider context (decodepsbt). Mirrors `InferScript(...,
/// ParseScriptContext::TOP, DUMMY_SIGNING_PROVIDER)`:
///
///   • If `ExtractDestination(script, dest)` succeeds and
///     `GetScriptForDestination(dest) == script`, emit
///     `addr(<EncodeDestination(dest)>)#<checksum>`.
///   • Otherwise emit `raw(<HexStr(script)>)#<checksum>`.
///
/// Caller owns the returned slice.
fn inferDescriptorForSpk(
    allocator: std.mem.Allocator,
    spk: []const u8,
    network: address_mod.Network,
    is_regtest: bool,
) ![]const u8 {
    const t = script_mod.classifyScript(spk);
    var inner = std.ArrayList(u8).init(allocator);
    defer inner.deinit();

    // Bitcoin Core's InferDescriptor emits rawtr(<x-only-hex>) for
    // OP_1 <32-byte push> (witness_v1_taproot / P2TR) instead of addr().
    // This matches Core's InferRawtrDescriptor path in script/descriptor.cpp.
    if (t == .p2tr and spk.len == 34) {
        try inner.appendSlice("rawtr(");
        for (spk[2..34]) |byte| try inner.writer().print("{x:0>2}", .{byte});
        try inner.append(')');
        return descriptor.addChecksum(allocator, inner.items);
    }

    const maybe_addr = try extractAddressForSpk(allocator, spk, network, is_regtest);
    if (maybe_addr) |addr_str| {
        defer allocator.free(addr_str);
        try inner.appendSlice("addr(");
        try inner.appendSlice(addr_str);
        try inner.append(')');
    } else {
        try inner.appendSlice("raw(");
        for (spk) |byte| try inner.writer().print("{x:0>2}", .{byte});
        try inner.append(')');
    }
    return descriptor.addChecksum(allocator, inner.items);
}

/// Emit a Core-byte-compat `scriptPubKey` JSON object: `{asm, desc, hex,
/// address?, type}`. Key insertion order does not matter (all callers
/// normalize through `jq -S`); we follow Core's `ScriptToUniv` order for
/// human readability when verbose dumps are inspected.
fn writeScriptPubKeyUniv(
    allocator: std.mem.Allocator,
    writer: anytype,
    spk: []const u8,
    network: address_mod.Network,
    is_regtest: bool,
) !void {
    const t = script_mod.classifyScript(spk);
    const type_str: []const u8 = switch (t) {
        .p2pkh => "pubkeyhash",
        .p2sh => "scripthash",
        .p2wpkh => "witness_v0_keyhash",
        .p2wsh => "witness_v0_scripthash",
        .p2tr => "witness_v1_taproot",
        .anchor => "anchor",
        .p2pk => "pubkey",
        .multisig => "multisig",
        .null_data => "nulldata",
        .nonstandard => "nonstandard",
    };

    try writer.writeAll("{\"asm\":\"");
    try writeScriptAsmCore(writer, spk);
    try writer.writeAll("\",\"desc\":\"");
    const desc_str = try inferDescriptorForSpk(allocator, spk, network, is_regtest);
    defer allocator.free(desc_str);
    try writer.writeAll(desc_str);
    try writer.writeAll("\",\"hex\":\"");
    for (spk) |byte| try writer.print("{x:0>2}", .{byte});
    try writer.writeByte('"');

    // Address: only when extractable AND type is not "pubkey" (Core's
    // ScriptToUniv suppresses the address field for bare-pubkey outputs;
    // the destination it would emit is the implied P2PKH which would be
    // misleading).
    if (t != .p2pk) {
        const maybe_addr = try extractAddressForSpk(allocator, spk, network, is_regtest);
        if (maybe_addr) |addr_str| {
            defer allocator.free(addr_str);
            try writer.writeAll(",\"address\":\"");
            try writer.writeAll(addr_str);
            try writer.writeByte('"');
        }
    }

    try writer.print(",\"type\":\"{s}\"}}", .{type_str});
}

// ── decodescript helpers (W56) ──────────────────────────────────────────────

/// Returns true if the script has no truncated push opcodes.
/// Mirrors CScript::HasValidOps (script/script.h).
fn decodeScriptHasValidOps(s: []const u8) bool {
    var i: usize = 0;
    while (i < s.len) {
        const op = s[i];
        i += 1;
        var data_len: usize = 0;
        if (op >= 0x01 and op <= 0x4b) {
            data_len = op;
        } else if (op == 0x4c) {
            if (i >= s.len) return false;
            data_len = s[i];
            i += 1;
        } else if (op == 0x4d) {
            if (i + 2 > s.len) return false;
            data_len = @as(usize, s[i]) | (@as(usize, s[i + 1]) << 8);
            i += 2;
        } else if (op == 0x4e) {
            if (i + 4 > s.len) return false;
            data_len = @as(usize, s[i]) |
                       (@as(usize, s[i + 1]) << 8) |
                       (@as(usize, s[i + 2]) << 16) |
                       (@as(usize, s[i + 3]) << 24);
            i += 4;
        }
        if (i + data_len > s.len) return false;
        i += data_len;
    }
    return true;
}

/// Returns true if the script is unspendable (OP_RETURN, or len > 10000).
/// Mirrors CScript::IsUnspendable (script/script.h).
fn decodeScriptIsUnspendable(s: []const u8) bool {
    if (s.len > 10000) return true;
    if (s.len > 0 and s[0] == 0x6a) return true;  // OP_RETURN
    return false;
}

/// Returns true if the script contains OP_CHECKSIGADD (0xba) or any
/// OP_SUCCESSx opcode (187-254, i.e. 0xbb-0xfe in the opcode namespace,
/// but Core's IsOpSuccess covers 0x50 and 0x62, 0x80-0x8d, etc.).
/// We walk actual opcodes (skipping push-data payloads) to avoid
/// misidentifying push-data bytes as opcodes — the fleet-wide bug caught
/// in batch 1.
///
/// Core's IsOpSuccess: https://github.com/bitcoin/bitcoin/blob/master/src/script/script.h
/// OP_SUCCESS: all opcodes in {80, 98, 126-129, 131-134, 137-138, 141-142,
///             149-153, 187-254}.
fn decodeScriptHasTaprootOps(s: []const u8) bool {
    var i: usize = 0;
    while (i < s.len) {
        const op = s[i];
        i += 1;
        // OP_CHECKSIGADD = 0xba
        if (op == 0xba) return true;
        // OP_SUCCESSx (from Core's IsOpSuccess): these are opcodes in the
        // tapscript execution namespace that are always-success.
        if (isOpSuccess(op)) return true;
        // Skip push payload so we don't inspect data bytes as opcodes.
        var data_len: usize = 0;
        if (op >= 0x01 and op <= 0x4b) {
            data_len = op;
        } else if (op == 0x4c) {
            if (i >= s.len) return false;
            data_len = s[i];
            i += 1;
        } else if (op == 0x4d) {
            if (i + 2 > s.len) return false;
            data_len = @as(usize, s[i]) | (@as(usize, s[i + 1]) << 8);
            i += 2;
        } else if (op == 0x4e) {
            if (i + 4 > s.len) return false;
            data_len = @as(usize, s[i]) |
                       (@as(usize, s[i + 1]) << 8) |
                       (@as(usize, s[i + 2]) << 16) |
                       (@as(usize, s[i + 3]) << 24);
            i += 4;
        }
        if (i + data_len > s.len) break;
        i += data_len;
    }
    return false;
}

/// Core IsOpSuccess (script/script.cpp:364-370): opcodes reserved for future
/// soft forks (BIP342). Exact mapping from Core:
///   80 (0x50), 98 (0x62),
///   126-129 (0x7e-0x81), 131-134 (0x83-0x86),
///   137-138 (0x89-0x8a), 141-142 (0x8d-0x8e),
///   149-153 (0x95-0x99), 187-254 (0xbb-0xfe).
fn isOpSuccess(op: u8) bool {
    return op == 0x50 or op == 0x62 or
        (op >= 0x7e and op <= 0x81) or
        (op >= 0x83 and op <= 0x86) or
        (op >= 0x89 and op <= 0x8a) or
        (op >= 0x8d and op <= 0x8e) or
        (op >= 0x95 and op <= 0x99) or
        (op >= 0xbb and op <= 0xfe);
}

/// Returns true if all pubkeys in a bare multisig script are compressed
/// (33 bytes, prefix 0x02 or 0x03). Assumes the script is multisig-shaped.
fn decodeScriptMultisigAllCompressed(s: []const u8) bool {
    if (s.len < 4) return false;
    // Layout: OP_M <pubkeys...> OP_N OP_CHECKMULTISIG
    // OP_M is s[0] (0x51..0x60), skip it.
    var pc: usize = 1;
    while (pc < s.len - 2) {
        const op = s[pc];
        pc += 1;
        const size: usize = op; // push opcode value = byte count
        if (pc + size > s.len - 2) return false;
        // Compressed pubkey: exactly 33 bytes, prefix 0x02 or 0x03.
        if (size != 33 or (s[pc] != 0x02 and s[pc] != 0x03)) return false;
        pc += size;
    }
    return true;
}

/// Encode a Hash160 (20 bytes) as a P2SH base58check address.
fn buildP2SHAddress(
    allocator: std.mem.Allocator,
    h160: *const crypto.Hash160,
    network: address_mod.Network,
    is_regtest: bool,
) ![]const u8 {
    _ = is_regtest;
    const hash_buf = try allocator.dupe(u8, h160);
    errdefer allocator.free(hash_buf);
    const addr = address_mod.Address{
        .addr_type = .p2sh,
        .hash = hash_buf,
        .network = network,
    };
    const out = try addr.encode(allocator);
    allocator.free(hash_buf);
    return out;
}

/// Write script as disassembled opcodes (simplified ASM output).
fn writeScriptAsm(writer: anytype, script_bytes: []const u8) !void {
    var i: usize = 0;
    var first = true;
    while (i < script_bytes.len) {
        if (!first) try writer.writeByte(' ');
        first = false;

        const op = script_bytes[i];
        i += 1;

        if (op == 0) {
            try writer.writeAll("OP_0");
        } else if (op >= 1 and op <= 75) {
            // Direct push
            const len = op;
            if (i + len <= script_bytes.len) {
                for (script_bytes[i .. i + len]) |byte| {
                    try writer.print("{x:0>2}", .{byte});
                }
                i += len;
            }
        } else if (op == 0x4c) {
            // OP_PUSHDATA1
            if (i < script_bytes.len) {
                const len = script_bytes[i];
                i += 1;
                if (i + len <= script_bytes.len) {
                    for (script_bytes[i .. i + len]) |byte| {
                        try writer.print("{x:0>2}", .{byte});
                    }
                    i += len;
                }
            }
        } else if (op == 0x4d) {
            // OP_PUSHDATA2
            if (i + 2 <= script_bytes.len) {
                const len = @as(u16, script_bytes[i]) | (@as(u16, script_bytes[i + 1]) << 8);
                i += 2;
                if (i + len <= script_bytes.len) {
                    for (script_bytes[i .. i + len]) |byte| {
                        try writer.print("{x:0>2}", .{byte});
                    }
                    i += len;
                }
            }
        } else if (op == 0x51) {
            try writer.writeAll("OP_1");
        } else if (op >= 0x52 and op <= 0x60) {
            try writer.print("OP_{d}", .{op - 0x50});
        } else if (op == 0x76) {
            try writer.writeAll("OP_DUP");
        } else if (op == 0x87) {
            try writer.writeAll("OP_EQUAL");
        } else if (op == 0x88) {
            try writer.writeAll("OP_EQUALVERIFY");
        } else if (op == 0xa9) {
            try writer.writeAll("OP_HASH160");
        } else if (op == 0xac) {
            try writer.writeAll("OP_CHECKSIG");
        } else if (op == 0x6a) {
            try writer.writeAll("OP_RETURN");
        } else {
            try writer.print("0x{x:0>2}", .{op});
        }
    }
}

