    const req = "{\"id\":1,\"method\":\"importdescriptors\",\"params\":[[{\"desc\":\"wpkh(02c6047f9441ed7d6d3045406e95c07cd85c778e4b8cef3ca7abac09b95c709ee5)\",\"timestamp\":\"now\"}]]}";
