    const req_priv = "{\"id\":1,\"method\":\"importdescriptors\",\"params\":[[{\"desc\":\"wpkh(cMaqCE6MJ4taofv6QYACyCfcw1bYKYuk7fBHs5tikmU7wqi76dnF)#4kwwalhk\",\"timestamp\":\"now\"}]]}";
