// ── W41 regression: decodepsbt must emit canonical-BE txid ────────────────
// The W40-C harness (tools/psbt-multi-input-test.sh) reported clearbit's
// decodepsbt omitting the top-level tx.txid field entirely. Bitcoin Core's
// decodepsbt invokes TxToUniv() which always emits txid + hash + per-vin
// txid in REVERSED display byte order. Without txid, every cross-impl PSBT
// equality test would silently treat clearbit as a divergence even when the
// underlying decoded transaction was correct.
//
// Reference: bitcoin-core/src/rpc/rawtransaction.cpp:1072  (decodepsbt →
// TxToUniv(... include_hex=false)).
// Fixture: tools/psbt-multi-input-fixture.json (canonical 2-in / 2-out PSBT
// extracted from bitcoin-core/test/functional/data/rpc_psbt.json signer[0]).
test "W41: decodepsbt emits txid in canonical big-endian display order" {
    const allocator = std.testing.allocator;

    var chain_state = storage.ChainState.init(null, 64, allocator);
    defer chain_state.deinit();
    var mempool = mempool_mod.Mempool.init(null, null, allocator);
    defer mempool.deinit();
    var peer_manager = peer_mod.PeerManager.init(allocator, &consensus.MAINNET);
    defer peer_manager.deinit();

    var server = RpcServer.init(
        allocator,
        &chain_state,
        &mempool,
        &peer_manager,
        &consensus.MAINNET,
        .{},
    );
    defer server.deinit();

    // W40-C fixture's psbt_signed (2-input / 2-output PSBT — see
    // tools/psbt-multi-input-fixture.json). The canonical BE txid for this
    // PSBT's unsigned tx, as reported by Bitcoin Core 31.99 decodepsbt, is
    // 82efd652d7ab1197f01a5f4d9a30cb4c68bb79ab6fec58dfa1bf112291d1617b.
    const psbt_b64 =
        "cHNidP8BAJoCAAAAAljoeiG1ba8MI76OcHBFbDNvfLqlyHV5JPVFiHuyq911" ++
        "AAAAAAD/////g40EJ9DsZQpoqka7CwmK6kQiwHGyyng1Kgd5WdB86h0BAAAA" ++
        "AP////8CcKrwCAAAAAAWABTYXCtx0AYLCcmIauuBXlCZHdoSTQDh9QUAAAAA" ++
        "FgAUAK6pouXw+HaliN9VRuh0LR2HAI8AAAAAAAEAuwIAAAABqtc5MQGL0l+E" ++
        "rkALaISL4J23BurCrBgpi6vucatlb4sAAAAASEcwRAIgWPb8fGoz4bMVSNSB" ++
        "yCbAFb0wE1qtQs1neQ2rZtKtJDsCIEoc7SYExnNbY5PltBaR3XiwDwxZQvuf" ++
        "dRhW+qk4FX26Af7///8CgPD6AgAAAAAXqRQPuUY0IWlrgsgzryQceMF9295J" ++
        "NIfQ8gonAQAAABepFCnKdPigj4GZlCgYXJe12FLkBj9hh2UAAAAiAgKVg785" ++
        "rgpgl0etGZrd1jT6YQhVnWxc05tMIYPxq5bgf0cwRAIgdAGK1BgAl7hzMjwA" ++
        "FXILNoTMgSOJEEjn282bVa1nnJkCIHPTabdA4+tT3O+jOCPIBwUUylWn3ZVE" ++
        "8VfBZ5EyYRGMASICAtq2H/SaFNtqfQKwzR+7ePxLGDErW05U2uTbovv+9TbX" ++
        "SDBFAiEA9hA4swjcHahlo0hSdG8BV3KTQgjG0kRUOTzZm98iF3cCIAVuZ1pn" ++
        "Wm0KArhbFOXikHTYolqbV2C+ooFvZhkQoAbqAQEDBAEAAAABBEdSIQKVg785" ++
        "rgpgl0etGZrd1jT6YQhVnWxc05tMIYPxq5bgfyEC2rYf9JoU22p9ArDNH7t4" ++
        "/EsYMStbTlTa5Nui+/71NtdSriIGApWDvzmuCmCXR60Zmt3WNPphCFWdbFzT" ++
        "m0whg/GrluB/ENkMak8AAACAAAAAgAAAAIAiBgLath/0mhTban0CsM0fu3j8" ++
        "SxgxK1tOVNrk26L7/vU21xDZDGpPAAAAgAAAAIABAACAAAEBIADC6wsAAAAA" ++
        "F6kUt/X69A49QKWkWbHbNTXyty+pIeiHIgIDCJ3BDHrG21T5EymvYXMz2ziM" ++
        "6tDCMfcjN50bmQMLAtxHMEQCIGLrelVhB6fHP0WsSrWh3d9vcHX7EnWWmn84" ++
        "Pv/3hLyyAiAMBdu3Rw2/LwhVfdNWxzJcHtMJE+mWzThAlF2xIijaXwEiAgI6" ++
        "3ZBPPW3PWd25BrDe4jUpt/+57VDl6GFRkmhgIh8Oc0cwRAIgZfRbpZmLWaJ/" ++
        "/hp77QFq8fH5DVSzqo90UKpfVqJRA70CIH9yRwOtHtuWaAsoS1bU/8uI9/t1" ++
        "nqu+CKow8puFE4PSAQEDBAEAAAABBCIAIIwjUxc3Q7WV37Sge3K6jkLjeX2n" ++
        "Tof+fZ10l+OyAokDAQVHUiEDCJ3BDHrG21T5EymvYXMz2ziM6tDCMfcjN50b" ++
        "mQMLAtwhAjrdkE89bc9Z3bkGsN7iNSm3/7ntUOXoYVGSaGAiHw5zUq4iBgI6" ++
        "3ZBPPW3PWd25BrDe4jUpt/+57VDl6GFRkmhgIh8OcxDZDGpPAAAAgAAAAIAD" ++
        "AACAIgYDCJ3BDHrG21T5EymvYXMz2ziM6tDCMfcjN50bmQMLAtwQ2QxqTwAA" ++
        "AIAAAACAAgAAgAAiAgOppMN/WZbTqiXbrGtXCvBlA5RJKUJGCzVHU+2e7KWH" ++
        "cRDZDGpPAAAAgAAAAIAEAACAACICAn9jmXV9Lv9VoTatAsaEsYOLZVbl8baz" ++
        "QoKpS2tQBRCWENkMak8AAACAAAAAgAUAAIAA";

    const req = try std.fmt.allocPrint(
        allocator,
        "{{\"id\":1,\"method\":\"decodepsbt\",\"params\":[\"{s}\"]}}",
        .{psbt_b64},
    );
    defer allocator.free(req);

    const resp = try server.dispatch(req);
    defer allocator.free(resp);

    // 1. Top-level tx.txid must be present and byte-reversed (BE display).
    const expected_txid = "82efd652d7ab1197f01a5f4d9a30cb4c68bb79ab6fec58dfa1bf112291d1617b";
    const txid_marker = "\"txid\":\"" ++ expected_txid ++ "\"";
    try std.testing.expect(std.mem.indexOf(u8, resp, txid_marker) != null);

    // 2. Inner tx object should sit under the "tx" key with the BE txid first.
    try std.testing.expect(std.mem.indexOf(u8, resp, "\"tx\":{\"txid\":\"" ++ expected_txid) != null);

    // 3. Per-vin txid: prevout 0 references previous-tx
    //    75ddabb27b8845f5247975c8a5ba7c6f336c4570708ebe230cad6db5217ae858
    //    (BE display-form), as Core decodepsbt reports.
    const vin0_prev = "75ddabb27b8845f5247975c8a5ba7c6f336c4570708ebe230caf6db5217ae858";
    try std.testing.expect(std.mem.indexOf(u8, resp, vin0_prev) != null);

    // 4. Sanity: the txid is NOT emitted in internal-LE order. The LE
    //    serialization of the same hash would start with 7b… ; assert that
    //    no "txid":"<LE form>" appears anywhere in the response (cheap
    //    regression guard against W41 reverting to mis-ordered emit).
    const txid_le_quoted = "\"txid\":\"7b61d1912211bfa1df58ec6fab79bb684ccb309a4d5f1af09711abd752d6ef82\"";
    try std.testing.expect(std.mem.indexOf(u8, resp, txid_le_quoted) == null);

    // 5. Two vin / two vout entries (asymmetric multi-input fixture).
    //    Count commas inside vin to verify length=2: cheaper than full parse.
    try std.testing.expect(std.mem.indexOf(u8, resp, "\"vin\":[") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp, "\"vout\":[") != null);

    // 6. version + locktime emitted (existing behavior, just a guard).
    try std.testing.expect(std.mem.indexOf(u8, resp, "\"version\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp, "\"locktime\":0") != null);
}

// ============================================================================
// getblockstats unit tests — fee math + percentiles, against a constructed block
// ============================================================================

test "getblockstats: calculateTruncatedMedian matches Core truncation" {
    var odd = [_]i64{ 5, 1, 3 };
    try std.testing.expectEqual(@as(i64, 3), calculateTruncatedMedian(&odd));

    var even = [_]i64{ 10, 2, 4, 6 }; // sorted: 2,4,6,10 → (4+6)/2 = 5
    try std.testing.expectEqual(@as(i64, 5), calculateTruncatedMedian(&even));

    var empty = [_]i64{};
    try std.testing.expectEqual(@as(i64, 0), calculateTruncatedMedian(&empty));

    // Core's (a+b)/2 truncates toward zero on odd sums.
    var odd_sum = [_]i64{ 1, 2 }; // (1+2)/2 = 1 (truncated)
    try std.testing.expectEqual(@as(i64, 1), calculateTruncatedMedian(&odd_sum));
}

test "getblockstats: calculatePercentilesByWeight is weight-ranked (Core algorithm)" {
    // Two feerates: rate 1 with weight 90 (heavy/cheap), rate 100 with weight 10
    // (light/expensive).  total_weight = 100.  Boundaries (weights): 10, 25, 50,
    // 75, 90.  Sorted by rate ascending: [{1,90},{100,10}].
    //   After {1,90}: cumulative=90 ≥ 10,25,50,75,90 → percentiles 0..3 (10/25/50/75)
    //                 AND 90th (boundary exactly 90) all become rate 1.
    //   After {100,10}: cumulative=100, no boundaries left.
    // Hence all five percentiles = 1 (the heavy-but-cheap tx dominates by weight).
    var scores = [_]FeerateScore{ .{ .rate = 100, .weight = 10 }, .{ .rate = 1, .weight = 90 } };
    const p = calculatePercentilesByWeight(&scores, 100);
    try std.testing.expectEqual([_]i64{ 1, 1, 1, 1, 1 }, p);

    // Empty → all zeros.
    var none = [_]FeerateScore{};
    const pz = calculatePercentilesByWeight(&none, 0);
    try std.testing.expectEqual([_]i64{ 0, 0, 0, 0, 0 }, pz);
}

test "getblockstats: computeBlockStats fee + size math on a constructed block" {
    // Build a block: coinbase + two non-coinbase txs, no witness.
    //   coinbase: 1 fake input → 1 output (50 BTC). Excluded from fee stats.
    //   txA: 1 input, 1 output value 9000; spent prevout value 10000 → fee 1000.
    //   txB: 1 input, 1 output value 5000; spent prevout value 5500  → fee  500.
    const empty_witness: []const []const u8 = &[_][]const u8{};

    const cb_in = types.TxIn{
        .previous_output = types.OutPoint.COINBASE,
        .script_sig = &[_]u8{ 0x03, 0x01, 0x02, 0x03 },
        .sequence = 0xFFFFFFFF,
        .witness = empty_witness,
    };
    const cb_out = types.TxOut{ .value = 5_000_000_000, .script_pubkey = &[_]u8{ 0x51 } }; // OP_TRUE
    const coinbase = types.Transaction{
        .version = 1,
        .inputs = &[_]types.TxIn{cb_in},
        .outputs = &[_]types.TxOut{cb_out},
        .lock_time = 0,
    };

    const a_in = types.TxIn{
        .previous_output = .{ .hash = [_]u8{0x11} ** 32, .index = 0 },
        .script_sig = &[_]u8{ 0x47, 0xAA, 0xBB }, // arbitrary scriptSig bytes
        .sequence = 0xFFFFFFFF,
        .witness = empty_witness,
    };
    const a_spk = [_]u8{ 0x76, 0xa9, 0x14 } ++ ([_]u8{0xCC} ** 20) ++ [_]u8{ 0x88, 0xac }; // P2PKH (25 bytes)
    const a_out = types.TxOut{ .value = 9000, .script_pubkey = &a_spk };
    const txA = types.Transaction{
        .version = 2,
        .inputs = &[_]types.TxIn{a_in},
        .outputs = &[_]types.TxOut{a_out},
        .lock_time = 0,
    };

    const b_in = types.TxIn{
        .previous_output = .{ .hash = [_]u8{0x22} ** 32, .index = 1 },
        .script_sig = &[_]u8{ 0x48, 0xDD },
        .sequence = 0xFFFFFFFF,
        .witness = empty_witness,
    };
    const b_spk = [_]u8{ 0x00, 0x14 } ++ ([_]u8{0xEE} ** 20); // P2WPKH spk (22 bytes)
    const b_out = types.TxOut{ .value = 5000, .script_pubkey = &b_spk };
    const txB = types.Transaction{
        .version = 2,
        .inputs = &[_]types.TxIn{b_in},
        .outputs = &[_]types.TxOut{b_out},
        .lock_time = 0,
    };

    const block = types.Block{
        .header = .{
            .version = 0x20000000,
            .prev_block = [_]u8{0} ** 32,
            .merkle_root = [_]u8{0} ** 32,
            .timestamp = 1_700_000_000,
            .bits = 0x1d00ffff,
            .nonce = 0,
        },
        .transactions = &[_]types.Transaction{ coinbase, txA, txB },
    };

    // Undo data: one TxUndo per non-coinbase tx, in order (txA, txB).  The
    // BlockUndoData / TxUndo slice fields are mutable ([]T), so the backing
    // arrays must be `var` to form non-const slices via `&`.
    var a_prevs = [_]storage.TxUndo.TxOut{
        .{ .value = 10000, .script_pubkey = &[_]u8{ 0x76, 0xa9 }, .height = 100, .is_coinbase = false },
    };
    var b_prevs = [_]storage.TxUndo.TxOut{
        .{ .value = 5500, .script_pubkey = &[_]u8{ 0x00, 0x14 }, .height = 101, .is_coinbase = false },
    };
    var undo_txs = [_]storage.TxUndo{
        .{ .prev_outputs = &a_prevs },
        .{ .prev_outputs = &b_prevs },
    };
    const undo = storage.BlockUndoData{ .tx_undo = &undo_txs };

    const stats = try computeBlockStats(&block, &undo, 500, &consensus.MAINNET);

    // ── Fee math (the load-bearing assertions). ──────────────────────────────
    try std.testing.expectEqual(@as(i64, 1500), stats.totalfee); // 1000 + 500
    try std.testing.expectEqual(@as(i64, 750), stats.avgfee); // 1500 / 2
    try std.testing.expectEqual(@as(i64, 1000), stats.maxfee);
    try std.testing.expectEqual(@as(i64, 500), stats.minfee);
    // medianfee of {1000,500}: sorted 500,1000 → (500+1000)/2 = 750.
    try std.testing.expectEqual(@as(i64, 750), stats.medianfee);

    // ── Counts. ──────────────────────────────────────────────────────────────
    try std.testing.expectEqual(@as(i64, 3), stats.txs); // includes coinbase
    try std.testing.expectEqual(@as(i64, 2), stats.ins); // coinbase fake input excluded
    try std.testing.expectEqual(@as(i64, 3), stats.outs); // all outputs incl. coinbase
    try std.testing.expectEqual(@as(i64, 14000), stats.total_out); // 9000 + 5000 (coinbase reward excluded)
    try std.testing.expectEqual(@as(i64, 0), stats.swtxs); // no witness in fixture

    // ── Size / weight cross-check against the serializer helpers. ────────────
    const a_size: i64 = @intCast(txTotalSize(&txA));
    const b_size: i64 = @intCast(txTotalSize(&txB));
    try std.testing.expectEqual(a_size + b_size, stats.total_size);
    try std.testing.expectEqual(@max(a_size, b_size), stats.maxtxsize);
    try std.testing.expectEqual(@min(a_size, b_size), stats.mintxsize);
    const a_wt: i64 = @intCast(txWeight(&txA));
    const b_wt: i64 = @intCast(txWeight(&txB));
    try std.testing.expectEqual(a_wt + b_wt, stats.total_weight);

    // ── Feerates: fee*4/weight, truncated. ───────────────────────────────────
    const a_feerate = @divTrunc(@as(i64, 1000) * 4, a_wt);
    const b_feerate = @divTrunc(@as(i64, 500) * 4, b_wt);
    try std.testing.expectEqual(@max(a_feerate, b_feerate), stats.maxfeerate);
    try std.testing.expectEqual(@min(a_feerate, b_feerate), stats.minfeerate);
    // avgfeerate = totalfee*4/total_weight.
    try std.testing.expectEqual(@divTrunc(@as(i64, 1500) * 4, a_wt + b_wt), stats.avgfeerate);

    // ── UTXO deltas. ─────────────────────────────────────────────────────────
    // utxo_increase = outs - ins = 3 - 2 = 1.
    try std.testing.expectEqual(@as(i64, 1), stats.utxo_increase);
    // Spendable outputs created (none unspendable here) minus inputs:
    //   coinbase OP_TRUE + txA P2PKH + txB P2WPKH = 3 spendable, ins = 2 → 1.
    try std.testing.expectEqual(@as(i64, 1), stats.utxo_increase_actual);

    // subsidy at height 500 (no halving on mainnet) = 50 BTC.
    try std.testing.expectEqual(@as(i64, 5_000_000_000), stats.subsidy);

    // header time passthrough.
    try std.testing.expectEqual(@as(i64, 1_700_000_000), stats.time);
}

test "getblockstats: non-coinbase tx without undo entry is a hard error (no fabricated fees)" {
    const empty_witness: []const []const u8 = &[_][]const u8{};
    const cb = types.Transaction{
        .version = 1,
        .inputs = &[_]types.TxIn{.{ .previous_output = types.OutPoint.COINBASE, .script_sig = &[_]u8{0x01}, .sequence = 0xFFFFFFFF, .witness = empty_witness }},
        .outputs = &[_]types.TxOut{.{ .value = 5_000_000_000, .script_pubkey = &[_]u8{0x51} }},
        .lock_time = 0,
    };
    const spend = types.Transaction{
        .version = 2,
        .inputs = &[_]types.TxIn{.{ .previous_output = .{ .hash = [_]u8{0x11} ** 32, .index = 0 }, .script_sig = &[_]u8{}, .sequence = 0xFFFFFFFF, .witness = empty_witness }},
        .outputs = &[_]types.TxOut{.{ .value = 9000, .script_pubkey = &[_]u8{0x51} }},
        .lock_time = 0,
    };
    const block = types.Block{
        .header = .{ .version = 1, .prev_block = [_]u8{0} ** 32, .merkle_root = [_]u8{0} ** 32, .timestamp = 1, .bits = 0x1d00ffff, .nonce = 0 },
        .transactions = &[_]types.Transaction{ cb, spend },
    };
    // Undo is null but the block has a non-coinbase tx → must fail loudly.
    try std.testing.expectError(error.UndoUnavailable, computeBlockStats(&block, null, 1, &consensus.MAINNET));
}

// ===========================================================================
// getnodeaddresses — Core-parity regression (rpc/net.cpp:911-970)
// ---------------------------------------------------------------------------
// Locks the SERIALIZED contract, not just the value set:
//   * exactly 5 keys, in Core's pushKV order time,services,address,port,network;
//   * services emitted as a RAW INTEGER (NOT a hex string — distinct from
//     getpeerinfo's "services":"000...09");
//   * address as a bare IP literal (no :port);
//   * count semantics: default 1, 0 = ALL, <0 -> RPC -8 "Address count out of
//     range";
//   * network filter: lowercased, only ipv4|ipv6|onion|i2p|cjdns accepted, an
//     unknown name -> RPC -8 "Network not recognized: <raw arg>"; a matching
//     filter that no stored addr satisfies -> [] (not an error);
//   * empty addrman -> [].
// These are byte-substring assertions against the dispatch envelope so a future
// switch to an alphabetising JSON encoder (which would reorder the keys to
// address,network,port,services,time) trips this test immediately.
// ===========================================================================

/// Inject a deterministic IPv4 AddressInfo straight into the addrman map so the
/// emitted time/services/port are exact known constants (addAddress would stamp
/// last_seen with the wall clock and force services). Returns nothing; asserts
/// the put succeeded via the caller's subsequent dispatch.
fn gnaTestInjectIpv4(
    pm: *peer_mod.PeerManager,
    a: u8,
    b: u8,
    c: u8,
    d: u8,
    port: u16,
    services: u64,
    time: i64,
) !void {
    const addr = std.net.Address.initIp4(.{ a, b, c, d }, port);
    const key = peer_mod.PeerManager.addressKey(addr);
    try pm.known_addresses.put(key, .{
        .address = addr,
        .services = services,
        .last_seen = time,
        .last_tried = 0,
        .attempts = 0,
        .success = false,
        .source = .manual,
    });
}

test "getnodeaddresses: serialized key order + integer services + bare-IP address" {
    const allocator = std.testing.allocator;

    var chain_state = storage.ChainState.init(null, 64, allocator);
    defer chain_state.deinit();
    var mempool = mempool_mod.Mempool.init(null, null, allocator);
    defer mempool.deinit();
    var peer_manager = peer_mod.PeerManager.init(allocator, &consensus.MAINNET);
    defer peer_manager.deinit();

    // 1.2.3.4:8333, services=1033 (NODE_NETWORK|NODE_WITNESS|NODE_NETWORK_LIMITED),
    // time=1700000000. 1.2.3.4 is publicly routable so addrman accepts it.
    try gnaTestInjectIpv4(&peer_manager, 1, 2, 3, 4, 8333, 1033, 1_700_000_000);

    var server = RpcServer.init(allocator, &chain_state, &mempool, &peer_manager, &consensus.MAINNET, .{});
    defer server.deinit();

    const result = try server.dispatch("{\"id\":1,\"method\":\"getnodeaddresses\",\"params\":[0]}");
    defer allocator.free(result);

    // Exact serialized object: byte-for-byte key order is the contract.
    const expected_obj = "{\"time\":1700000000,\"services\":1033,\"address\":\"1.2.3.4\",\"port\":8333,\"network\":\"ipv4\"}";
    try std.testing.expect(std.mem.indexOf(u8, result, expected_obj) != null);

    // The whole result must be the array wrapped in the standard envelope.
    const expected_full = "{\"result\":[" ++ expected_obj ++ "],\"error\":null,\"id\":1}";
    try std.testing.expectEqualStrings(expected_full, result);

    // services is an INTEGER, never a hex string (the getpeerinfo trap).
    try std.testing.expect(std.mem.indexOf(u8, result, "\"services\":\"") == null);
    // address carries NO port (port lives in its own field).
    try std.testing.expect(std.mem.indexOf(u8, result, "\"address\":\"1.2.3.4:8333\"") == null);
}

test "getnodeaddresses: default count=1 caps the result" {
    const allocator = std.testing.allocator;

    var chain_state = storage.ChainState.init(null, 64, allocator);
    defer chain_state.deinit();
    var mempool = mempool_mod.Mempool.init(null, null, allocator);
    defer mempool.deinit();
    var peer_manager = peer_mod.PeerManager.init(allocator, &consensus.MAINNET);
    defer peer_manager.deinit();

    try gnaTestInjectIpv4(&peer_manager, 1, 2, 3, 4, 8333, 9, 1_700_000_000);
    try gnaTestInjectIpv4(&peer_manager, 5, 6, 7, 8, 8333, 9, 1_700_000_001);
    try gnaTestInjectIpv4(&peer_manager, 9, 10, 11, 12, 8333, 9, 1_700_000_002);

    var server = RpcServer.init(allocator, &chain_state, &mempool, &peer_manager, &consensus.MAINNET, .{});
    defer server.deinit();

    // No params -> count default 1 -> exactly one object emitted.
    const result = try server.dispatch("{\"id\":1,\"method\":\"getnodeaddresses\",\"params\":[]}");
    defer allocator.free(result);

    // Exactly one '{' inside the array (count the per-object brace).
    var objs: usize = 0;
    for (result) |ch| {
        if (ch == '{') objs += 1;
    }
    // One brace for the envelope + one per address object => 2 total for count=1.
    try std.testing.expectEqual(@as(usize, 2), objs);
}

test "getnodeaddresses: count<0 -> RPC -8 'Address count out of range'" {
